#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation always has the same fingerprint.
        // If p is not a palindrome, then p' (reversed p) will be different from p.
        // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
        // For example, [1,2,1] is not a permutation.
        // A permutation cannot be a palindrome unless n=1 (which is not allowed here, n>=2).
        // For n=2, p=[1,2], reversed is [2,1]. These are different.
        // For n=3, p=[1,2,3], reversed is [3,2,1]. These are different.
        // If p_i = p_{n-1-i} for all i, then p would have to be symmetric.
        // For example, if n=4, p=[1,2,2,1] is not a permutation.
        // If n=5, p=[1,2,3,2,1] is not a permutation.
        // Since all elements must be distinct, a permutation cannot be a palindrome
        // unless n=1 (which is not allowed) or n=0.
        // Thus, reversing any permutation p (with n >= 2) will always result in a different permutation p'.
        // The problem guarantees a solution exists. Reversing is the simplest and always valid solution.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a[i].original_index] = a[i].value;
            y[a[i].original_index] = b[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
