#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long total_spells = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0, so a[i] is not the smallest pile),
            // we want to add min_val to it as many times as possible without exceeding k.
            // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
            // Note: k - a[i] must be non-negative. Since a[i] <= k, this is always true.
            // If a[i] is already k, then k - a[i] = 0, so 0 / min_val = 0 spells.
            // If a[i] is k-1 and min_val is 1, then (k-1 - (k-1)) / 1 = 0 spells.
            // If a[i] is 1 and min_val is 1, and k is 5, then (5-1)/1 = 4 spells.
            // The pile a[i] itself is never used as the source for copying, only min_val (a[0]) is.
            // The problem states "if some pile contains strictly more than k candies".
            // So, a_j can be exactly k.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

