int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int initial_a1 = a[0];
        int current_days_left = d;
        int added_haybales = 0;

        for (int i = 1; i < n; ++i) { // Iterate through piles from 2 to n (index 1 to n-1)
            int pile_index = i; // 0-indexed pile index
            int haybales_in_pile = a[pile_index];
            int days_per_haybale = pile_index; // Days to move one haybale from pile_index to pile 0

            if (days_per_haybale == 0) { // Should not happen for i > 0
                continue;
            }

            // Calculate how many haybales can be moved from this pile
            // based on available days
            int max_haybales_can_move = current_days_left / days_per_haybale;

            // The actual number of haybales to move is the minimum of
            // haybales available in the pile and haybales that can be moved
            // with current days left.
            int haybales_to_move = std::min(haybales_in_pile, max_haybales_can_move);

            added_haybales += haybales_to_move;
            current_days_left -= haybales_to_move * days_per_haybale;

            if (current_days_left <= 0) {
                break; // No more days left
            }
        }
        std::cout << initial_a1 + added_haybales << std::endl;
    }
    return 0;
}

