int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s, t;
        std::cin >> s >> t;

        bool possible = false;
        // Iterate through all characters 'a' through 'z'
        for (char c_val = 'a'; c_val <= 'z'; ++c_val) {
            bool s_has_char = false;
            for (char sc : s) {
                if (sc == c_val) {
                    s_has_char = true;
                    break;
                }
            }

            bool t_has_char = false;
            for (char tc : t) {
                if (tc == c_val) {
                    t_has_char = true;
                    break;
                }
            }

            // If both strings contain the character c_val,
            // then it's possible to make them equal to a string
            // consisting entirely of c_val.
            if (s_has_char && t_has_char) {
                possible = true;
                break;
            }
        }

        if (possible) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }
    return 0;
}

