    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        if (n == 1) {
            std::cout << -1 << "\n";
        } else {
            // For n >= 2, we can construct a number.
            // The strategy is to use '2' as the first digit,
            // and '3' for all subsequent digits, except the last one.
            // The last digit will be '9'.
            // This forms a number like 233...39.
            //
            // Let's check divisibility:
            // 1. Not divisible by 2: The number ends in 9 (odd).
            // 2. Not divisible by 3: The sum of digits is 2 + (n-2)*3 + 9.
            //    Sum = 2 + 3n - 6 + 9 = 3n + 5.
            //    For 3n+5 to be divisible by 3, 5 must be divisible by 3, which is false.
            //    So, the number is never divisible by 3.
            // 3. Not divisible by 9: Since it's not divisible by 3, it cannot be divisible by 9.
            //
            // All digits are non-zero (2, 3, 9).
            // The number has n digits.
            //
            // Example:
            // n=2: 29 (2+9=11, not div by 3)
            // n=3: 239 (2+3+9=14, not div by 3)
            // n=4: 2339 (2+3+3+9=17, not div by 3)
            // This construction works for n >= 2.

            std::cout << '2';
            for (int i = 0; i < n - 2; ++i) {
                std::cout << '3';
            }
            std::cout << '9' << "\n";
        }
    }
    return 0;
}

