#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int count_T_half = 0;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // White
        } else if (a[i] > T_half) {
            p[i] = 1; // Black
        } else { // a[i] == T_half
            if (T_is_even) {
                // Alternate colors for elements equal to T/2
                // This ensures that if there are k such elements,
                // floor(k/2) go to one color and ceil(k/2) to the other,
                // minimizing pairs within the same color.
                // Specifically, if k elements are 3 and T=6,
                // we want to put one 3 in white, and the rest in black,
                // or vice versa.
                // The strategy is to assign 0, 1, 0, 1, ...
                // This means the first T_half element gets 0, second gets 1, etc.
                p[i] = count_T_half % 2;
                count_T_half++;
            } else {
                // T is odd, so T/2 is not an integer.
                // No a[i] can be equal to T/2. This branch should not be reached
                // if a[i] == T_half is true, as T_half would be integer division.
                // However, if T_half is used as a float, then a[i] == T/2 is impossible.
                // Given T_half is integer division, a[i] == T_half means a[i] is an integer.
                // If T is odd, T/2 (integer division) is (T-1)/2.
                // If a[i] == (T-1)/2, then a[i] < T/2.
                // So this case (a[i] == T_half when T is odd) implies a[i] < T/2.
                // This means the first branch (a[i] < T_half) would have been taken.
                // This 'else' branch is only for a[i] == T_half when T is even.
                // To be safe, if it somehow happens, treat it like other non-T/2 elements.
                p[i] = 0; // Default to white if logic is ambiguous
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

