void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_taken(n, false);
    std::vector<bool> col_taken(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_taken[i] = true;
                col_taken[j] = true;
            }
        }
    }

    int available_rows_count = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_taken[i]) {
            available_rows_count++;
        }
    }

    int available_cols_count = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_taken[j]) {
            available_cols_count++;
        }
    }

    int moves_possible = std::min(available_rows_count, available_cols_count);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

