int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    bool n_assigned = false;

    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        p[i] = max_val_for_i;
        if (p[i] == n - 1) { // This is a candidate for p[i] = n
            // If we haven't assigned n yet, assign it to this position
            // and mark that n has been assigned.
            // If we already assigned n, then this position must be n-1.
            if (!n_assigned) {
                p[i] = n;
                n_assigned = true;
            }
        }
    }

    // If n was not assigned to any position (meaning all max_val_for_i were < n-1),
    // it means there was a position where p[i] was n, but all other p[j] were small,
    // so max_val_for_i was not n-1. This case is covered by the problem constraints
    // guaranteeing a solution. The logic above correctly identifies the position
    // that should be n if its max_val_for_i is n-1.
    // If no p[i] was n-1, it means n was assigned to a position where all other p[j] were smaller than n-1.
    // In such a case, max_val_for_i would be some value < n-1.
    // However, the problem guarantees a solution.
    // The only way for n not to be assigned is if all max_val_for_i are strictly less than n-1.
    // This would imply that for all i, p[i] <= n-1, which contradicts p being a permutation of 1..n.
    // So, n_assigned must be true after the loop.

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_so_far with the last element's price
        // This represents the minimum price encountered from the right end of the array
        int min_so_far = a[n - 1];

        // Iterate from the second to last element backwards
        for (int i = n - 2; i >= 0; --i) {
            // If the current price a[i] is greater than the minimum price
            // found to its right (min_so_far), then a[i] is a bad price.
            if (a[i] > min_so_far) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_so_far, it means a[i]
                // is either smaller than or equal to min_so_far.
                // In this case, a[i] becomes the new minimum price
                // encountered when moving further left.
                min_so_far = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
