int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed for problem statement, 0-indexed for string)
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - (last_r_pos + 1)
                // which simplifies to i - last_r_pos
                max_dist = std::max(max_dist, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // The last 'R' is at index last_r_pos (0-indexed string), which corresponds to cell last_r_pos + 1.
        // The target is cell n+1.
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_dist = std::max(max_dist, (int)s.length() - last_r_pos);
        std::cout << max_dist << "\n";
    }
    return 0;
}

