    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            long long cells_for_k_stairs = k * (k + 1) / 2;
            if (current_cost + cells_for_k_stairs <= x) {
                current_cost += cells_for_k_stairs;
                count++;
                k = k * 2 + 1; // Next nice staircase has 2k+1 stairs
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

