    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (x_i)
        // should be i times the area of a single piece.
        // Total area of carrot = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of triangle up to x_i = i * (h / (2n)).
        // Also, Area of triangle up to x_i = x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * h / (2n)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

