#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use in the zigzag part

    // The first k+1 elements will generate k distinct differences:
    // |1 - (k+1)| = k
    // |(k+1) - 2| = k-1
    // |2 - k| = k-2
    // ...
    // This pattern generates differences k, k-1, ..., 1.
    // The numbers used are 1, 2, ..., k+1.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, print from left (small)
            std::cout << left << " ";
            left++;
        } else { // Odd index, print from right (large)
            std::cout << right << " ";
            right--;
        }
    }

    // After the first k+1 elements, we have used numbers 1 to k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // To avoid introducing new distinct differences, we can just print them in increasing order.
    // The last number printed from the zigzag part was either `left-1` or `right+1`.
    // If it was `left-1`, then `left` is the next available smallest number.
    // If it was `right+1`, then `right` is the next available largest number.
    // In either case, `left` now holds the smallest unused number from the range [1, k+1].
    // Since we want to print numbers from k+2 to n, we can just print them sequentially.
    // The difference between the last element of the zigzag and (k+2) will be small,
    // likely 1 or 2, which are already among the k distinct differences.
    // For example, if k=2, n=5:
    // 1 3 2 (zigzag part, uses 1,2,3)
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}. k=2.
    // Next numbers are 4, 5.
    // Output: 1 3 2 4 5
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1. Still {1,2}.

    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of terms in the sequence m, 2m, ..., km

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for the first 10 multiples of m
        // (m % 10), (2m % 10), ..., (10m % 10)
        long long sum_of_first_10_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_10_last_digits += (static_cast<long long>(i) * m) % 10;
        }

        // The number of full cycles of 10 terms
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * sum_of_first_10_last_digits;

        // Add the remaining terms
        long long remaining_terms = k % 10;
        for (long long i = 1; i <= remaining_terms; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a decreasing suffix
    // This is the first index `i` from the right such that a[i] < a[i+1]
    // Or, find the longest suffix that is non-increasing.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // Suffix: [2] -> non-increasing
    // Suffix: [3, 2] -> non-increasing
    // Suffix: [5, 3, 2] -> non-increasing
    // Suffix: [4, 5, 3, 2] -> 4 < 5, so this is not non-increasing.
    // The rightmost peak of a decreasing suffix is at index 3 (value 4).
    // The suffix [4, 5, 3, 2] is not non-increasing.
    // The suffix [5, 3, 2] is non-increasing.
    // So, `i` would be 4 (index of 5).

    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is a non-increasing suffix.
    // If i=0, the whole array is non-increasing.

    // Find the rightmost peak of an increasing suffix
    // This is the first index `j` from the right such that a[j] > a[j+1]
    // Or, find the longest suffix that is non-decreasing.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // Suffix: [2] -> non-decreasing
    // Suffix: [3, 2] -> not non-decreasing (3 > 2)
    // So, `j` would be 5 (index of 3).

    int j = i; // Start from where the non-increasing suffix ended
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a suffix that first non-decreasingly then non-increasingly.
    // The elements from index `j` to `i` form a non-decreasing sequence.
    // The elements from index `i` to `n-1` form a non-increasing sequence.
    // The combined sequence a[j...n-1] is of the form X...Y...Z where X <= ... <= Y >= ... >= Z.
    // This is the longest suffix that can be made good.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, current_min_idx and current_max_idx are already pos[1].
        // The length of the segment is 1. Max value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to include 'm' into our current segment.
        // The segment currently covers numbers 1 to m-1.
        // Its range is [current_min_idx, current_max_idx].
        // To include 'm', we must extend the segment to cover pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the segment [current_min_idx, current_max_idx]
        // contains exactly numbers 1 to m.
        // This means:
        // 1. The minimum value in p[current_min_idx ... current_max_idx] is 1. (Guaranteed by construction)
        // 2. The maximum value in p[current_min_idx ... current_max_idx] is m. (Guaranteed by construction)
        // 3. The length of the segment is exactly m.
        //    Length = current_max_idx - current_min_idx + 1.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d^2 - 4d >= 0 for d >= 4
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Ensure a >= b for consistent output, though problem doesn't strictly require it.
            // The problem asks for non-negative real numbers.
            // Since d >= 4, d - sqrt(d^2 - 4d) >= 0.
            // d^2 >= d^2 - 4d => 0 >= -4d => 4d >= 0, which is true for d >= 0.
            // So both a and b calculated this way will be non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) { // Cannot increase if no '1' is available before current index
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) { // Cannot decrease if no '-1' is available before current index
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this element.
        // The flags has_one and has_minus_one are updated based on a[i]
        // for subsequent elements.
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate minimum required values for the left increasing part
    // min_left[i] = minimum value a[i] must take if it's part of an increasing sequence starting from 0
    // i.e., a[0] >= 0, a[1] >= 1, ..., a[i] >= i
    std::vector<long long> min_left(n);
    min_left[0] = 0;
    for (int i = 1; i < n; ++i) {
        min_left[i] = min_left[i-1] + 1;
    }

    // Calculate minimum required values for the right decreasing part
    // min_right[i] = minimum value a[i] must take if it's part of a decreasing sequence ending at 0
    // i.e., a[n-1] >= 0, a[n-2] >= 1, ..., a[i] >= (n-1-i)
    std::vector<long long> min_right(n);
    min_right[n-1] = 0;
    for (int i = n - 2; i >= 0; --i) {
        min_right[i] = min_right[i+1] + 1;
    }

    // Check if there exists a peak k such that a[k] can satisfy both conditions
    // a[k] >= min_left[k] AND a[k] >= min_right[k]
    // Since we can decrease elements, we only need to check if the original a[k] is large enough
    // to be decreased to at least min_left[k] and min_right[k].
    // This means a[k] >= min_left[k] and a[k] >= min_right[k].
    // Or more simply, a[k] >= max(min_left[k], min_right[k]).
    // Note that min_left[k] is k, and min_right[k] is (n-1-k).
    // So we need a[k] >= k and a[k] >= (n-1-k).

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (a[k] >= k && a[k] >= (n - 1 - k)) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak"; // Box 1: (-inf, -1]
    std::string ans2 = "Tidak"; // Box 2: (-1, 0)
    std::string ans3 = "Tidak"; // Box 3: (0, 1)
    std::string ans4 = "Tidak"; // Box 4: [1, inf)

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    } else {
        // Case 1: Final product is negative
        // This requires an odd number of initial negative toys (A+B)
        // The final product can be in Box 1 or Box 2.

        // Can it be Box 1? (negative, magnitude >= 1)
        // To get magnitude >= 1:
        //   - At least one toy from Box 1 (A > 0)
        //   - Or at least one toy from Box 4 (D > 0) AND enough other toys to boost magnitude
        //   - Or multiple toys from Box 2/3 that multiply to >= 1 (e.g., 0.5 * 0.5 * 0.5 * ... * 0.5)
        //     This is generally hard to guarantee without specific values.
        //     However, if we have A > 0 or D > 0, we can potentially achieve magnitude >= 1.
        //     If A > 0, we can pick a value like -10.
        //     If D > 0, we can pick a value like 10.
        //     If A=0 and D=0, all initial toys are in (-1, 1). The product will always be in (-1, 1).
        //     So, for Box 1 or Box 4, we need A > 0 or D > 0.

        // If (A+B) is odd:
        if ((A + B) % 2 != 0) {
            // Can be Box 1:
            // Need A > 0 or D > 0 to potentially get magnitude >= 1.
            // If A=0 and D=0, all initial toys are in (-1, 1), so product is in (-1, 1).
            if (A > 0 || D > 0) {
                ans1 = "Ya";
            }
            // Can be Box 2: (negative, magnitude < 1)
            // This is always possible if (A+B) is odd.
            // We can pick values close to 0 for B and C, and values like -0.5 for A, or -0.5 for B.
            // If A=0 and D=0, the product is guaranteed to be in (-1, 1).
            // If A>0 or D>0, we can still make it < 1 by picking values like -0.1, 0.1, etc.
            ans2 = "Ya";
        }

        // Case 2: Final product is positive
        // This requires an even number of initial negative toys (A+B)
        // The final product can be in Box 3 or Box 4.

        // If (A+B) is even:
        if ((A + B) % 2 == 0) {
            // Can be Box 3: (positive, magnitude < 1)
            // This is always possible if (A+B) is even.
            // We can pick values close to 0 for B and C, or values like 0.5 for A, or 0.5 for D.
            // If A=0 and D=0, the product is guaranteed to be in (0, 1).
            // If A>0 or D>0, we can still make it < 1 by picking values like 0.1, -0.1, etc.
            ans3 = "Ya";

            // Can be Box 4: (positive, magnitude >= 1)
            // Need A > 0 or D > 0 to potentially get magnitude >= 1.
            // If A=0 and D=0, all initial toys are in (-1, 1), so product is in (0, 1).
            if (A > 0 || D > 0) {
                ans4 = "Ya";
            }
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (smaller elements)
        // We want to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j will also be >= a[j]
        // We try to match the smallest available element a[j] that is greater than a[i].
        // This leaves larger elements for later, potentially larger a[i]'s.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'available' pool
        } else {
            // No more elements in 'available' pool are greater than a[i]
            // Any subsequent a[k] (k > i) will be >= a[i], so no more matches possible.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to partition 2n students into two classes,
        // each with an odd number of students.
        // Let the sizes of the classes be S1 and S2.
        // S1 + S2 = 2n.
        // S1 must be odd, S2 must be odd.
        // If S1 is odd, then S2 = 2n - S1 must also be odd (even - odd = odd).
        // So, we just need to ensure S1 is odd.
        // The smallest possible odd size is 1. The largest is 2n-1.
        //
        // Consider the sorted array a_1, a_2, ..., a_{2n}.
        //
        // If we pick the first class to have students with skill levels
        // a_1, ..., a_k, and the second class to have students with skill levels
        // a_{k+1}, ..., a_{2n}, this is not necessarily optimal because
        // we can mix students.
        //
        // However, the key insight for median problems often comes from sorting.
        //
        // Let's consider the structure of the medians.
        // For a class of size 2k+1, its median is the (k+1)-th element.
        //
        // Consider the case where n=1. Total students = 2.
        // Each class must have an odd number of students.
        // The only possible partition is Class 1: 1 student, Class 2: 1 student.
        // Medians are a[0] and a[1]. Difference is |a[1] - a[0]|.
        // After sorting, a[0] and a[1] are the only elements.
        // The median of a class of size 1 is just that element.
        // So, for n=1, the answer is a[1] - a[0].
        //
        // Consider the general case.
        // We have 2n students.
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // If we form two classes, say C1 and C2.
        // Let C1 have size S1 = 2k1 + 1. Its median is m1.
        // Let C2 have size S2 = 2k2 + 1. Its median is m2.
        // S1 + S2 = 2n => (2k1+1) + (2k2+1) = 2n => 2k1 + 2k2 + 2 = 2n => k1 + k2 + 1 = n.
        //
        // The problem asks for the minimum possible absolute difference |m1 - m2|.
        //
        // Consider the elements a_{n-1} and a_n in the sorted array.
        // These are the two "middle" elements.
        //
        // If we can make one class's median a_{n-1} and the other class's median a_n,
        // then the difference would be a_n - a_{n-1}.
        //
        // Can we always achieve this?
        //
        // Let's try to construct classes such that their medians are a_{n-1} and a_n.
        //
        // Class 1:
        // We want a_{n-1} to be its median.
        // This means Class 1 must have k1 elements smaller than or equal to a_{n-1},
        // and k1 elements greater than or equal to a_{n-1}.
        //
        // Class 2:
        // We want a_n to be its median.
        // This means Class 2 must have k2 elements smaller than or equal to a_n,
        // and k2 elements greater than or equal to a_n.
        //
        // The total number of elements smaller than a_{n-1} is n-1.
        // The total number of elements greater than a_n is 2n - (n+1) = n-1.
        //
        // Consider the partition where:
        // Class 1 consists of the first n elements: a_0, ..., a_{n-1}.
        // Class 2 consists of the last n elements: a_n, ..., a_{2n-1}.
        // This partition is not valid because both classes have size n, which might be even.
        //
        // The problem states that each class must have an odd number of students.
        //
        // Let's consider the elements a_{n-1} and a_n.
        //
        // If we take the first n elements for one class and the remaining n elements for the other,
        // this is not allowed if n is even.
        //
        // The crucial observation is that if we sort all $2n$ students,
        // the $n$-th student (0-indexed $a_{n-1}$) and the $(n+1)$-th student (0-indexed $a_n$)
        // are the two "middle" students.
        //
        // If we assign $a_{n-1}$ to one class and $a_n$ to another,
        // and we want to make them medians, we need to balance elements around them.
        //
        // Consider the partition where:
        // Class 1 takes $a_0, a_1, \dots, a_{n-1}$. (size n)
        // Class 2 takes $a_n, a_{n+1}, \dots, a_{2n-1}$. (size n)
        // This is not valid if n is even.
        //
        // However, the problem asks for *any* partition.
        //
        // Let's consider the elements $a_{n-1}$ and $a_n$.
        //
        // If we assign $a_{n-1}$ to Class 1 and $a_n$ to Class 2.
        //
        // Class 1: $a_0, \dots, a_{n-1}$ (size n)
        // Class 2: $a_n, \dots, a_{2n-1}$ (size n)
        //
        // If n is odd:
        // Class 1 has size n (odd). Its median is $a_{(n-1)/2}$.
        // Class 2 has size n (odd). Its median is $a_{n + (n-1)/2}$.
        // This is a valid partition. The difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$.
        //
        // If n is even:
        // This partition is not valid.
        //
        // The problem is simpler than it looks.
        // The minimum difference between medians will always be achieved by taking
        // the two "middle" elements of the *entire sorted array* as the medians of the two classes.
        //
        // Let the sorted array be $a_0, a_1, \dots, a_{2n-1}$.
        //
        // We can always form two classes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other class.
        //
        // Class 1: Take $a_{n-1}$ as the median.
        // To do this, we need to pick $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We have $n-1$ elements smaller than $a_{n-1}$ ($a_0, \dots, a_{n-2}$).
        // We have $n$ elements larger than $a_{n-1}$ ($a_n, \dots, a_{2n-1}$).
        //
        // Class 2: Take $a_n$ as the median.
        // To do this, we need to pick $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        // We have $n$ elements smaller than $a_n$ ($a_0, \dots, a_{n-1}$).
        // We have $n-1$ elements larger than $a_n$ ($a_{n+1}, \dots, a_{2n-1}$).
        //
        // Consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        //
        // Each class has $n$ students.
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        //
        // If $n$ is even, this partition is not valid because class sizes are even.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        //
        // Why?
        // Let $m_1$ and $m_2$ be the medians of the two classes.
        // Let $S_1$ and $S_2$ be their sizes. $S_1 = 2k_1+1$, $S_2 = 2k_2+1$.
        // $S_1+S_2 = 2n \implies 2k_1+1+2k_2+1 = 2n \implies k_1+k_2+1 = n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // Any median $m_1$ must be one of the $a_i$'s.
        // Any median $m_2$ must be one of the $a_j$'s.
        //
        // Suppose $m_1 < m_2$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // If $m_1$ is the median of a class of size $2k_1+1$, then there are $k_1$ elements
        // in that class less than or equal to $m_1$, and $k_1$ elements greater than or equal to $m_1$.
        //
        // If $m_2$ is the median of a class of size $2k_2+1$, then there are $k_2$ elements
        // in that class less than or equal to $m_2$, and $k_2$ elements greater than or equal to $m_2$.
        //
        // The total number of elements less than or equal to $m_1$ in its class is $k_1+1$.
        // The total number of elements greater than or equal to $m_2$ in its class is $k_2+1$.
        //
        // The total number of elements in the entire set that are less than or equal to $m_1$
        // must be at least $k_1+1$. So $m_1 \ge a_{k_1}$.
        // The total number of elements in the entire set that are greater than or equal to $m_2$
        // must be at least $k_2+1$. So $m_2 \le a_{2n - (k_2+1)}$.
        //
        // This implies $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        //
        // Proof:
        // Let $C_1$ and $C_2$ be the two classes. Let their sorted elements be $c_{1,1} \le \dots \le c_{1,S_1}$
        // and $c_{2,1} \le \dots \le c_{2,S_2}$.
        // $S_1 = 2k_1+1$, $S_2 = 2k_2+1$.
        // Medians are $m_1 = c_{1,k_1+1}$ and $m_2 = c_{2,k_2+1}$.
        //
        // Assume without loss of generality $m_1 \le m_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The number of elements in $C_1$ that are $\le m_1$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\le m_2$ is $k_2+1$.
        //
        // The total number of elements in $A$ that are $\le m_1$ is at least $k_1+1$.
        // So $m_1 \ge a_{k_1}$.
        //
        // The total number of elements in $A$ that are $\ge m_2$ is at least $k_2+1$.
        // So $m_2 \le a_{2n - (k_2+1)}$.
        //
        // We know $k_1+k_2+1 = n$.
        //
        // From $m_1 \ge a_{k_1}$:
        // The number of elements in $A$ that are $\le m_1$ is at least $k_1+1$.
        // This means $m_1$ must be at least $a_{k_1}$.
        //
        // From $m_2 \le a_{2n - (k_2+1)}$:
        // The number of elements in $A$ that are $\ge m_2$ is at least $k_2+1$.
        // This means $m_2$ must be at most $a_{2n - (k_2+1)}$.
        //
        // Let's try a different approach.
        //
        // Consider the $n$ smallest elements $a_0, \dots, a_{n-1}$.
        // Consider the $n$ largest elements $a_n, \dots, a_{2n-1}$.
        //
        // Let $m_1$ be the median of Class 1 and $m_2$ be the median of Class 2.
        //
        // Suppose $m_1$ is from the set $\{a_0, \dots, a_{n-1}\}$ and $m_2$ is from the set $\{a_n, \dots, a_{2n-1}\}$.
        // Then $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // In this case, $m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // What if both medians are from $\{a_0, \dots, a_{n-1}\}$?
        // Then $m_1, m_2 \le a_{n-1}$.
        //
        // What if both medians are from $\{a_n, \dots, a_{2n-1}\}$?
        // Then $m_1, m_2 \ge a_n$.
        //
        // This is a known result for problems involving partitioning into two sets with medians.
        // The minimum difference between medians is always achieved when one median is $a_{n-1}$
        // and the other is $a_n$ (using 0-indexed sorted array).
        //
        // Let's prove that $m_1 \le a_{n-1}$ and $m_2 \ge a_n$ (or vice versa).
        //
        // Let $m_1$ be the median of $C_1$ (size $2k_1+1$) and $m_2$ be the median of $C_2$ (size $2k_2+1$).
        // $k_1+k_2+1 = n$.
        //
        // Suppose $m_1 > a_{n-1}$. This means $m_1 \ge a_n$.
        // If $m_1 \ge a_n$, then at least $n$ elements are $\le m_1$ in the full sorted array.
        // For $m_1$ to be the median of $C_1$, there must be $k_1$ elements in $C_1$ that are $\le m_1$
        // and $k_1$ elements in $C_1$ that are $\ge m_1$.
        //
        // The number of elements in $A$ that are $\le m_1$ is at least $n$.
        // The number of elements in $A$ that are $\ge m_1$ is at most $2n - n = n$.
        //
        // If $m_1 \ge a_n$, then $C_1$ must contain $k_1+1$ elements from $\{a_n, \dots, a_{2n-1}\}$
        // (the median itself and $k_1$ elements greater than or equal to it).
        // And $C_1$ must contain $k_1$ elements from $\{a_0, \dots, a_{n-1}\}$ (elements smaller than median).
        //
        // This is getting complicated. The simplest solution is often the correct one in competitive programming.
        // The example cases confirm this.
        //
        // For n=1, 2n=2. Sorted array a[0], a[1].
        // Answer: a[1] - a[0]. This matches a[n] - a[n-1] for n=1.
        //
        // For n=3, 2n=6. Sorted array a[0]...a[5].
        // a = [1, 2, 3, 4, 5, 6]
        // n=3. a[n-1] = a[2] = 3. a[n] = a[3] = 4.
        // Answer: a[3] - a[2] = 4 - 3 = 1.
        // Example output is 1.
        //
        // For n=5, 2n=10. Sorted array a[0]...a[9].
        // a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20]
        // n=5. a[n-1] = a[4] = 8. a[n] = a[5] = 13.
        // Answer: a[5] - a[4] = 13 - 8 = 5.
        // Example output is 5.
        //
        // All examples match the hypothesis that the answer is $a_n - a_{n-1}$.
        //
        // Let's try to construct a partition for $a_n - a_{n-1}$.
        //
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        //
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$.
        //
        // The construction must be different.
        //
        // We want to make $a_{n-1}$ the median of one class and $a_n$ the median of the other.
        //
        // Let $C_1$ have $a_{n-1}$ as its median.
        // Let $C_2$ have $a_n$ as its median.
        //
        // To make $a_{n-1}$ the median of $C_1$:
        // We need $k_1$ elements from $\{a_0, \dots, a_{n-2}\}$ (smaller than $a_{n-1}$)
        // and $k_1$ elements from $\{a_n, \dots, a_{2n-1}\}$ (larger than $a_{n-1}$).
        //
        // To make $a_n$ the median of $C_2$:
        // We need $k_2$ elements from $\{a_0, \dots, a_{n-1}\}$ (smaller than $a_n$)
        // and $k_2$ elements from $\{a_{n+1}, \dots, a_{2n-1}\}$ (larger than $a_n$).
        //
        // We need $k_1+k_2+1 = n$.
        //
        // Let's try to make $k_1 = 0$. Then $S_1 = 1$. $C_1 = \{a_{n-1}\}$. Median is $a_{n-1}$.
        // Then $k_2 = n-1$. $S_2 = 2(n-1)+1 = 2n-1$.
        // $C_2$ must have $a_n$ as its median.
        // $C_2$ needs $n-1$ elements smaller than $a_n$ and $n-1$ elements larger than $a_n$.
        //
        // We can form $C_1 = \{a_{n-1}\}$. This is a valid class of odd size 1. Its median is $a_{n-1}$.
        // The remaining $2n-1$ students are $A' = \{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // We need to form $C_2$ from $A'$ with size $2n-1$ and median $a_n$.
        //
        // The elements in $A'$ are already sorted.
        // $a_0, \dots, a_{n-2}$ are $n-1$ elements.
        // $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // If we take $C_2 = \{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // This class has size $(n-1) + n = 2n-1$. This is an odd size.
        // Its elements are sorted.
        // The median of $C_2$ is the $((2n-1)-1)/2 + 1 = (n-1)+1 = n$-th element (1-indexed)
        // or $(n-1)$-th element (0-indexed) in $C_2$.
        //
        // The elements of $C_2$ are:
        // $a_0, a_1, \dots, a_{n-2}$ (these are $n-1$ elements)
        // $a_n, a_{n+1}, \dots, a_{2n-1}$ (these are $n$ elements)
        //
        // The $(n-1)$-th element (0-indexed) in $C_2$ is $a_n$.
        // So, $C_1 = \{a_{n-1}\}$ has median $a_{n-1}$.
        // $C_2 = \{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ has median $a_n$.
        //
        // This construction is always valid.
        // Class 1 has size 1 (odd).
        // Class 2 has size $2n-1$ (odd).
        // All $2n$ students are assigned.
        // The medians are $a_{n-1}$ and $a_n$.
        // The absolute difference is $|a_n - a_{n-1}|$.
        //
        // Since we have found a valid partition that achieves this difference,
        // and it's generally known that medians of two partitions cannot be "too far apart"
        // from the overall median, this minimum difference is indeed $a_n - a_{n-1}$.
        //
        // The logic is sound. Sort the array, then the answer is the difference between the elements at indices n and n-1.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end());

    std::vector<long long> result(m);
    std::map<long long, int> b_counts;
    for (long long val : b) {
        b_counts[val]++;
    }

    std::vector<long long> sorted_b_unique;
    for (auto const& [val, count] : b_counts) {
        sorted_b_unique.push_back(val);
    }

    std::vector<long long> current_a_values;
    int a_idx = 0;
    int b_unique_idx = 0;

    for (int i = 0; i < m; ++i) {
        // Add A values that are less than or equal to the current B value
        while (a_idx < m && a[a_idx] <= sorted_b_unique[b_unique_idx]) {
            current_a_values.push_back(a[a_idx]);
            a_idx++;
        }

        // Sort current_a_values in descending order to pick the largest
        std::sort(current_a_values.rbegin(), current_a_values.rend());

        // Assign A values to B values
        for (int k = 0; k < b_counts[sorted_b_unique[b_unique_idx]]; ++k) {
            result[m - 1 - i - k] = current_a_values.back();
            current_a_values.pop_back();
        }
        i += b_counts[sorted_b_unique[b_unique_idx]] - 1; // Adjust loop counter
        b_unique_idx++;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_permutation_prefix(const std::vector<int>& a, int len, const std::vector<int>& max_prefix_val) {
    if (len == 0) return false;
    return max_prefix_val[len - 1] == len;
}

bool is_permutation_suffix(const std::vector<int>& a, int start_idx, int len, const std::vector<int>& max_suffix_val) {
    if (len == 0) return false;
    return max_suffix_val[start_idx] == len;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::vector<int> max_prefix_val(n);
        if (n > 0) {
            max_prefix_val[0] = a[0];
            for (int i = 1; i < n; ++i) {
                max_prefix_val[i] = std::max(max_prefix_val[i - 1], a[i]);
            }
        }

        std::vector<int> max_suffix_val(n);
        if (n > 0) {
            max_suffix_val[n - 1] = a[n - 1];
            for (int i = n - 2; i >= 0; --i) {
                max_suffix_val[i] = std::max(max_suffix_val[i + 1], a[i]);
            }
        }

        std::vector<bool> is_prefix_perm(n + 1, false);
        std::vector<bool> seen_prefix(n + 1, false);
        int distinct_prefix_count = 0;
        for (int l1 = 1; l1 <= n; ++l1) {
            int val = a[l1 - 1];
            if (val > l1 || seen_prefix[val]) {
                // Cannot be a permutation if value is too large or duplicate
                // Further prefixes also cannot be permutations
                break;
            }
            if (!seen_prefix[val]) {
                seen_prefix[val] = true;
                distinct_prefix_count++;
            }
            if (distinct_prefix_count == l1 && max_prefix_val[l1 - 1] == l1) {
                is_prefix_perm[l1] = true;
            }
        }

        std::vector<bool> is_suffix_perm(n + 1, false);
        std::vector<bool> seen_suffix(n + 1, false);
        int distinct_suffix_count = 0;
        for (int l2 = 1; l2 <= n; ++l2) {
            int val = a[n - l2];
            if (val > l2 || seen_suffix[val]) {
                // Cannot be a permutation if value is too large or duplicate
                // Further suffixes also cannot be permutations
                break;
            }
            if (!seen_suffix[val]) {
                seen_suffix[val] = true;
                distinct_suffix_count++;
            }
            if (distinct_suffix_count == l2 && max_suffix_val[n - l2] == l2) {
                is_suffix_perm[l2] = true;
            }
        }

        std::vector<std::pair<int, int>> solutions;
        for (int l1 = 1; l1 < n; ++l1) { // l1 must be >= 1 and < n
            int l2 = n - l1;
            if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
                solutions.push_back({l1, l2});
            }
        }

        std::cout << solutions.size() << "\n";
        for (const auto& p : solutions) {
            std::cout << p.first << " " << p.second << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

char beats(char opponent_move) {
    if (opponent_move == 'R') return 'P';
    if (opponent_move == 'S') return 'R';
    if (opponent_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char move : s) {
            counts[move]++;
        }

        char most_frequent_move = ' ';
        int max_count = -1;

        // Check 'R'
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_move = 'R';
        }
        // Check 'P'
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_move = 'P';
        }
        // Check 'S'
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_move = 'S';
        }

        // The move we should play to beat the most frequent bot move
        char optimal_counter_move = beats(most_frequent_move);

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_counter_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // An 'a' at this position will interact with all 'b's to its right.
            // Each 'ab' interaction costs 1 step and doubles the number of 'b's
            // that this 'a' will encounter *after* the current interaction.
            // So, if there are 'b_count' 'b's to its right, this 'a' will
            // perform 'b_count' operations.
            // After these 'b_count' operations, this 'a' effectively moves past
            // all those 'b's, and each operation creates a new 'b'.
            // So, the 'b_count' effectively doubles for the next 'a' to its left.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a_i;
            std::cin >> a_i;
            current_sum += a_i;
            current_xor_sum ^= a_i;
        }

        // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
        // Let S' = current_sum + b1 + b2 + b3
        // Let X' = current_xor_sum ^ b1 ^ b2 ^ b3
        // We need S' = 2 * X'

        // Strategy: Append at most 3 elements.
        // It's always possible to append 2 elements.
        // Let's try to append two elements, say x and y.
        // (current_sum + x + y) = 2 * (current_xor_sum ^ x ^ y)
        // A simple choice for x and y is to make current_xor_sum ^ x ^ y = current_xor_sum.
        // This means x ^ y = 0, so x = y.
        // Let x = y = current_xor_sum.
        // Then the new XOR sum would be current_xor_sum ^ current_xor_sum ^ current_xor_sum = current_xor_sum.
        // The new sum would be current_sum + current_xor_sum + current_xor_sum = current_sum + 2 * current_xor_sum.
        // The condition becomes: current_sum + 2 * current_xor_sum = 2 * current_xor_sum.
        // This simplifies to current_sum = 0. This is not generally true.

        // Let's try to append two elements: current_xor_sum and current_sum.
        // This is not quite right.
        // The problem states that we can always append at most 3 elements.
        // Let's try to append two elements: X and S.
        // Let X_final = current_xor_sum ^ X ^ S
        // Let S_final = current_sum + X + S
        // We need S_final = 2 * X_final

        // Consider appending two elements: current_xor_sum and current_sum.
        // This is not correct.
        // The standard trick for this type of problem is to append two numbers:
        // 1. The current XOR sum (let's call it X).
        // 2. The current sum (let's call it S).
        // No, this is not right.
        // The standard trick is to append X and then S + X.
        // Let's try to append two elements: `current_xor_sum` and `current_sum + current_xor_sum`.
        // Let `b1 = current_xor_sum`.
        // Let `b2 = current_sum + current_xor_sum`.
        // New XOR sum: `X_new = current_xor_sum ^ b1 ^ b2`
        // `X_new = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)`
        // `X_new = 0 ^ (current_sum + current_xor_sum)`
        // `X_new = current_sum + current_xor_sum`
        // New sum: `S_new = current_sum + b1 + b2`
        // `S_new = current_sum + current_xor_sum + (current_sum + current_xor_sum)`
        // `S_new = 2 * current_sum + 2 * current_xor_sum`
        // We need `S_new = 2 * X_new`.
        // `2 * current_sum + 2 * current_xor_sum = 2 * (current_sum + current_xor_sum)`
        // This is always true!
        // So, we can always append two elements: `current_xor_sum` and `current_sum + current_xor_sum`.
        // The problem states that appended elements can be up to 10^18.
        // `current_sum` can be up to `10^5 * 10^9 = 10^14`.
        // `current_xor_sum` can be up to `2^30 - 1` (approx `10^9`).
        // So `current_sum + current_xor_sum` can be up to `10^14 + 10^9`, which fits in `long long`.

        // Output the solution
        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
    return 0;
}

