#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // `i` represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // Sum of w[n-j]...w[n-1]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for extra items
        if (i > j) { // More items from left than right
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (long long)(j - i - 1) * Qr;
        }
        // If i == j, no extra penalty from Ql or Qr (i-j-1 or j-i-1 would be -1)
        // The problem statement implies penalty only if there are *more* items of one type.
        // The logic (i-j-1) and (j-i-1) correctly handles this.
        // For example, if i=3, j=1, then i-j=2. We have 2 more left items.
        // The sequence could be LRL, LLR, RLL.
        // If we take 3 left, 1 right. The items are LLLR.
        // The "extra" items are those that cause consecutive picks of the same type.
        // If i=3, j=1, total 4 items.
        // L L L R. 2 extra L picks. (i-j-1) = 3-1-1 = 1. This is not 2.
        // The problem states: "If the previous action was the same (left-hand), then the robot spends extra Q_l energy units".
        // This means if we take `i` items from left and `j` items from right,
        // and `i > j`, then there are `i-j` "excess" left items.
        // These `i-j` excess items must be taken after all `j` right items are taken.
        // For example, if i=3, j=1. Sequence could be LRL. Then 2 L items remain.
        // LRL L L. The last two L's are consecutive.
        // The number of times we pick an item of type X consecutively, *after* all items of type Y are exhausted,
        // is (count_X - count_Y - 1) if count_X > count_Y.
        // Example: i=3, j=1. LLLR.
        // L (cost w1*l)
        // L (cost w2*l + Ql)
        // L (cost w3*l + Ql)
        // R (cost w4*r)
        // Total Ql: 2*Ql.
        // Our formula (i-j-1) gives (3-1-1) = 1. This is incorrect.
        // The problem states: "If the previous action was the same (left-hand), then the robot spends extra Q_l energy units".
        // This means if we take `k` items from the left, there are `k-1` potential `Ql` penalties.
        // If we take `k` items from the right, there are `k-1` potential `Qr` penalties.
        // The crucial part is when we switch hands.
        //
        // Let's re-evaluate the penalty logic.
        // The total number of items is `n`. We take `i` from left and `j` from right.
        // The minimum number of "switches" between left and right is 0 (if all from one side) or 1 (if we take some from left, then some from right, or vice versa).
        // The maximum number of switches is `min(i, j) * 2`.
        //
        // Consider the case where `i` items are taken from left and `j` items from right.
        // Total items `i+j = n`.
        //
        // If `i == j`:
        // We can alternate LRLR... or RLRL...
        // No consecutive picks of the same type *after* all items of the other type are gone.
        // The number of "excess" items of one type is 0.
        // So, no `Ql` or `Qr` penalty from this rule.
        //
        // If `i > j`:
        // We have `i` left items and `j` right items.
        // We can pick `j` left items and `j` right items in an alternating fashion (e.g., LRLR... or RLRL...).
        // After these `2j` items are picked, there are `i - j` left items remaining.
        // These `i - j` left items must be picked consecutively from the left.
        // The first of these `i - j` items might or might not incur a `Ql` penalty, depending on the last pick of the `2j` items.
        // However, the problem states "If the previous action was the same".
        // If we pick `i-j` items from the left, and the previous action was also left, we pay `Ql`.
        // If the previous action was right, we don't pay `Ql` for the first of these `i-j` items.
        // But all subsequent `i-j-1` items will definitely incur `Ql` because they are picked after a left item.
        // So, there are `i-j-1` guaranteed `Ql` penalties for these "excess" left items.
        //
        // If `j > i`:
        // Similarly, there are `j - i` right items remaining after `2i` alternating picks.
        // These `j - i` right items must be picked consecutively from the right.
        // This results in `j - i - 1` guaranteed `Qr` penalties.
        //
        // The formula `(i - j - 1) * Ql` if `i > j` and `(j - i - 1) * Qr` if `j > i` is correct.
        // This is because if `i > j`, there are `i-j` items that are picked from the left after all right items are gone.
        // The first of these `i-j` items might not incur a penalty (if the last item picked before it was a right item).
        // But the remaining `(i-j)-1` items will definitely incur a penalty.
        // So, `max(0LL, (long long)i - j - 1) * Ql` is the correct way to write it.
        // The `(long long)` cast is important to prevent overflow before multiplication.

        if (i > j) {
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) {
            current_energy += (long long)(j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

