// Function to get prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, then p is not a valid x.
        // We need to find the largest divisor of p, say x_max, such that x_max is not divisible by q.
        // This means x_max must be p / (some factor k) such that (p/k) % q != 0.
        // To maximize x_max, we need to minimize k.
        // The condition (p/k) % q != 0 means that p/k does not have all prime factors of q
        // with sufficient powers.
        // Let q = q_1^a_1 * q_2^a_2 * ... * q_m^a_m be the prime factorization of q.
        // If p is divisible by q, then p must contain all these prime factors with at least these powers.
        // To make p/k not divisible by q, we must remove enough factors from p such that
        // for at least one prime factor q_j, the power of q_j in p/k is less than a_j.
        // To maximize p/k, we should remove the minimum necessary factors.
        // For each prime factor q_j of q, we can try to divide p by q_j until p is no longer divisible by q_j^a_j.
        // More precisely, we want to find the smallest k such that p/k is not divisible by q.
        // This means for some prime factor q_j of q, v_{q_j}(p/k) < v_{q_j}(q).
        // To achieve this, we must divide p by q_j at least v_{q_j}(p) - v_{q_j}(q) + 1 times.
        // The smallest k that achieves this for a specific q_j is q_j^(v_{q_j}(p) - v_{q_j}(q) + 1).
        // We want to find the maximum p/k. This means we want to find the minimum k.
        // The minimum k will be achieved by dividing p by the smallest possible power of some q_j.
        // So, for each prime factor q_j of q, we calculate p / (q_j ^ (v_{q_j}(p) - v_{q_j}(q) + 1)).
        // The maximum of these values will be our answer.

        std::vector<long long> prime_factors_q = get_prime_factors(q);
        long long max_x = 0;

        for (long long q_prime : prime_factors_q) {
            long long current_p = p;
            // Divide current_p by q_prime until it's no longer divisible by q_prime
            // or until current_p is no longer divisible by q.
            // We want to find the largest divisor of p, say x_candidate, such that x_candidate % q_prime != 0.
            // To do this, we divide p by q_prime until it's no longer divisible by q_prime.
            // This gives us p / (q_prime ^ (v_{q_prime}(p))).
            // This is a valid x_candidate if it's not divisible by q.
            // However, we need to ensure that the resulting x_candidate is not divisible by q.
            // The strategy is: for each prime factor `f` of `q`, we try to make `p` not divisible by `f`.
            // We do this by dividing `p` by `f` repeatedly until `p` is no longer divisible by `f`.
            // Let `temp_p = p`. While `temp_p % q == 0`, divide `temp_p` by `f`.
            // This `temp_p` is a candidate for `x`.
            // We want to find the largest such `temp_p`.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= q_prime;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

