#include <iostream>
#include <algorithm>
#include <vector>

void solve() {
    int n;
    std::cin >> n;

    // Initialize bounds for X and Y.
    // The problem states coordinates are up to 10^5, and if a solution exists,
    // one exists within [-10^5, 10^5].
    // To be safe and handle edge cases where a robot might only be able to move
    // in one direction from its starting point, we can use slightly larger bounds.
    // A common practice is to use -10^9 to 10^9 or similar large values for initial bounds.
    // Given the problem constraints, -200000 to 200000 should be more than enough.
    long long min_x = -200000; 
    long long max_x = 200000;
    long long min_y = -200000;
    long long max_y = 200000;

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1: can move left (x_c - 1, y_c)
        // If f1 == 0, robot cannot move left.
        // This means its final X coordinate must be >= its current X coordinate.
        // So, X >= x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }

        // f2: can move up (x_c, y_c + 1)
        // If f2 == 0, robot cannot move up.
        // This means its final Y coordinate must be <= its current Y coordinate.
        // So, Y <= y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }

        // f3: can move right (x_c + 1, y_c)
        // If f3 == 0, robot cannot move right.
        // This means its final X coordinate must be <= its current X coordinate.
        // So, X <= x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }

        // f4: can move down (x_c, y_c - 1)
        // If f4 == 0, robot cannot move down.
        // This means its final Y coordinate must be >= its current Y coordinate.
        // So, Y >= y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid target point exists. We can pick any point within the valid range.
        // For example, (min_x, min_y).
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        // No valid target point exists.
        std::cout << 0 << "\n";
    }
}

