        // 1. The number of coders: k <= c
        // 2. The number of mathematicians: k <= m
        // 3. The total number of students: 3 * k <= c + m + x
        // Combining 1 and 2: k <= min(c, m)
        // Combining all: k <= min(c, m, (c + m + x) / 3)
        // We can use binary search for k, or observe that the maximum k is bounded by min(c, m)
        // and also by the total number of students divided by 3.
        // So, k must be less than or equal to min(c, m) AND k must be less than or equal to (c + m + x) / 3.
        // Therefore, k <= min(c, m, (c + m + x) / 3).
        // The maximum possible value for k is exactly this minimum.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
