int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // Since MOD is prime and > 2, MOD_INV_2 exists.
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;

    // Modular inverse of 2 modulo MOD
    // MOD = 10^9 + 7, which is prime.
    // Using Fermat's Little Theorem: a^(MOD-2) % MOD
    long long inv2 = (MOD + 1) / 2; // (1000000007 + 1) / 2 = 500000004

    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum(k*b) + sum(1)
    // = b * sum(k) + a
    // sum(k) for k from 1 to a is a * (a+1) / 2
    long long sum_k_b_plus_1_term = (a * (a + 1) / 2) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term * b) % MOD;
    sum_k_b_plus_1_term = (sum_k_b_plus_1_term + a) % MOD;

    long long total_sum = (sum_r_term * sum_k_b_plus_1_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

