void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> present_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s[s[i] - 'a'] = true;
        if (i + 1 < s.length()) {
            adj[s[i] - 'a'].insert(s[i+1]);
            adj[s[i+1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && adj[i].size() <= 1 && !visited[i]) {
            // This is a potential start of a path (or an isolated character in s)
            char current_char = (char)('a' + i);

            while (current_char != 0) { // 0 indicates end of path
                if (visited[current_char - 'a']) {
                    // This should not happen if logic is correct and no cycles are formed
                    // within a path, but as a safeguard.
                    break; 
                }
                visited[current_char - 'a'] = true;
                layout += current_char;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                current_char = next_char;
            }
        }
    }

    // Check if all characters present in 's' have been included in the layout
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
