            // The logic for finding starting points should cover this.
            // If a character in 's' is not visited, it means it's part of a component
            // where all nodes have degree 2, which is a cycle.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in 's'
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

