    // This is equivalent to comparing s[k...L-1]s[0...k-1] with s[k'...L-1]s[0...k'-1] starting from index 1.
    // The length of the common prefix of s[a...L-1]s[0...a-1] and s[b...L-1]s[0...b-1]
    // is the length of the common prefix of s[a...L-1]s[0...a-1]s[a...L-1]s[0...a-1] and s[b...L-1]s[0...b-1]s[b...L-1]s[0...b-1]
    // This is the LCP of cyclic shifts.
    // We can use Z-algorithm on s + s.
    std::string s_double = s + s;
    std::vector<std::vector<int>> z_table(L); // z_table[i] stores Z-function for s_double starting at index i

    for (int i = 0; i < L; ++i) {
        std::string temp_s = s_double.substr(i);
        z_table[i] = calculate_z_function(temp_s);
    }

    // Function to get LCP of two cyclic shifts starting at k1 and k2
    // LCP(s_k1, s_k2)
    auto get_lcp = [&](int k1, int k2) {
        if (k1 == k2) return L;
        // LCP of s[k1...L-1]s[0...k1-1] and s[k2...L-1]s[0...k2-1]
        // This is equivalent to LCP of s_double.substr(k1) and s_double.substr(k2)
        // The Z-value for s_double.substr(k2) compared to s_double.substr(k1)
        // is z_table[k1][k2 - k1] if k2 > k1
        // or z_table[k2][k1 - k2] if k1 > k2
        // More generally, it's z_table[k_start][k_other - k_start]
        // where k_start is the starting index of the string for which z_table was computed.
        // We need LCP of s_double.substr(k1) and s_double.substr(k2).
        // This is z_table[k1][k2 - k1] if k2 > k1.
        // If k1 > k2, it's z_table[k2][k1 - k2].
        // A simpler way: LCP of s_double.substr(k1) and s_double.substr(k2)
        // is z_table[k1][k2 - k1] if k2 > k1.
        // If k1 > k2, it's z_table[k2][k1 - k2].
        // This is not quite right. z_table[k1] is Z-function for s_double.substr(k1).
        // z_table[k1][j] is LCP of s_double.substr(k1) and s_double.substr(k1+j).
        // So, LCP(s_k1, s_k2) is z_table[k1][k2 - k1] if k2 > k1.
        // If k1 > k2, it's z_table[k2][k1 - k2].
        // This is for comparing s[k1...] with s[k2...].
        // The LCP of two cyclic shifts s_k1 and s_k2 is LCP(s_double.substr(k1), s_double.substr(k2)).
        // This is z_table[k1][k2 - k1] if k2 > k1.
        // If k1 > k2, it's z_table[k2][k1 - k2].
        // This is correct.
        if (k1 < k2) {
            return z_table[k1][k2 - k1];
        } else { // k1 > k2
            return z_table[k2][k1 - k2];
        }
    };

    double total_win_prob = 0.0;

    // Group shifts by their first character t[0] = s[k]
    std::map<char, std::vector<int>> shifts_by_first_char;
    for (int k = 0; k < L; ++k) {
        shifts_by_first_char[s[k]].push_back(k);
    }

    for (auto const& [first_char, k_indices] : shifts_by_first_char) {
        if (k_indices.empty()) continue;

        // If only one shift starts with this character, Vasya wins for sure for this char.
        // But this is not true. Vasya needs to uniquely identify k.
        // If there are multiple k's that result in the same t[0] and t[p-1], Vasya loses.
        // So, if k_indices.size() == 1, Vasya wins for this k.
        // The problem states "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
        // So if k_indices.size() == 1, Vasya wins for this k.
        // This is handled by the loop below.

        double max_win_prob_for_char = 0.0;

        // Vasya chooses p (1-indexed, so t[p-1])
        // p can be from 1 to L-1 (since t[0] is already known)
        for (int p = 1; p < L; ++p) { // p is 1-indexed position, so t[p-1]
            std::map<char, std::vector<int>> shifts_by_second_char;
            for (int k : k_indices) {
                shifts_by_second_char[s[(k + p) % L]].push_back(k);
            }

            int current_p_wins = 0;
            for (auto const& [second_char, k_indices_filtered] : shifts_by_second_char) {
                if (k_indices_filtered.empty()) continue;

                if (k_indices_filtered.size() == 1) {
                    current_p_wins++;
                } else {
                    // Check if any k in k_indices_filtered can be uniquely identified
                    // A k is uniquely identified if for all other k' in k_indices_filtered,
                    // (t[0], t[p-1]) for k is different from (t[0], t[p-1]) for k'.
                    // This is already guaranteed by grouping.
                    // So, if k_indices_filtered.size() > 1, Vasya loses for all these k's.
                    // However, the problem states: "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                    // This means if k_indices_filtered.size() > 1, Vasya loses for all these k's.
                    // So, current_p_wins does not increase.
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)current_p_wins);
        }
        total_win_prob += max_win_prob_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

struct Operation {
    char type;
    int val;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char type;
        int val;
        std::cin >> type >> val;

        if (type == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (type == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (type == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    std::vector<Operation> result_ops;

    // Determine the final AND mask
    // If a bit in current_and_mask is 0, it means the final value for that bit will be 0, regardless of input.
    // If a bit in current_and_mask is 1, it means the final value for that bit depends on the input and subsequent OR/XOR.
    // So, we need an AND operation with current_and_mask.
    // This AND operation should be the first one.
    // The effective AND mask for the input x is current_and_mask.
    // The effective OR mask for the input x is current_or_mask.
    // The effective XOR mask for the input x is current_xor_mask.

    // The final value for a bit `b` is `((x_b & current_and_mask_b) | current_or_mask_b) ^ current_xor_mask_b`.
    // This can be simplified.
    // Let's find the equivalent A, B, C such that `(x & A | B) ^ C` is the result.

    // For each bit `b` from 0 to 9:
    // Let `x_b` be the b-th bit of input `x`.
    // Let `a_b = (current_and_mask >> b) & 1`.
    // Let `o_b = (current_or_mask >> b) & 1`.
    // Let `x_b = (current_xor_mask >> b) & 1`.

    // The final bit `res_b` is `((x_b & a_b) | o_b) ^ x_b`.

    // We want to find `final_and_val`, `final_or_val`, `final_xor_val`
    // such that `(x & final_and_val | final_or_val) ^ final_xor_val` is equivalent.

    int final_and_val = 0;
    int final_or_val = 0;
    int final_xor_val = 0;

    for (int b = 0; b < 10; ++b) {
        int a_b = (current_and_mask >> b) & 1;
        int o_b = (current_or_mask >> b) & 1;
        int x_b = (current_xor_mask >> b) & 1;

        // Test with input bit 0
        int res_0 = ((0 & a_b) | o_b) ^ x_b;
        // Test with input bit 1
        int res_1 = ((1 & a_b) | o_b) ^ x_b;

        // We need to find `fa_b`, `fo_b`, `fx_b` such that
        // `((0 & fa_b) | fo_b) ^ fx_b == res_0`
        // `((1 & fa_b) | fo_b) ^ fx_b == res_1`

        // Case 1: fa_b = 0
        // `(0 | fo_b) ^ fx_b == res_0` => `fo_b ^ fx_b == res_0`
        // `(0 | fo_b) ^ fx_b == res_1` => `fo_b ^ fx_b == res_1`
        // This implies `res_0 == res_1`. If they are different, fa_b cannot be 0.
        if (res_0 == res_1) {
            // If fa_b = 0, then the input bit doesn't matter.
            // The output bit is fixed to `res_0`.
            // This means we need to set `fo_b` to `res_0 ^ fx_b`.
            // We can achieve this by `(x & 0 | res_0) ^ 0` or `(x & 0 | (1-res_0)) ^ 1`.
            // Let's choose `fa_b = 0`, `fx_b = 0`. Then `fo_b = res_0`.
            // This means `final_and_val` has 0 at bit `b`.
            // `final_or_val` has `res_0` at bit `b`.
            // `final_xor_val` has 0 at bit `b`.
            final_or_val |= (res_0 << b);
        } else { // res_0 != res_1. This means fa_b must be 1.
            // If fa_b = 1, then:
            // `((0 & 1) | fo_b) ^ fx_b == res_0` => `fo_b ^ fx_b == res_0`
            // `((1 & 1) | fo_b) ^ fx_b == res_1` => `(1 | fo_b) ^ fx_b == res_1`
            // Since `1 | fo_b` is always 1, this simplifies to `1 ^ fx_b == res_1`.

            // From `1 ^ fx_b == res_1`, we get `fx_b = 1 ^ res_1`.
            // From `fo_b ^ fx_b == res_0`, we get `fo_b = res_0 ^ fx_b`.
            // Substituting `fx_b`: `fo_b = res_0 ^ (1 ^ res_1)`.

            // So, for this bit `b`:
            // `final_and_val` has 1 at bit `b`.
            // `final_xor_val` has `(1 ^ res_1)` at bit `b`.
            // `final_or_val` has `(res_0 ^ (1 ^ res_1))` at bit `b`.
            final_and_val |= (1 << b);
            final_xor_val |= ((1 ^ res_1) << b);
            final_or_val |= ((res_0 ^ (1 ^ res_1)) << b);
        }
    }

    // Now we have `final_and_val`, `final_or_val`, `final_xor_val`.
    // The equivalent program is `(x & final_and_val | final_or_val) ^ final_xor_val`.
    // We need to output these operations.
    // An AND operation with 1023 is a no-op.
    // An OR operation with 0 is a no-op.
    // An XOR operation with 0 is a no-op.

    if (final_and_val != 1023) {
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) {
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) {
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.type << " " << op.val << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total counts
    int initial_s = 0;
    int initial_b = 0;
    for (int x : a) {
        if (x == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // Precompute prefix sums for left side (jars 0 to n-1)
    // and suffix sums for right side (jars n to 2n-1)
    // For left side, we iterate from left to right.
    // For right side, we iterate from right to left.

    // Left side: jars 0 to n-1
    // diff_L[k] = (count of 1s in a[k]...a[n-1]) - (count of 2s in a[k]...a[n-1])
    // This is equivalent to (count of 1s in a[0]...a[n-1]) - (count of 2s in a[0]...a[n-1])
    // minus (count of 1s in a[0]...a[k-1]) - (count of 2s in a[0]...a[k-1])
    // Let's use prefix sums from left to right for the left half.
    // `left_diff[k]` will store (count of 1s - count of 2s) for jars `a[0]` to `a[k-1]`.
    // `left_diff[0]` is 0 (empty prefix).
    // `left_diff[k]` for `k` from 1 to `n`.
    std::vector<int> left_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_diff[i + 1] = left_diff[i] + (a[i] == 1 ? 1 : -1);
    }

    // Right side: jars n to 2n-1
    // `right_diff[k]` will store (count of 1s - count of 2s) for jars `a[2n-1]` down to `a[2n-k]`.
    // `right_diff[0]` is 0 (empty suffix).
    // `right_diff[k]` for `k` from 1 to `n`.
    std::vector<int> right_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_diff[i + 1] = right_diff[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars eaten from the right side for each possible `right_diff` value.
    // `map_right_diff[diff_val]` = `k_R` (number of jars eaten from right)
    std::map<int, int> map_right_diff;
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff = right_diff[k_R];
        if (map_right_diff.find(current_diff) == map_right_diff.end()) {
            map_right_diff[current_diff] = k_R;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible `k_L` (jars eaten from left)
    for (int k_L = 0; k_L <= n; ++k_L) {
        // `diff_remaining_left` is the (1s - 2s) for jars `a[k_L]` to `a[n-1]`
        int diff_remaining_left = left_diff[n] - left_diff[k_L];

        // We need `diff_remaining_left + diff_remaining_right = 0`
        // So, `diff_remaining_right` must be `-diff_remaining_left`.
        int target_diff_right = -diff_remaining_left;

        if (map_right_diff.count(target_diff_right)) {
            int k_R = map_right_diff[target_diff_right];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Iterate through all possible right endpoints r
    for (int r = 0; r < n; ++r) {
        // Find the first '1' to the left of or at r
        int first_one_idx = -1;
        for (int k = r; k >= 0; --k) {
            if (s[k] == '1') {
                first_one_idx = k;
                break;
            }
        }

        if (first_one_idx == -1) {
            // No '1' found up to r, so all substrings ending at r are '0's.
            // f(0...0) = 0. Length must be 0, which is impossible for non-empty substrings.
            // So no good substrings ending at r if all are '0's.
            continue;
        }

        // Now, first_one_idx is the index of the most significant bit (MSB) for any
        // substring s[l...r] that starts with '1'.
        // The actual value of the substring s[l...r] is determined by s[first_one_idx...r].
        // The length of this part is r - first_one_idx + 1.
        // The maximum possible value for a substring of length L is 2^L - 1.
        // The maximum length of s is 2e5.
        // If a substring has length L, its value must be L.
        // 2^L - 1 >= L. This holds for L >= 1.
        // However, if L is large, 2^L grows much faster than L.
        // For example, if L = 18, 2^18 = 262144.
        // If L = 19, 2^19 = 524288.
        // The maximum possible value for a substring of length 19 is 2^19 - 1.
        // If the length of the string s is N, then the maximum possible length of a substring is N.
        // If N = 2e5, then 2^18 is already larger than N.
        // This means we only need to check substrings whose actual binary value
        // (ignoring leading zeros) is not too large.
        // Specifically, if the value of s[first_one_idx...r] is V, and its length is L_val = r - first_one_idx + 1.
        // The full substring is s[l...r], its length is L_full = r - l + 1.
        // We need L_full = V.
        // Since s[l...r] has leading zeros if l < first_one_idx, its value is still V.
        // So we need r - l + 1 = V.
        // This implies l = r + 1 - V.
        // We also need l <= first_one_idx (because s[first_one_idx] is the MSB).
        // So, r + 1 - V <= first_one_idx.
        // And l >= 0. So r + 1 - V >= 0.

        long long current_val = 0;
        // Iterate from first_one_idx to r to calculate the value
        // and check the condition.
        // The maximum length of s[first_one_idx...r] is r - first_one_idx + 1.
        // If this length exceeds ~20, the value will be too large to be equal to r - l + 1.
        // Max value of r - l + 1 is N = 2e5.
        // 2^17 = 131072. 2^18 = 262144.
        // So, if r - first_one_idx + 1 > 18, the value will be > 2e5,
        // which means it cannot be equal to r - l + 1 (since r - l + 1 <= N).
        // So we only need to consider substrings s[first_one_idx...r] where
        // r - first_one_idx + 1 is at most around 18-20.
        // Let's use a safe upper bound like 20.
        int max_len_from_first_one = std::min(r - first_one_idx + 1, 20); // Max 20 bits for value calculation

        for (int k = 0; k < max_len_from_first_one; ++k) {
            int current_bit_idx = r - k; // current_bit_idx goes from r down to r - max_len_from_first_one + 1

            // Calculate value from s[current_bit_idx...r]
            // This is equivalent to s[first_one_idx...r] if current_bit_idx == first_one_idx
            // and we are building the value from right to left.
            // No, this is not correct. We need to calculate the value of s[first_one_idx...r].
            // Let's recalculate current_val for s[first_one_idx...r]
            // The loop should be from first_one_idx to r.
            // current_val = (current_val << 1) | (s[i] - '0');
            // This is for fixed first_one_idx.

            // Let's restart the inner loop logic.
            // For a fixed r, and fixed first_one_idx (the first '1' to the left of or at r).
            // We are interested in substrings s[l...r] where l <= first_one_idx.
            // The value of s[l...r] is determined by s[first_one_idx...r].
            // Let V = f(s[first_one_idx...r]).
            // Let L_val = r - first_one_idx + 1.
            // We need to find l such that r - l + 1 = V.
            // This means l = r + 1 - V.
            // We need to check two conditions for this l:
            // 1. l >= 0
            // 2. l <= first_one_idx (to ensure s[first_one_idx] is indeed the MSB of the value V)

            // Calculate V for s[first_one_idx...r]
            current_val = 0;
            for (int i = first_one_idx; i <= r; ++i) {
                current_val = (current_val << 1) | (s[i] - '0');
                // If current_val exceeds N (max possible length), then it can't be a good substring.
                // We can cap current_val at N+1 to avoid overflow and unnecessary large calculations.
                if (current_val > n + 1) { // N+1 is a safe upper bound for length
                    current_val = n + 1;
                    break;
                }
            }

            // Now we have V = current_val.
            // Calculate the required starting index l.
            long long required_l = r + 1 - current_val;

            // Check conditions:
            // 1. required_l >= 0
            // 2. required_l <= first_one_idx
            if (required_l >= 0 && required_l <= first_one_idx) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Calculate the minimum number of moves to reach (n, m) using only diagonal and axis-parallel moves.
        // This is equivalent to max(abs(n), abs(m)) if we can move freely.
        // Here, we are moving from (0,0) to (n,m), so abs(n) and abs(m) are just n and m.
        // The minimum number of moves is n (by making m diagonal moves and n-m axis-parallel moves).
        // If k < n, it's impossible to reach (n,m) in k moves.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Parity check:
        // Each move changes the sum of coordinates (x+y) by -2, 0, or 2 for diagonal moves,
        // and by -1 or 1 for axis-parallel moves.
        // More simply, each move changes the parity of x or y or both.
        // A diagonal move changes both x and y, so (x+y) changes by an even amount.
        // An axis-parallel move changes one of x or y, so (x+y) changes by an odd amount.
        //
        // The parity of (n+m) must be the same as the parity of k.
        // If (n+m) and k have different parities, it's impossible.
        // (n % 2) != (k % 2) is equivalent to (n+k) % 2 != 0.
        if ((n % 2) != (k % 2)) {
            // If n and k have different parities, and n >= m,
            // then we need to make an odd number of "extra" moves to adjust parity.
            // This means we must use at least one move that changes the parity of the sum of coordinates.
            //
            // Consider the target (n, m) and k moves.
            // If n and k have different parities, it means we need to make an odd number of moves
            // that change the parity of the x-coordinate.
            //
            // If n and k have different parities, we must make at least one move that changes the parity of the x-coordinate.
            // If we make k moves, and n and k have different parities,
            // we can reach (n, m) if we make k-1 moves to reach (n', m') where n' and k-1 have same parity,
            // and then one move to adjust.
            //
            // The simplest way to think about this is that each move changes the parity of (x+y) by 1.
            // So, after k moves, the parity of (current_x + current_y) will be (0+0+k) % 2 = k % 2.
            // Thus, we must have (n+m) % 2 == k % 2.
            //
            // However, the problem statement implies that we can always reach (n,m) if k >= n and k >= m
            // and k and n have the same parity (after ensuring n >= m).
            //
