        int steps = std::min(dist_to_left_one, dist_to_right_one);
        max_steps = std::max(max_steps, steps);

        if (dist_to_left_one == dist_to_right_one) {
            // The 0 at idx becomes 1.
            final_a[idx] = 1;
        } else if (dist_to_left_one < dist_to_right_one) {
            // The 0 at idx becomes 1.
            final_a[idx] = 1;
            // The 0s to its right, up to idx + dist_to_left_one - 1, also become 1.
            for (int k = idx + 1; k < idx + dist_to_left_one; ++k) {
                final_a[k] = 1;
            }
        } else { // dist_to_right_one < dist_to_left_one
            // The 0 at idx becomes 1.
            final_a[idx] = 1;
            // The 0s to its left, up to idx - dist_to_right_one + 1, also become 1.
            for (int k = idx - 1; k > idx - dist_to_right_one; --k) {
                final_a[k] = 1;
            }
        }
    }

    for (int i = 0; i < right_zeros_idx.size(); ++i) {
        int idx = right_zeros_idx[i];
        int dist_to_left_zero = 0;
        for (int j = idx - 1; j >= 0; --j) {
            if (a[j] == 0) {
                dist_to_left_zero = idx - j;
                break;
            }
        }
        int dist_to_right_zero = 0;
        for (int j = idx + 1; j < n; ++j) {
            if (a[j] == 0) {
                dist_to_right_zero = j - idx;
                break;
            }
        }

        if (dist_to_left_zero == 0 || dist_to_right_zero == 0) { // Should not happen for idx in right_zeros_idx
            // Similar to above, this implies a[idx-1] or a[idx+1] is not 0, which contradicts how right_zeros_idx is populated.
            // The only edge case is if the 0s are at the very ends, e.g., 010.
            // For 010, idx=1. dist_to_left_zero=1, dist_to_right_zero=1.
        }

        int steps = std::min(dist_to_left_zero, dist_to_right_zero);
        max_steps = std::max(max_steps, steps);

        if (dist_to_left_zero == dist_to_right_zero) {
            // The 1 at idx becomes 0.
            final_a[idx] = 0;
        } else if (dist_to_left_zero < dist_to_right_zero) {
            // The 1 at idx becomes 0.
            final_a[idx] = 0;
            // The 1s to its right, up to idx + dist_to_left_zero - 1, also become 0.
            for (int k = idx + 1; k < idx + dist_to_left_zero; ++k) {
                final_a[k] = 0;
            }
        } else { // dist_to_right_zero < dist_to_left_zero
            // The 1 at idx becomes 0.
            final_a[idx] = 0;
            // The 1s to its left, up to idx - dist_to_right_zero + 1, also become 0.
            for (int k = idx - 1; k > idx - dist_to_right_zero; --k) {
                final_a[k] = 0;
            }
        }
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop
    std::vector<int> dp_x(n + 1, 0);

    for (int i = 1; i <= n; ++i) {
        if (i + a[i] > n) { // First step leads to termination
            dp_y[i] = a[i];
            dp_x[i] = i + a[i];
        } else if (i + a[i] <= 0) { // First step leads to termination
            dp_y[i] = a[i];
            dp_x[i] = i + a[i];
        }
    }

    for (int i = 1; i <= n; ++i) {
        if (dp_y[i] != -2) { // Already computed or terminates in first step
            continue;
        }

        std::vector<int> path;
        int current_x = i;

        while (current_x >= 1 && current_x <= n && dp_y[current_x] == -2) {
            path.push_back(current_x);

            long long val_at_current_x = a[current_x];
            int next_x_after_step2 = current_x + val_at_current_x;

            if (next_x_after_step2 > n || next_x_after_step2 <= 0) {
                dp_y[current_x] = val_at_current_x;
                dp_x[current_x] = next_x_after_step2;
                break;
            }

            long long val_at_next_x_after_step2 = a[next_x_after_step2];
            int next_x_after_step3 = next_x_after_step2 - val_at_next_x_after_step2;

            if (next_x_after_step3 > n || next_x_after_step3 <= 0) {
                dp_y[current_x] = val_at_current_x + val_at_next_x_after_step2;
                dp_x[current_x] = next_x_after_step3;
                break;
            }

            current_x = next_x_after_step3;

            // Check for cycle
            bool in_path = false;
            for(size_t k = 0; k < path.size(); ++k) {
                if (path[k] == current_x) {
                    in_path = true;
                    break;
                }
            }
            if (in_path) {
                // Cycle detected, mark all nodes in path as -1
                for (int node : path) {
                    dp_y[node] = -1;
                }
                break;
            }
        }

        // Propagate results back through the path
        for (int k = path.size() - 1; k >= 0; --k) {
            int node = path[k];
            if (dp_y[node] != -2) { // Already computed or part of a cycle
                continue;
            }

            long long val_at_node = a[node];
            int next_x_after_step2 = node + val_at_node;

            if (next_x_after_step2 > n || next_x_after_step2 <= 0) {
                dp_y[node] = val_at_node;
                dp_x[node] = next_x_after_step2;
            } else {
                long long val_at_next_x_after_step2 = a[next_x_after_step2];
                int next_x_after_step3 = next_x_after_step2 - val_at_next_x_after_step2;

                if (next_x_after_step3 > n || next_x_after_step3 <= 0) {
                    dp_y[node] = val_at_node + val_at_next_x_after_step2;
                    dp_x[node] = next_x_after_step3;
                } else {
                    if (dp_y[next_x_after_step3] == -1) {
                        dp_y[node] = -1;
                    } else {
                        dp_y[node] = val_at_node + val_at_next_x_after_step2 + dp_y[next_x_after_step3];
                        dp_x[node] = dp_x[next_x_after_step3];
                    }
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for this run

        long long current_y = 0;
        int current_x = 1;

        long long val_at_current_x = a[current_x];
        current_x += val_at_current_x;
        current_y += val_at_current_x;

        if (current_x > n || current_x <= 0) {
            std::cout << current_y << "\n";
            continue;
        }

        long long val_at_next_x_after_step2 = a[current_x];
        current_y += val_at_next_x_after_step2;
        current_x -= val_at_next_x_after_step2;

        if (current_x > n || current_x <= 0) {
            std::cout << current_y << "\n";
            continue;
        }

        if (dp_y[current_x] == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + dp_y[current_x] << "\n";
        }
    }

    return 0;
}

#include <iostream>
