// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Precompute parities for all prefixes of a
    // parity_a[i] stores parity of a[0...i-1]
    std::vector<int> parity_a_prefix_counts(a.length() + 1, 0);
    for (size_t i = 0; i < a.length(); ++i) {
        parity_a_prefix_counts[i + 1] = parity_a_prefix_counts[i] + (a[i] == '1' ? 1 : 0);
    }

    // Iterate through all possible starting suffixes of 'a'
    // A suffix of 'a' starts at index 'i' (0-indexed)
    for (size_t i = 0; i < a.length(); ++i) {
        std::string current_a_suffix = a.substr(i);

        // Calculate parity of current_a_suffix
        // parity_a_prefix_counts[a.length()] is total ones in 'a'
        // parity_a_prefix_counts[i] is total ones in 'a[0...i-1]'
        // So, total ones in 'a[i...a.length()-1]' is parity_a_prefix_counts[a.length()] - parity_a_prefix_counts[i]
        int current_ones_count = parity_a_prefix_counts[a.length()] - parity_a_prefix_counts[i];
        int current_parity = current_ones_count % 2;

        // Now, we can append parity bits to current_a_suffix
        // We need to check if 'b' can be formed by current_a_suffix + some parity bits
        // This means 'b' must be a prefix of current_a_suffix + parity_bits...
        // OR, current_a_suffix + parity_bits... must be a prefix of 'b'
        // The problem states "turn a into b", so b must be the final string.
        // This implies b must be a suffix of current_a_suffix + parity_bits...
        // No, it means b must be exactly current_a_suffix + parity_bits...

        // Case 1: b is exactly current_a_suffix
        if (current_a_suffix == b) {
            std::cout << "YES\n";
            return 0;
        }

        // Case 2: b is longer than current_a_suffix
        // This means b must be current_a_suffix followed by some parity bits.
        if (b.length() > current_a_suffix.length()) {
            if (b.rfind(current_a_suffix, 0) == 0) { // Check if current_a_suffix is a prefix of b
                std::string remaining_b = b.substr(current_a_suffix.length());

                // Simulate appending parity bits
                std::string temp_s = current_a_suffix;
                int temp_ones_count = current_ones_count;

                bool possible = true;
                for (char expected_char : remaining_b) {
                    int appended_parity = temp_ones_count % 2;
                    if ((appended_parity == 1 && expected_char == '1') || (appended_parity == 0 && expected_char == '0')) {
                        // Correct parity appended
                        if (appended_parity == 1) {
                            temp_ones_count++;
                        }
                    } else {
                        possible = false;
                        break;
                    }
                }
                if (possible) {
                    std::cout << "YES\n";
                    return 0;
                }
            }
        }
    }

    std::cout << "NO\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[i] to a very large value (effectively infinity)
    // This represents the upper bound for a_0[i] derived from type 2 operations.
    // If a_0[i] is not constrained by any type 2 operation, it can be 0.
    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    // Calculate the maximum possible initial_a[i] for each i
    // based on type 2 operations.
    // For each type 2 operation (l, r, m), we know that for any j in [l, r],
    // a_0[j] + sum_d_applied_to_j_before_this_op <= m.
    // This means a_0[j] <= m - sum_d_applied_to_j_before_this_op.
    // We want to find the tightest upper bound for a_0[j].
    // Iterate operations in reverse to calculate sum_d_applied_to_j_before_this_op
    // for each type 2 operation.
    std::vector<long long> current_d_prefix_sum(n + 1, 0); // Stores sum of d for type 1 ops *after* current op
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This is a type 1 operation (l, r, d).
            // It affects elements a[l]...a[r].
            // When we process operations in reverse, this 'd' is applied *before*
            // the current operation in the forward pass.
            // So, we need to subtract 'd' from the prefix sums for elements in [l, r].
            current_d_prefix_sum[ops[i].l] -= ops[i].val;
            current_d_prefix_sum[ops[i].r + 1] += ops[i].val;
        } else {
            // This is a type 2 operation (l, r, m).
            // For each j in [l, r], a_0[j] + (sum of d's before this op) <= m.
            // The sum of d's before this op is the total_d_applied_to_j_at_this_point.
            // This total_d_applied_to_j_at_this_point is calculated by summing
            // all d's from type 1 operations that occurred *before* this op.
            // In our reverse iteration, current_d_prefix_sum helps us calculate this.
            // Let's compute the actual current_d_at_j for this operation.
            long long current_d_at_j = 0;
            for (int j = 0; j < n; ++j) {
                current_d_at_j += current_d_prefix_sum[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    initial_a[j] = std::min(initial_a[j], ops[i].val - current_d_at_j);
                }
            }
        }
    }

    // If initial_a[i] is still max_long_long, it means it was never constrained by a type 2 op.
    // We can set it to 0 to satisfy the |a_i| <= 10^9 constraint.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
    }

    // Verify the constructed initial_a
    // Simulate all operations with the constructed initial_a
    // and check if all type 2 operations yield the expected maximum.
    std::vector<long long> current_a = initial_a;
    std::vector<long long> current_d_diff(n + 1, 0); // Difference array for current_d

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Apply type 1 operation to current_a
            current_d_diff[op.l] += op.val;
            current_d_diff[op.r + 1] -= op.val;
        } else {
            // Check type 2 operation
            long long max_val = std::numeric_limits<long long>::min();
            long long current_d_val = 0;
            for (int j = 0; j < n; ++j) {
                current_d_val += current_d_diff[j];
                if (j >= op.l && j <= op.r) {
                    max_val = std::max(max_val, initial_a[j] + current_d_val);
                }
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i is now cured

        long long current_cry_from_v = children[i].v;
        long long total_d_cry_effect = 0; // Accumulates d_j cries from children who leave

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cry from child i (v_i)
            if (current_cry_from_v > 0) {
                children[j].p -= current_cry_from_v;
                current_cry_from_v--;
            }

            // Apply accumulated d_j cries
            children[j].p -= total_d_cry_effect;

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b_val = 0; // The previous element in the constructed non-decreasing array
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a[i] is already >= prev_b_val.
        // We can potentially keep a[i] as is, or increment it.
        // If a[i] >= prev_b_val, we can set b[i] = a[i].
        // This requires 0 operations for this element.
        // The condition for this is (a[i] + 0) % m >= prev_b_val.
        // This is true if a[i] >= prev_b_val.

        // Case 2: a[i] < prev_b_val.
        // We must increment a[i] to make it at least prev_b_val.
        // The smallest value we can achieve is (a[i] + k) % m >= prev_b_val.
        // This means a[i] + k >= prev_b_val.
        // The minimum k required is prev_b_val - a[i].
        // If this k is <= x, then we can set b[i] = prev_b_val.
        // The condition for this is (a[i] + (prev_b_val - a[i])) % m >= prev_b_val.
        // This is true if prev_b_val - a[i] <= x.

        // Combining these:
        // If a[i] >= prev_b_val:
        //   We can potentially use a[i] as b[i].
        //   We can also potentially use (a[i] + k) % m as b[i] where 0 < k <= x.
        //   If (a[i] + x) % m < prev_b_val, it means even with max operations, we wrap around
        //   and end up below prev_b_val. In this case, we must use prev_b_val.
        //   This happens if a[i] + x < prev_b_val (impossible since a[i] >= prev_b_val and x >= 0)
        //   OR if a[i] + x >= m AND (a[i] + x) % m < prev_b_val.
        //   In this specific scenario, we must use prev_b_val.
        //   Otherwise, we can use a[i] as b[i].

        // If a[i] < prev_b_val:
        //   We must increment a[i].
        //   The target value must be at least prev_b_val.
        //   The minimum increment needed is prev_b_val - a[i].
        //   If prev_b_val - a[i] <= x, we can achieve prev_b_val. So we set b[i] = prev_b_val.
        //   If prev_b_val - a[i] > x, we cannot achieve prev_b_val.
        //   Even if we increment by x, (a[i] + x) % m will be less than prev_b_val.
        //   So it's impossible.

        // Let's simplify the logic:
        // We want to find the smallest b_i >= prev_b_val such that b_i can be formed from a_i
        // using at most x operations.
        // The possible values for b_i are (a_i + k) % m for 0 <= k <= x.

        // Option 1: Don't wrap around m.
        // If a[i] + x >= prev_b_val, then we can potentially set b_i = max(prev_b_val, a[i]).
        // If a[i] >= prev_b_val, we can set b_i = a[i].
        // If a[i] < prev_b_val, we need to increment by at least prev_b_val - a[i].
        // If prev_b_val - a[i] <= x, we can set b_i = prev_b_val.
        // So, if a[i] >= prev_b_val, we can keep prev_b_val as is.
        // If a[i] < prev_b_val, we need to check if a[i] + x >= prev_b_val.
        // If it is, we can set prev_b_val to prev_b_val.
        // If a[i] + x < prev_b_val, then we cannot reach prev_b_val without wrapping.
        // This means we must wrap around.

        // Let's consider the two possible values for b_i:
        // 1. b_i = a_i (if a_i >= prev_b_val)
        // 2. b_i = prev_b_val (if prev_b_val is reachable from a_i)

        // If a[i] >= prev_b_val:
        //   We can potentially set b_i = a[i]. This requires 0 operations.
        //   We can also potentially set b_i = prev_b_val. This requires (prev_b_val - a[i] + m) % m operations.
        //   If (a[i] + x) % m < prev_b_val, it means even with x operations, we cannot reach prev_b_val
        //   without wrapping around and ending up below prev_b_val.
        //   Specifically, if a[i] + x < m and a[i] + x < prev_b_val, then we can't make it.
        //   But we are in the case a[i] >= prev_b_val, so a[i] + x >= prev_b_val is usually true.
        //   The only problematic case is if a[i] + x wraps around and becomes smaller than prev_b_val.
        //   Example: m=10, a[i]=8, x=3, prev_b_val=7.
        //   a[i] >= prev_b_val is true.
        //   (a[i]+x)%m = (8+3)%10 = 1. This is < prev_b_val.
        //   In this case, we cannot use a[i] as b_i, because if we increment it, it becomes 1, which is too small.
        //   We must use prev_b_val. But can we reach prev_b_val?
        //   To reach prev_b_val from a[i] (8 to 7), we need to add (7-8+10)%10 = 9 operations.
        //   If x=3, we cannot do 9 operations. So this is impossible.

        // Correct logic:
        // We need to find a value `val` such that `prev_b_val <= val < m` and `val` can be formed from `a[i]`
        // by adding `k` operations, where `0 <= k <= x`.
        // This means `val = (a[i] + k) % m`.

        // If `a[i]` itself is already greater than or equal to `prev_b_val`:
        //   We can potentially set `b_i = a[i]`. This requires 0 operations.
        //   We can also potentially set `b_i = prev_b_val`. This requires `(prev_b_val - a[i] + m) % m` operations.
        //   If `a[i]` is chosen as `b_i`, then `prev_b_val` for the next iteration becomes `a[i]`.
        //   If `prev_b_val` is chosen as `b_i`, then `prev_b_val` for the next iteration becomes `prev_b_val`.
        //   We want to keep `prev_b_val` as small as possible.
        //   So, if `a[i] >= prev_b_val`, we check if `a[i] + x` wraps around `m` and becomes less than `prev_b_val`.
        //   This happens if `(a[i] + x) % m < prev_b_val` AND `a[i] + x >= m`.
        //   If this condition is true, it means we cannot use `a[i]` as `b_i` and increment it by some `k` (0 < k <= x)
        //   to stay above `prev_b_val`. The only way to stay above `prev_b_val` is to not increment `a[i]` at all,
        //   or increment it by `k` such that `a[i]+k` does not wrap around and `a[i]+k >= prev_b_val`.
        //   But if `(a[i]+x)%m < prev_b_val` and `a[i]+x >= m`, it means any increment `k` (0 < k <= x)
        //   will result in `(a[i]+k)%m` being less than `prev_b_val`.
        //   So, if `a[i] >= prev_b_val` and `(a[i] + x) % m < prev_b_val` (which implies `a[i] + x >= m`),
        //   then we must set `b_i = prev_b_val`. This is only possible if `prev_b_val` is reachable from `a[i]`.
        //   The cost to reach `prev_b_val` from `a[i]` is `(prev_b_val - a[i] + m) % m`.
        //   If this cost is `> x`, then it's impossible.
        //   Otherwise, we set `prev_b_val = prev_b_val`.
        //   If `a[i] >= prev_b_val` and `(a[i] + x) % m >= prev_b_val` (or `a[i] + x < m`),
        //   then we can set `b_i = a[i]`. So `prev_b_val` for next iteration becomes `a[i]`.

        // If `a[i] < prev_b_val`:
        //   We must increment `a[i]` to reach at least `prev_b_val`.
        //   The minimum increment needed is `prev_b_val - a[i]`.
        //   If `prev_b_val - a[i] <= x`, then we can achieve `prev_b_val`. So we set `b_i = prev_b_val`.
        //   `prev_b_val` for next iteration remains `prev_b_val`.
        //   If `prev_b_val - a[i] > x`, then we cannot reach `prev_b_val` without wrapping around.
        //   Even if we increment by `x`, `(a[i] + x) % m` will be less than `prev_b_val`.
        //   So it's impossible. Return `false`.

        // Simplified logic:
        // We want to find the smallest `b_i` such that `b_i >= prev_b_val` and `b_i` can be formed from `a[i]`
        // by adding `k` operations, where `0 <= k <= x`.

        // Case 1: `a[i]` is already greater than or equal to `prev_b_val`.
        //   We can potentially use `a[i]` as `b_i`. This requires 0 operations.
        //   The value `a[i]` is a valid candidate for `b_i`.
        //   We also need to consider if `a[i]` can be incremented by some `k <= x` such that `(a[i]+k)%m` is still `>= prev_b_val`.
        //   If `a[i] + x < m` (no wrap-around for max increment):
        //     Then `a[i] + k >= a[i] >= prev_b_val` for `0 <= k <= x`.
        //     So, `a[i]` is a valid choice for `b_i`. We update `prev_b_val = a[i]`.
        //   If `a[i] + x >= m` (wrap-around possible for max increment):
        //     This means `(a[i] + x) % m` could be small.
        //     If `(a[i] + x) % m < prev_b_val`:
        //       It means any increment `k` (0 < k <= x) will cause `(a[i]+k)%m` to be less than `prev_b_val`.
        //       So, we cannot use `a[i]` as `b_i` and increment it.
        //       We must use `prev_b_val` as `b_i`.
        //       But can we reach `prev_b_val` from `a[i]`?
        //       The cost to reach `prev_b_val` from `a[i]` is `(prev_b_val - a[i] + m) % m`.
        //       If this cost is `> x`, then it's impossible. Return `false`.
        //       Otherwise, `prev_b_val` remains `prev_b_val`.
        //     Else (`(a[i] + x) % m >= prev_b_val`):
        //       It means we can increment `a[i]` by `x` and still be `>= prev_b_val` (possibly after wrap-around).
        //       So, `a[i]` is a valid choice for `b_i`. We update `prev_b_val = a[i]`.

        // Case 2: `a[i] < prev_b_val`.
        //   We must increment `a[i]`.
        //   The minimum increment needed to reach `prev_b_val` is `prev_b_val - a[i]`.
        //   If `prev_b_val - a[i] <= x`:
        //     We can achieve `prev_b_val`. So `b_i = prev_b_val`.
        //     `prev_b_val` for next iteration remains `prev_b_val`.
        //   Else (`prev_b_val - a[i] > x`):
        //     We cannot reach `prev_b_val` without wrapping around.
        //     Even if we increment by `x`, `(a[i] + x) % m` will be less than `prev_b_val`.
        //     So it's impossible. Return `false`.

        // This can be simplified further:
        // If `a[i] >= prev_b_val`:
        //   We can potentially keep `a[i]` as `b_i`.
        //   The only time we *cannot* keep `a[i]` as `b_i` is if `a[i] + x` wraps around `m`
        //   AND `(a[i] + x) % m` is less than `prev_b_val`.
        //   In this specific scenario, we are forced to try to make `b_i = prev_b_val`.
        //   The cost to make `a[i]` into `prev_b_val` is `(prev_b_val - a[i] + m) % m`.
        //   If this cost is `> x`, then it's impossible.
        //   Otherwise, `prev_b_val` remains `prev_b_val`.
        //   If the above problematic scenario does NOT occur, then we can simply set `b_i = a[i]`.
        //   So `prev_b_val` becomes `a[i]`.

        // If `a[i] < prev_b_val`:
        //   We must increment `a[i]`.
        //   The cost to make `a[i]` into `prev_b_val` is `prev_b_val - a[i]`.
        //   If `prev_b_val - a[i] > x`, then it's impossible. Return `false`.
        //   Otherwise, `prev_b_val` remains `prev_b_val`.

        // Let's try this logic:
        if (current_a >= prev_b_val) {
            // Option 1: Keep current_a as b_i. This is valid if current_a + x doesn't wrap around
            // and become less than prev_b_val.
            // This means (current_a + x) % m >= prev_b_val OR current_a + x < m.
            // If (current_a + x) % m < prev_b_val AND current_a + x >= m:
            //   This is the problematic case. We cannot use current_a as b_i and increment it.
            //   We are forced to try to make b_i = prev_b_val.
            //   The cost to make current_a into prev_b_val is (prev_b_val - current_a + m) % m.
            //   If this cost > x, then it's impossible.
            //   Otherwise, prev_b_val remains prev_b_val.
            if ((current_a + x) % m < prev_b_val && current_a + x >= m) {
                // This means we must use prev_b_val.
                // The cost to reach prev_b_val from current_a is (prev_b_val - current_a + m) % m.
                // If this cost is > x, then it's impossible.
                // But wait, if current_a >= prev_b_val, then (prev_b_val - current_a + m) % m
                // is the cost to wrap around and reach prev_b_val.
                // Example: m=10, a[i]=8, prev_b_val=7. Cost is (7-8+10)%10 = 9.
                // If x=3, we can't do 9 operations. So impossible.
                // This is the correct check.
                long long cost_to_reach_prev = (prev_b_val - current_a + m) % m;
                if (cost_to_reach_prev > x) {
                    return false; // Cannot make b_i = prev_b_val
                }
                // If cost_to_reach_prev <= x, then we can make b_i = prev_b_val.
                // prev_b_val for next iteration remains prev_b_val.
            } else {
                // We can use current_a as b_i.
                // prev_b_val for next iteration becomes current_a.
                prev_b_val = current_a;
            }
        } else { // current_a < prev_b_val
            // We must increment current_a to reach at least prev_b_val.
            // The minimum increment needed is prev_b_val - current_a.
            if (prev_b_val - current_a > x) {
                return false; // Cannot reach prev_b_val
            }
            // If prev_b_val - current_a <= x, we can make b_i = prev_b_val.
            // prev_b_val for next iteration remains prev_b_val.
        }
    }
    return true;
}

