#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put a[0] into one subsequence (say, 1) and a[1] into the other (say, 2).
    // This ensures that a[0] and a[1] are in different subsequences,
    // making f(a[0], a[1]) = a[0].value + a[1].value + h.
    // This value is likely to be the minimum f value if h is large enough.
    // To minimize max_f - min_f, we want to make min_f as large as possible
    // and max_f as small as possible.
    //
    // Consider putting a[0] in subseq 1, and all other elements in subseq 2.
    // min_f:
    //   - a[0] + a[i] + h (for i > 0)
    //   - a[i] + a[j] (for i, j > 0)
    // The smallest of these is min(a[0].value + a[1].value + h, a[1].value + a[2].value).
    //
    // max_f:
    //   - a[0] + a[n-1] + h
    //   - a[n-1] + a[n-2]
    // The largest of these is max(a[0].value + a[n-1].value + h, a[n-1].value + a[n-2].value).
    //
    // Let's try a specific partition: a[0] in subseq 1, a[1]...a[n-1] in subseq 2.
    // min_f_val = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    // max_f_val = std::max(a[0].value + a[n-1].value + h, a[n-1].value + a[n-2].value);
    //
    // This specific partition is:
    // a[0] in subseq 1
    // a[1], ..., a[n-1] in subseq 2
    //
    // The minimum possible f value for this partition:
    // It's either (a[0] + a[1] + h) (a[0] and a[1] are in different subsequences)
    // OR (a[1] + a[2]) (a[1] and a[2] are in the same subsequence 2).
    // So, min_f_val = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    //
    // The maximum possible f value for this partition:
    // It's either (a[0] + a[n-1] + h) (a[0] and a[n-1] are in different subsequences)
    // OR (a[n-1] + a[n-2]) (a[n-1] and a[n-2] are in the same subsequence 2).
    // So, max_f_val = std::max(a[0].value + a[n-1].value + h, a[n-1].value + a[n-2].value);
    //
    // Goodness for this partition: max_f_val - min_f_val.
    //
    // Let's calculate this goodness.
    long long min_f_val_case2 = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    long long max_f_val_case2 = std::max(a[0].value + a[n - 1].value + h, a[n - 1].value + a[n - 2].value);
    long long goodness2 = max_f_val_case2 - min_f_val_case2;

    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
