// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: Try all possible single cuts
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // We can reassemble them as s[i...N-1] + s[0...i-1].
    // We need this new string to be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the cut point, 0 < i < N
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: If k=1 didn't work, check if k=2 is possible.
    // If all characters in s are the same (e.g., "aaaa"), then no matter how we cut and reassemble,
    // the resulting string will always be "aaaa". In this case, it's impossible to get s' != s.
    // We can check this by counting distinct characters. If only one distinct character, it's impossible.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // it must have at least two distinct characters.
    // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
    // Example: "abacaba" -> "aba|c|aba" -> "aba|c|aba" (no change)
    // But we can always make a cut that results in a different palindrome.
    // For any palindrome s of length N > 1, if not all characters are the same,
    // we can always find a way to make 2 cuts to form a new palindrome.
    // For example, take s[0] and s[N-1]. If s[0] != s[1], then s[0]s[1...N-2]s[N-1]
    // Cut s into s[0], s[1...N-2], s[N-1].
    // Reassemble as s[N-1], s[1...N-2], s[0]. This is a palindrome if s is.
    // This new string is s[N-1] + s.substr(1, N-2) + s[0].
    // Since s is a palindrome, s[N-1] == s[0]. So this new string is identical to s.
    // This specific strategy doesn't work.

    // However, if not all characters are the same, it means there exists at least one character s[i] such that s[i] != s[0].
    // Since s is a palindrome, s[i] == s[N-1-i].
    // Consider the first half of the string s[0...N/2 - 1].
    // If all characters in s[0...N/2 - 1] are the same, then s must be of the form "aaaa...aa" or "aaaa...aaa" (if N is odd).
    // But we already handled the "all_same_char" case.
    // So, there must be some `i` in `0 < i < N/2` such that `s[i] != s[0]`.
    // This implies that `s[i]` is different from `s[0]`, and `s[N-1-i]` is different from `s[N-1]`.
    //
    // Let's consider the string `s_half = s.substr(0, n/2)`.
    // If `s_half` is not a palindrome, then we can cut `s` into `s_half`, `s[n/2]` (if n is odd), and `reverse(s_half)`.
    // And then reassemble.
    //
    // A simpler argument for k=2:
    // If `s` is a palindrome and not all characters are the same, then there must be at least two distinct characters.
    // This means `s` is not of the form "aaaaa".
    // Consider the string `s_prefix = s.substr(0, n-1)`. This is `s` without its last character.
    // If `s_prefix` is not a palindrome, then we can cut `s` into `s_prefix` and `s[n-1]`.
    // Then `s[n-1] + s_prefix` is a candidate for `k=1`. We already checked this.
    //
    // The problem statement guarantees that if not all characters are the same, k=2 is always possible.
    // For example, "nolon". N=5. Not all same. k=1 fails. Output 2.
    // "kinnikkinnik". N=12. Not all same. k=1 works. Output 1.
    // "otto". N=4. Not all same. k=1 works. Output 1.
    //
    // The only case where it's impossible is when all characters are the same.
    // If `k=1` fails, and not all characters are the same, then `k=2` must be the answer.
    // This is because if `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // For example, `s = "abacaba"`. `n=7`.
    // `k=1` checks:
    // `i=1`: "bacaba" + "a" = "bacabaa" (not palindrome)
    // `i=2`: "acaba" + "ab" = "acabaab" (not palindrome)
    // `i=3`: "caba" + "aba" = "cabaaba" (not palindrome)
    // `i=4`: "aba" + "acab" = "abaacab" (not palindrome)
    // `i=5`: "ba" + "abaca" = "baabaca" (not palindrome)
    // `i=6`: "a" + "abacab" = "aabacab" (not palindrome)
    // So for "abacaba", k=1 fails.
    // Since not all characters are the same, the answer must be 2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Pointer for target tracks
    int h_idx = 0; // Pointer for heads

    while (p_idx < m) {
        if (h_idx >= n) {
            // No more heads available, but there are still target tracks to cover
            return false;
        }

        // Find the first head h[h_idx] that can reach p[p_idx]
        // A head h_k can reach p_j if h_k - T <= p_j <= h_k + T
        // We need h_k <= p_j + T and h_k >= p_j - T
        // So, we need to find h_k such that h_k >= p_j - T
        // And then check if h_k + T >= p_j

        // Skip heads that are too far to the left to reach p[p_idx]
        // i.e., h[h_idx] + T < p[p_idx]
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        if (h_idx >= n) {
            // No head can reach p[p_idx]
            return false;
        }

        // At this point, h[h_idx] is the first head (from left) that *might* be able to reach p[p_idx].
        // Specifically, h[h_idx] + T >= p[p_idx].
        // We also need to ensure h[h_idx] - T <= p[p_idx].
        // If h[h_idx] - T > p[p_idx], then this head is too far to the right for p[p_idx].
        // In this case, no subsequent head can reach p[p_idx] either, because heads are sorted.
        // So, p[p_idx] cannot be covered.
        if (h[h_idx] - T > p[p_idx]) {
            return false;
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // Now, use this head h[h_idx] to cover as many subsequent target tracks as possible.
        // The head h[h_idx] can cover tracks in the range [h[h_idx] - T, h[h_idx] + T].
        // We want to cover p[p_idx], p[p_idx+1], ..., p[k] such that p[k] <= h[h_idx] + T.
        long long current_head_max_reach = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= current_head_max_reach) {
            p_idx++;
        }

        // Move to the next head for the remaining target tracks
        h_idx++;
    }

    // All target tracks covered
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: distance between furthest p and furthest h, plus some buffer.
    // A safe upper bound is (p_m-1 - h_0) or (h_n-1 - p_0), which can be up to 10^10.
    // Or simply max(p_m-1, h_n-1) - min(p_0, h_0) which is roughly 10^10.
    // Each head can cover 2*T range.
    // A single head might need to travel from h_i to p_j, distance |h_i - p_j|.
    // So T can be up to 10^10.
    long long high = 20000000000LL; // A sufficiently large upper bound, e.g., 2 * 10^10

    long long ans = high; // Initialize with a value that will be overwritten

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
