int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any 3-AP pattern.
    // Initialize with n-1, meaning s[i...n-1] is initially considered valid.
    std::vector<int> max_r_for_l(n);
    std::iota(max_r_for_l.begin(), max_r_for_l.end(), n - 1);

    // Iterate through all possible starting positions x for a 3-AP pattern
    // and all possible k values.
    // The condition is s[x] == s[x+k] == s[x+2k].
    // The pattern spans from index x to x+2k.
    // If such a pattern is found, any substring s[l...r] where l <= x and r >= x+2k
    // will contain this pattern.
