int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem statement guarantees that a solution exists.
        // Reversing the permutation p always produces a different permutation p'
        // (unless n=1, but n >= 2) and maintains the same set of adjacent sums.
        // If p = [p_1, p_2, ..., p_n], its adjacent sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
        // If p' = [p_n, p_{n-1}, ..., p_1], its adjacent sums are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
        // These two sets of sums are identical, just in reverse order.
        // Sorting them will result in the same fingerprint.
        // Since n >= 2, p and reverse(p) are different unless n=1 (which is not allowed)
        // or p is a palindrome (e.g., [1,2,1] not a permutation, [1,2,3,2,1] not a permutation).
        // A permutation cannot be a palindrome unless n=1.
        // For n >= 2, p and reverse(p) are always different.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

