#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // up to 2048.
        // For example, if we have three 512s, we can use two of them to make a 1024.
        // The remaining 512 can also contribute.
        // The total sum of numbers less than or equal to 2048 is what matters.
        // If we have 512, 512, 512, 512, 512, the sum is 2560.
        // We can make two 1024s and one 512.
        // The total sum of values up to 2048 is what we can potentially combine.
        // If current_sum is 1000 and we add 512, it becomes 1512.
        // If we have 1000 and add 1024, it becomes 2024.
        // If we have 1000 and add 2048, it becomes 3048.
        // We only care if the sum reaches 2048.
        current_sum += (long long)val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

