    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n > 1, we can construct a number.
        // A simple construction is to use '2' as the first digit,
        // and '3' for all subsequent n-1 digits.
        // Example: n=2 -> 23
        //          n=3 -> 233
        //          n=4 -> 2333
        // Let's check this construction:
        // The number s will be 2 followed by n-1 threes.
        // All digits are non-zero (2 and 3).
        // We need to check divisibility by 2 and 3.
        //
        // Divisibility by 2:
        // The number ends in 3, which is odd. So, it's not divisible by 2.
        //
        // Divisibility by 3:
        // The sum of digits is 2 + (n-1)*3.
        // Sum of digits = 2 + 3n - 3 = 3n - 1.
        // For the number to be divisible by 3, its sum of digits must be divisible by 3.
        // 3n - 1 is never divisible by 3, because 3n is divisible by 3, so 3n-1 leaves a remainder of 2 when divided by 3.
        // Thus, the number is not divisible by 3.
        //
        // Since the number is not divisible by 2 (its first digit) and not divisible by 3 (its other digits),
        // this construction works for all n > 1.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

