#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[n - 1] != b[n - 1]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for a[i]
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a 1 to be available from an earlier index.
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a -1 to be available from an earlier index.
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }

        // Update availability of 1 and -1 for elements at indices < i
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

