        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is a new minimum for the suffix starting from i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_for_i = std::max(max_val_for_i, a[i][j]);
        }
        // If max_val_for_i is n-1, it means p[i] must be n.
        // Otherwise, p[i] must be max_val_for_i.
        // This is because if p[i] were greater than max_val_for_i,
        // then max_val_for_i would be p[k] for some k, and p[i] would be
        // greater than all other p[j] (j!=i), which means p[i] would be n.
        // If p[i] is n, then max_val_for_i would be n-1.
        // So, if max_val_for_i is not n-1, p[i] must be max_val_for_i.
        // If max_val_for_i is n-1, p[i] must be n.
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
