int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // For 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // Remaining students: c_rem = c - mid, m_rem = m - mid, x_rem = x.
            // Total remaining students: c_rem + m_rem + x_rem.
            // Each of the 'mid' teams needs one more member.
            // So, we need 'mid' additional members to fill the teams.
            // These additional members can come from c_rem, m_rem, or x_rem.
            if (c - mid >= 0 && m - mid >= 0 && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;

        // Precompute costs of nice staircases
        // A nice staircase with k stairs has cost (2^k - 1) * (2^k) / 2
        // This is equivalent to (2^k - 1) * 2^(k-1)
        // Let m = 2^k - 1. Then cost is m * (m+1)/2.
        // The sequence of m values is 1, 3, 7, 15, ...
        // The sequence of costs is 1, 6, 28, 120, ...

        // We can generate these costs iteratively.
        // Let current_m = 1.
        // Cost for current_m is current_m * (current_m + 1) / 2.
        // Next current_m is 2 * current_m + 1.

        long long current_m = 1; // Represents 2^k - 1 for k=1
        long long total_staircases = 0;

        while (true) {
            long long cost = current_m * (current_m + 1) / 2;

            if (cost <= x) {
                total_staircases++;
                x -= cost;

                // Calculate next_m = 2 * current_m + 1
                // Check for overflow before multiplication
                if (current_m > (2000000000000000000LL - 1) / 2) { // 2*current_m + 1 could overflow long long
                    break; // current_m is already too large, next_m will definitely overflow or cost will be too large
                }
                current_m = 2 * current_m + 1;
            } else {
                break;
            }
        }
        std::cout << total_staircases << "\n";
    }
    return 0;
}

#include <iostream>
