int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int current_gap = 0;
        // The frog starts at cell 0.
        // It needs to jump over the first 'R' block.
        // The first 'R' is at index 0 (s[0]).
        // The last 'R' is at index s.length()-1 (s[n-1]).
        // The target is cell n+1.
        // Consider the sequence of 'R's.
        // If s = "R R R", n=3. Cells 0,1,2,3,4.
        // Frog at 0. Can jump to 1,2,3,4.
        // If d=1, 0->1->2->3->4. Max gap is 1.
        // If s = "L L R", n=3. Cells 0,1,2,3,4.
        // Frog at 0.
        // s[0] = 'L', s[1] = 'L', s[2] = 'R'.
        // The 'R's are at indices where s[i] == 'R'.
        // These are the cells the frog *can* land on and jump right from.
        // The frog must be able to jump from 0 to the first 'R' cell,
        // then from one 'R' cell to the next 'R' cell,
        // and finally from the last 'R' cell to n+1.
        // The distance between 0 and the first 'R' cell (say at index i) is i+1.
        // The distance between an 'R' cell at index i and an 'R' cell at index j (j>i) is j-i.
        // The distance between the last 'R' cell (say at index k) and n+1 is (n+1)-(k+1) = n-k.
        // This is equivalent to finding the maximum distance between consecutive 'R's,
        // including the distance from 0 to the first 'R', and from the last 'R' to n+1.

        // Add a virtual 'R' at position -1 (representing cell 0)
        // and a virtual 'R' at position n (representing cell n+1).
        // Then find the maximum distance between any two consecutive 'R's.

        // The positions of 'R's are 1-indexed cell numbers.
        // Cell 0 is a starting point.
        // Cell n+1 is a target point.
        // Let's consider the indices of 'R' characters in the string s.
        // s[i] corresponds to cell i+1.
        // We need to find the maximum distance between:
        // 1. Cell 0 and the first cell j+1 where s[j] == 'R'. This distance is (j+1) - 0 = j+1.
        // 2. Cell i+1 and cell j+1 where s[i] == 'R', s[j] == 'R', and there are no 'R's between i and j. This distance is (j+1) - (i+1) = j-i.
        // 3. The last cell k+1 where s[k] == 'R' and cell n+1. This distance is (n+1) - (k+1) = n-k.

        // Let's track the last 'R' position (0-indexed string index).
        // Initialize last_r_idx to -1, representing cell 0.
        int last_r_idx = -1;
        int min_d = 0;

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // Current 'R' is at cell i+1.
                // Previous 'R' (or start) was at cell last_r_idx+1.
                // The distance needed to jump from last_r_idx+1 to i+1 is (i+1) - (last_r_idx+1) = i - last_r_idx.
                min_d = std::max(min_d, i - last_r_idx);
                last_r_idx = i;
            }
        }
        // After the loop, last_r_idx holds the index of the last 'R' character.
        // We need to jump from this last 'R' (cell last_r_idx+1) to cell n+1.
        // The distance is (n+1) - (last_r_idx+1) = n - last_r_idx.
        min_d = std::max(min_d, (int)s.length() - last_r_idx);

        std::cout << min_d << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces should have an area of (h/2) / n = h / (2n).
    //
    // Consider a smaller triangle formed by a cut at distance x from the apex.
    // This smaller triangle is similar to the original large triangle.
    // If its height is x, its base will be x/h (by similarity: base/height = 1/h).
    // The area of this smaller triangle is (1/2) * (x/h) * x = x^2 / (2h).
    //
    // For the i-th cut (from 1 to n-1), the area of the triangle from the apex
    // to this cut should be i times the area of one piece.
    // Area_i = i * (h / (2n))
    //
    // So, x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * (h / (2n)) * (2h)
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we'll use in the zig-zag part to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // For example, if k=4, range is [1, 5].
    // Output: 1 5 2 4 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.
    // This generates differences 4, 3, 2, 1.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these numbers in increasing order.
    // This will only introduce the difference '1' (e.g., |(k+1) - (k+2)| = 1, |(k+2) - (k+3)| = 1).
    // Since '1' is already one of the k distinct differences generated,
    // no new distinct differences will be added.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0 && open_needed < close_needed) {
            // Only add ')' if it can be matched by an already added '('
            // This condition (open_needed < close_needed) ensures that
            // the number of '(' added so far is greater than the number of ')' added so far.
            // Specifically, (k/2 - open_needed) is the count of '(' added.
            // (k/2 - close_needed) is the count of ')' added.
            // We need (k/2 - open_needed) > (k/2 - close_needed)
            // which simplifies to -open_needed > -close_needed, or open_needed < close_needed.
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the non-increasing suffix
    int j = i; // Start searching from `i`
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now, a[j...i-1] is non-increasing.
    // The segment a[j...n-1] is the longest suffix that can be made good.
    // The prefix to remove is of length `j`.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <algorithm>
