        // So, sort the array and output `a[n] - a[n-1]`.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m;

        std::vector<long long> cycle_sum_prefix(11); // cycle_sum_prefix[i] stores sum of first i last digits in a cycle
        // The cycle length is at most 10.
        // For example, if m=14, last digits are 4, 8, 2, 6, 0, 4, 8, 2, 6, 0, ...
        // The cycle is 4, 8, 2, 6, 0. Length 5.
        // cycle_sum_prefix[0] = 0
        // cycle_sum_prefix[1] = 4
        // cycle_sum_prefix[2] = 4+8 = 12
        // cycle_sum_prefix[3] = 12+2 = 14
        // cycle_sum_prefix[4] = 14+6 = 20
        // cycle_sum_prefix[5] = 20+0 = 20
        // cycle_sum_prefix[6] = 20+4 = 24 (this is for the 6th element, which is the 1st of the next cycle)
        // We only need up to 10 elements for the cycle.
        // The actual cycle length is determined by when (k*m)%10 repeats.
        // (k*m)%10 will repeat for k+10. So the cycle length is at most 10.
        // We can precompute the sum of last digits for the first 10 multiples of m.

        for (int i = 1; i <= 10; ++i) {
            cycle_sum_prefix[i] = cycle_sum_prefix[i-1] + (static_cast<long long>(i) * m) % 10;
        }

        long long full_cycles = count / 10;
        long long remaining_elements = count % 10;

        long long total_sum = full_cycles * cycle_sum_prefix[10];
        total_sum += cycle_sum_prefix[remaining_elements];

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, current_min_idx and current_max_idx are already set to pos[1].
        // The range is [pos[1], pos[1]], length 1. min is 1, max is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the range to include 'm'.
        // 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover
        // all numbers from 1 to m.
        // This means the new range must be [min(old_min_idx, pos[m]), max(old_max_idx, pos[m])].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current range [current_min_idx, current_max_idx]
        // satisfies the conditions for 'm' to be beautiful:
        // 1. The length of the subsegment is exactly 'm'.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The minimum value in the subsegment is 1. (Always true by construction)
        // 3. The maximum value in the subsegment is m. (Always true by construction)
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

