            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // Quadratic equation: a^2 - d*a + d = 0
        // Discriminant: delta = d^2 - 4d
        double delta = d * d - 4.0 * d;

        if (delta < 0.0) { // No real solutions
            std::cout << "N\n";
        } else {
            // Solutions for 'a': (d +/- sqrt(delta)) / 2
            double sqrt_delta = std::sqrt(delta);
            double a1 = (d + sqrt_delta) / 2.0;
            double b1 = d - a1; // b = d - a

            // Check if a and b are non-negative
            // Since d >= 0, and sqrt_delta >= 0, d + sqrt_delta >= 0, so a1 >= 0.
            // We need to check b1 = d - a1 = d - (d + sqrt_delta) / 2 = (2d - d - sqrt_delta) / 2 = (d - sqrt_delta) / 2
