void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_val: minimum possible value for a[i] if it's part of the increasing sequence starting from 0.
    // prefix_min_val[i] = i
    // We need a[i] >= i for the increasing part.
    // If a[i] < i, then it's impossible to make a[i] = i (or greater) by decreasing.
    // So, if a[i] < i, it's impossible to satisfy a_1 < a_2 < ... < a_i with a_1=0.
    // More generally, if a_1 = x, then a_i >= x + i - 1.
    // Since we can decrease a_1 to 0, the minimum possible value for a_i is i-1.
    // So, we need a[i] >= i-1 for the increasing part.
    // Let's check this condition for the left side.
    // For a_1 < a_2 < ... < a_k, we need a_i >= i-1 for i=1..k.
    // This is because we can set a_1' = 0, a_2' = 1, ..., a_i' = i-1.
    // If any a[i] < i-1, then it's impossible to make a[i]' >= i-1.
    // So, we need to find the first index `i` from the left where `a[i] < i`.
    // All elements `a[0]` to `a[i-1]` satisfy `a[j] >= j`.
    int left_limit = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Calculate suffix_min_val: minimum possible value for a[i] if it's part of the decreasing sequence ending at 0.
    // suffix_min_val[i] = n - 1 - i
    // For a_k > a_{k+1} > ... > a_n, we need a_i >= n-1-i for i=k..n.
    // This is because we can set a_n' = 0, a_{n-1}' = 1, ..., a_i' = n-1-i.
    // If any a[i] < n-1-i, then it's impossible to make a[i]' >= n-1-i.
    // So, we need to find the first index `i` from the right where `a[i] < n-1-i`.
    // All elements `a[i+1]` to `a[n-1]` satisfy `a[j] >= n-1-j`.
    int right_limit = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_limit = i;
            break;
        }
    }

    // If there is any k such that a_k can be the peak, then it must satisfy:
    // 1. a_k >= k (for the increasing part from left, assuming a_1'=0)
    // 2. a_k >= n-1-k (for the decreasing part to right, assuming a_n'=0)
    //
    // The `left_limit` is the first index `i` such that `a[i] < i`.
    // This means for all `j < left_limit`, `a[j] >= j`.
    // So, any `k` in `[0, left_limit - 1]` can potentially be the peak from the left side.
    //
    // The `right_limit` is the first index `i` such that `a[i] < n-1-i`.
    // This means for all `j > right_limit`, `a[j] >= n-1-j`.
    // So, any `k` in `[right_limit + 1, n - 1]` can potentially be the peak from the right side.
    //
    // We need to find if there exists *any* `k` such that `a[k] >= k` AND `a[k] >= n-1-k`.
    // This is equivalent to checking if there is any `k` in the range `[0, n-1]` such that
    // `k < left_limit` AND `k > right_limit`.
    //
    // In other words, we need to find if the interval `[0, left_limit - 1]` and `[right_limit + 1, n - 1]`
    // have a non-empty intersection.
    // The intersection is `[max(0, right_limit + 1), min(n - 1, left_limit - 1)]`.
    // We need `max(0, right_limit + 1) <= min(n - 1, left_limit - 1)`.
    // Since `0 <= k <= n-1`, this simplifies to `right_limit + 1 <= left_limit - 1`.
    // Or `right_limit < left_limit - 1`.
    // Or `right_limit + 1 < left_limit`.

    if (right_limit + 1 < left_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

