// Function to determine if a box can be the special box
void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    // If only one toy, that toy is the super toy.
    // Its box is the special box.
    if (total_toys == 1) {
        std::cout << (a > 0 ? "Ya" : "Tidak") << " "
                  << (b > 0 ? "Ya" : "Tidak") << " "
                  << (c > 0 ? "Ya" : "Tidak") << " "
                  << (d > 0 ? "Ya" : "Tidak") << std::endl;
        return;
    }

    // Initialize results for each box
    std::string res_box1 = "Tidak";
    std::string res_box2 = "Tidak";
    std::string res_box3 = "Tidak";
    std::string res_box4 = "Tidak";

    // --- Analyze sign possibilities ---
    // The final product's sign depends on the parity of negative numbers multiplied.
    // Initial number of negative toys: neg_initial = a + b
    // If neg_initial is even, final product can be positive.
    // If neg_initial is odd, final product can be negative.

    // --- Analyze magnitude possibilities ---
    // Let's consider the counts of toys with magnitude < 1 and >= 1.
    // mag_lt_1_initial = b + c
    // mag_ge_1_initial = a + d

    // Case 1: Final product is negative (can end up in Box 1 or Box 2)
    // This requires an odd number of negative factors in the final multiplication chain.
    // This is possible if (a + b) is odd.
    // If (a + b) is odd:
    if ((a + b) % 2 != 0) {
        // Can it be Box 1 (negative, magnitude >= 1)?
        // To get magnitude >= 1, we need at least one toy with magnitude >= 1
        // to "dominate" the product, or many small numbers multiplying to a large one.
        // If there's at least one toy with magnitude >= 1 (a > 0 or d > 0),
        // we can potentially achieve magnitude >= 1.
        // The only way to guarantee magnitude < 1 is if all initial toys have magnitude < 1.
        // If a + d > 0 (at least one toy with magnitude >= 1 initially),
        // it's possible to get a final product with magnitude >= 1.
        // Example: -2 * 0.5 = -1 (Box 1)
        // Example: -2 * 3 = -6 (Box 1)
        // Example: -0.5 * 3 = -1.5 (Box 1)
        // If a + d == 0, then all initial toys have magnitude < 1.
        // In this case, the final product will always have magnitude < 1.
        // So, if (a + b) is odd AND (a + d > 0), Box 1 is possible.
        if (a + d > 0) {
            res_box1 = "Ya";
        }
        // Can it be Box 2 (negative, magnitude < 1)?
        // This is always possible if the final product is negative.
        // We can always pick small numbers or arrange multiplications to keep magnitude < 1.
        // Example: -2 * 0.1 = -0.2 (Box 2)
        // Example: -0.5 * 0.5 = -0.25 (Box 2)
        // The only exception is if all initial toys have magnitude >= 1 (b+c == 0).
        // If b + c == 0, then all initial toys are from Box 1 or Box 4.
        // If (a+b) is odd, and b+c == 0, then b=0. So a is odd.
        // All toys are from Box 1 or Box 4. All have magnitude >= 1.
        // The product of numbers >= 1 is always >= 1.
        // So if b + c == 0, Box 2 is NOT possible.
        if (b + c > 0) { // If there's at least one toy with magnitude < 1
            res_box2 = "Ya";
        } else { // b + c == 0, all toys have magnitude >= 1
            // If a+b is odd, and b=0, then a is odd.
            // All toys are from Box 1 or Box 4. All have magnitude >= 1.
            // Product will have magnitude >= 1. So Box 2 is not possible.
            res_box2 = "Tidak";
        }
    }

    // Case 2: Final product is positive (can end up in Box 3 or Box 4)
    // This requires an even number of negative factors in the final multiplication chain.
    // This is possible if (a + b) is even.
    // If (a + b) is even:
    if ((a + b) % 2 == 0) {
        // Can it be Box 3 (positive, magnitude < 1)?
        // This is always possible if the final product is positive.
        // We can always pick small numbers or arrange multiplications to keep magnitude < 1.
        // Example: -2 * -0.1 = 0.2 (Box 3)
        // Example: 0.5 * 0.5 = 0.25 (Box 3)
        // The only exception is if all initial toys have magnitude >= 1 (b+c == 0).
        // If b + c == 0, then all initial toys are from Box 1 or Box 4.
        // All have magnitude >= 1. Product will have magnitude >= 1.
        // So if b + c == 0, Box 3 is NOT possible.
        if (b + c > 0) { // If there's at least one toy with magnitude < 1
            res_box3 = "Ya";
        } else { // b + c == 0, all toys have magnitude >= 1
            res_box3 = "Tidak";
        }

        // Can it be Box 4 (positive, magnitude >= 1)?
        // To get magnitude >= 1, we need at least one toy with magnitude >= 1.
        // If a + d > 0 (at least one toy with magnitude >= 1 initially),
        // it's possible to get a final product with magnitude >= 1.
        // Example: -2 * -3 = 6 (Box 4)
        // Example: 0.5 * 3 = 1.5 (Box 4)
        // If a + d == 0, then all initial toys have magnitude < 1.
        // In this case, the final product will always have magnitude < 1.
        // So, if (a + b) is even AND (a + d > 0), Box 4 is possible.
        if (a + d > 0) {
            res_box4 = "Ya";
        }
    }

    // Special case: If there are no toys with magnitude < 1 (b+c == 0),
    // then all toys have magnitude >= 1. The product of such toys will always be >= 1.
    // In this scenario, Box 2 and Box 3 are impossible.
    if (b + c == 0) {
        res_box2 = "Tidak";
        res_box3 = "Tidak";
    }

    // Special case: If there are no toys with magnitude >= 1 (a+d == 0),
    // then all toys have magnitude < 1. The product of such toys will always be < 1.
    // In this scenario, Box 1 and Box 4 are impossible.
    if (a + d == 0) {
        res_box1 = "Tidak";
        res_box4 = "Tidak";
    }

    std::cout << res_box1 << " " << res_box2 << " " << res_box3 << " " << res_box4 << std::endl;
}

