// Function to check if a subarray is a permutation
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem constraints say l1, l2 >= 1
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val < 1 || val > (i + 1) || seen_prefix[val]) {
            possible_prefix = false;
        }
        if (possible_prefix) {
            seen_prefix[val] = true;
            if (val > max_prefix) {
                max_prefix = val;
            }
            if (max_prefix == (i + 1)) {
                is_prefix_perm[i + 1] = true;
            }
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        int val = a[i];
        if (val < 1 || val > len || seen_suffix[val]) {
            possible_suffix = false;
        }
        if (possible_suffix) {
            seen_suffix[val] = true;
            if (val > max_suffix) {
                max_suffix = val;
            }
            if (max_suffix == len) {
                is_suffix_perm[len] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

