            most_frequent_bot_move = 'P';
        }

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor ^ b1 ^ b2 ^ b3)
    // Let S = current_sum, X = current_xor.
    // We need S' = 2 * X'.
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append at most 3 elements.
    // It's always possible to achieve the condition with at most 3 elements.
    // Let's try to append two elements.
    // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2).
    // A simple choice for b1 and b2 that often works is:
    // b1 = X
    // b2 = S + X
    // Let's check this:
    // New sum S' = S + X + (S + X) = 2S + 2X
    // New XOR X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X
    // Is S' = 2 * X'?
    // 2S + 2X = 2 * (S + X)
    // This is always true!
    // So, we can always append X and S+X.
    // The problem states that appended elements can be up to 10^18.
    // S can be up to 10^5 * 10^9 = 10^14.
    // X can be up to 2^30 - 1 (approx 10^9).
    // So S+X can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << current_sum + current_xor << std::endl;
}

