#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we see a 'b', it can potentially form an 'ab' pair with any 'a' to its left.
            // Each 'a' to its left will eventually "jump" over this 'b'.
            // When an 'a' jumps over a 'b', it consumes the 'b' and produces two 'b's.
            // So, effectively, this 'b' will be "doubled" for each 'a' that passes it.
            // The number of 'a's that will pass this 'b' is `count_a`.
            // So, this 'b' contributes `count_a` to the total steps.
            // After this 'b' is processed by all 'a's to its left, it effectively becomes `2^count_a` 'b's.
            // These new 'b's will then interact with 'a's further to the left.
            // This means the number of 'b's available for 'a's further left doubles.
            // So, `count_a` (which represents the number of 'b's available for the next 'a')
            // should be updated by adding `count_a` to itself, effectively doubling it.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we see an 'a', it will form 'ab' pairs with all 'b's to its right.
            // The number of 'b's to its right that it will interact with is `count_a`.
            // This 'a' will contribute `count_a` to the total steps.
            // After this 'a' has processed all 'b's to its right, it effectively moves past them.
            // It then becomes available to interact with 'b's further to its left.
            // So, we increment `count_a` to reflect that there is one more 'a' available
            // for 'b's that appear further to the left.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>
#include <utility> // For std::pair

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice (once for same x, once for same y)
    // but should only be counted once.
    // The condition is (x1=x2 AND y1=y2) OR (x1=x2 AND y1!=y2) OR (x1!=x2 AND y1=y2).
    // We counted (x1=x2) and (y1=y2).
    // If x1=x2 and y1=y2, it's counted in x_counts and y_counts.
    // If x1=x2 and y1!=y2, it's counted in x_counts only.
    // If x1!=x2 and y1=y2, it's counted in y_counts only.
    // So, points with identical coordinates (x,y) are counted twice.
    // We need to subtract the number of pairs of identical points.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining: N-1. Opponent gets to play on N-1.
                // If N-1 is odd, opponent takes 1.
                // If N-1 is even, opponent takes (N-1)/2 or 1.
                // This path is generally worse for Chanek if N/2 is available.

                // Option 2: Take N/2 coins
                // Remaining: N/2. Opponent gets to play on N/2.
                // This is usually the greedy choice for even N.

                // Special case: N is a power of 2.
                // If N is a power of 2 (e.g., 2, 4, 8, 16, ...), and it's Chanek's turn.
                // If Chanek takes N/2, opponent gets N/2.
                // If N/2 is also a power of 2, opponent will take (N/2)/2 = N/4.
                // This continues until 1 coin is left.
                // Example: N=8. Chanek takes 4. Opponent takes 2. Chanek takes 1. Opponent takes 1.
                // Chanek: 4+1=5. Opponent: 2+1=3.
                // If Chanek takes 1, N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                // In this case, taking N/2 is optimal.

                // What if N is even but not a power of 2?
                // N = 2 * K, where K is odd.
                // Example: N=6.
                // Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // If Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // In this case, taking N/2 is optimal.

                // The only time taking 1 might be better is if taking N/2 leaves the opponent in a very strong position
                // where they can take a lot, and Chanek gets very little later.
                // This happens if N/2 is a power of 2, and N is not.
                // Example: N=12.
                // Chanek takes 6. N=6. Opponent takes 3. N=3. Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 6+1+1=8. Opponent: 3+1=4.
                // If Chanek takes 1. N=11. Opponent takes 1. N=10. Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+5+2+1=9. Opponent: 1+1+1=3.
                // Here, taking 1 is better.

                // The strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2 (N = 2^k):
                //     Take N/2. This is optimal.
                //   If N is even but not a power of 2:
                //     Take N/2. This is optimal.
                // The only exception is when taking 1 coin makes the opponent face an odd number,
                // which forces them to take 1, and then Chanek gets to face an even number again.
                // This is exactly the case when N is even, and N/2 is odd.
                // If N/2 is odd, then N = 2 * (odd number).
                // Example: N=6. N/2=3 (odd).
                // Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Example: N=10. N/2=5 (odd).
                // Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 5+2+1=8. Opponent: 1+1=2.
                // In these cases, taking N/2 seems optimal.

                // Let's re-evaluate the N=12 case.
                // N=12. Chanek's turn.
                // Option A: Take 1. N becomes 11. Chanek gets 1.
                //   Opponent's turn, N=11. Opponent takes 1. N becomes 10. Opponent gets 1.
                //   Chanek's turn, N=10. Chanek takes 5. N becomes 5. Chanek gets 5.
                //   Opponent's turn, N=5. Opponent takes 1. N becomes 4. Opponent gets 1.
                //   Chanek's turn, N=4. Chanek takes 2. N becomes 2. Chanek gets 2.
                //   Opponent's turn, N=2. Opponent takes 1. N becomes 1. Opponent gets 1.
                //   Chanek's turn, N=1. Chanek takes 1. N becomes 0. Chanek gets 1.
                // Total Chanek: 1 + 5 + 2 + 1 = 9. Total Opponent: 1 + 1 + 1 = 3.

                // Option B: Take N/2 = 6. N becomes 6. Chanek gets 6.
                //   Opponent's turn, N=6. Opponent takes 3. N becomes 3. Opponent gets 3.
                //   Chanek's turn, N=3. Chanek takes 1. N becomes 2. Chanek gets 1.
                //   Opponent's turn, N=2. Opponent takes 1. N becomes 1. Opponent gets 1.
                //   Chanek's turn, N=1. Chanek takes 1. N becomes 0. Chanek gets 1.
                // Total Chanek: 6 + 1 + 1 = 8. Total Opponent: 3 + 1 = 4.

                // So for N=12, taking 1 is better (9 vs 8).
                // What's special about N=12? N=12 = 2^2 * 3. N/2 = 6 = 2 * 3.
                // N/2 is even, but not a power of 2.
                // The rule seems to be:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2 (N = 2^k for k >= 1): take N/2.
                //   If N is even but not a power of 2 (N = 2^k * M, where M > 1 and M is odd):
                //     Take 1. (This makes N-1 odd, forcing opponent to take 1, then Chanek faces N-2 which is even).
                //     This is because taking N/2 would leave N/2, which is also even, and opponent could take (N/2)/2.
                //     By taking 1, Chanek ensures the opponent faces an odd number, and then Chanek gets to play on an even number again.

                // Let's test this refined strategy.
                // N=5 (odd): Chanek takes 1. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+1=2. Opponent: 2+1=3. Correct for example.

                // N=6 (even, not power of 2, N=2*3):
                // Strategy says take 1. N=5.
                // Opponent takes 1. N=4.
                // Chanek takes 2. N=2.
                // Opponent takes 1. N=1.
                // Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2. Correct for example.

                // N=12 (even, not power of 2, N=2^2*3):
                // Strategy says take 1. N=11.
                // Opponent takes 1. N=10.
                // Chanek takes 5. N=5.
                // Opponent takes 1. N=4.
                // Chanek takes 2. N=2.
                // Opponent takes 1. N=1.
                // Chanek takes 1. N=0.
                // Chanek: 1+5+2+1=9. Opponent: 1+1+1=3. This matches our manual calculation.

                // N=8 (power of 2):
                // Strategy says take N/2 = 4. N=4.
                // Opponent takes 2. N=2.
                // Chanek takes 1. N=1.
                // Opponent takes 1. N=0.
                // Chanek: 4+1=5. Opponent: 2+1=3.

                // This strategy seems robust.
                // How to check if N is a power of 2? `(n > 0) && ((n & (n - 1)) == 0)`

                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                // Opponent applies the same logic to maximize their own coins.
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

