#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Cost for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Cost for items taken from the right
        // Sum of w[n-j]...w[n-1] is prefix_sum[n] - prefix_sum[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for imbalance
        if (i > j) { // More items from left than right
            int diff = i - j;
            // If all items are taken (i+j=n), and i > j, then diff = i - (n-i) = 2i - n.
            // If diff is 1, it means i = j+1. The last item taken was from the left.
            // If diff > 1, it means i > j+1. The last item taken was from the left, and there are (i-j-1) more left items than right items.
            // These (i-j-1) items must have been taken consecutively from the left after the right items ran out.
            // So, (i-j-1) extra Ql penalties.
            current_energy += (diff - 1) * Ql;
        } else if (j > i) { // More items from right than left
            int diff = j - i;
            // If all items are taken (i+j=n), and j > i, then diff = j - (n-j) = 2j - n.
            // If diff is 1, it means j = i+1. The last item taken was from the right.
            // If diff > 1, it means j > i+1. The last item taken was from the right, and there are (j-i-1) more right items than left items.
            // These (j-i-1) items must have been taken consecutively from the right after the left items ran out.
            // So, (j-i-1) extra Qr penalties.
            current_energy += (diff - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

