#include <map>

// Function to get prime factors of a number
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must not be divisible by q.
        // Let q = q1^a1 * q2^a2 * ... * qk^ak be the prime factorization of q.
        // For x to not be divisible by q, there must be some qi such that
        // the power of qi in x's factorization is less than ai.

        // Find prime factors of q
        std::map<long long, int> q_factors = get_prime_factors(q);

        long long max_x = 1;

        // Iterate through each prime factor qi of q
        for (auto const& [qi, ai] : q_factors) {
            // Calculate the largest power of qi that divides p
            long long current_p = p;
            long long p_qi_power = 0;
            while (current_p > 0 && current_p % qi == 0) {
                p_qi_power++;
                current_p /= qi;
            }

            // If p_qi_power < ai, it means p is not divisible by qi^ai,
            // which implies p is not divisible by q. But we already handled p % q != 0.
            // So, p_qi_power must be >= ai.

            // We need to reduce the power of qi in p such that the new number is not divisible by qi^ai.
            // The largest such divisor of p would be p / (qi^(p_qi_power - ai + 1)).
            // This ensures that the power of qi in the new number is (p_qi_power - (p_qi_power - ai + 1)) = ai - 1,
            // which is less than ai.
            long long current_x = p;
            for (int k = 0; k < p_qi_power - ai + 1; ++k) {
                current_x /= qi;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

