void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL;
    long long max_y = 2000000000LL;

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 0 means cannot move left, so target X must be >= current x
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // f2 = 0 means cannot move up, so target Y must be <= current y
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
        // f3 = 0 means cannot move right, so target X must be <= current x
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 0 means cannot move down, so target Y must be >= current y
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

