void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int pivot = 0; pivot <= 9; ++pivot) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit colored 1
        int last2 = -1; // Last digit colored 2
        bool possible_pivot = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_pivot = false;
                    break;
                }
                colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > pivot) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_pivot = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == pivot
                // Can be color 1 or 2. Prefer 2 if possible to keep 1s small.
                // If last2 is already greater than pivot, then this pivot must be color 1.
                // Otherwise, it can be color 2.
                if (d[i] < last2) { // d[i] == pivot, but last2 > pivot, so this is impossible.
                                    // This condition is actually d[i] < last2.
                                    // If d[i] == pivot, and last2 > pivot, then d[i] < last2 is true.
                                    // So if last2 > pivot, this must be color 1.
                    if (d[i] < last1) { // If it must be color 1, check if it's valid for color 1.
                        possible_pivot = false;
                        break;
                    }
                    colors[i] = 1;
                    last1 = d[i];
                } else { // d[i] == pivot, and last2 <= pivot. Can be color 2.
                    colors[i] = 2;
                    last2 = d[i];
                }
            }
        }

        if (possible_pivot) {
            // Final check: all digits colored 1 must be <= all digits colored 2.
            // This is implicitly handled by the pivot logic.
            // last1 is the maximum digit colored 1.
            // first2 is the minimum digit colored 2.
            // We need last1 <= first2.
            // The way we constructed it, all digits colored 1 are <= pivot.
            // All digits colored 2 are >= pivot.
            // So if last1 <= pivot and first2 >= pivot, then last1 <= first2.
            // The only edge case is if last1 is from a digit == pivot, and first2 is from a digit == pivot.
            // Example: 1 2 3 4 5 6 7 8 9. Pivot 5.
            // 1 2 3 4 (color 1) 5 (color 1) 6 7 8 9 (color 2)
            // last1 = 5, first2 = 6. OK.
            // Example: 1 2 3 4 5 6 7 8 9. Pivot 5.
            // 1 2 3 4 (color 1) 5 (color 2) 6 7 8 9 (color 2)
            // last1 = 4, first2 = 5. OK.

            // The logic for assigning 'pivot' digits:
            // If d[i] == pivot:
            //   If d[i] < last2 (which means last2 > pivot):
            //     Assign to color 1. Check d[i] >= last1.
            //   Else (last2 <= pivot):
            //     Assign to color 2. Check d[i] >= last2.
            // This ensures that if a pivot digit is assigned to color 1, it's because it *must* be color 1
            // (due to a previous color 2 digit being > pivot).
            // And if it's assigned to color 2, it's because it *can* be color 2.
            // This greedy choice for pivot digits ensures that last1 is minimized and first2 is maximized
            // among the pivot digits, which is good.

            // The condition `d[i] < last2` for `d[i] == pivot` means `pivot < last2`.
            // If this is true, `d[i]` must be color 1.
            // If `pivot < last1` (after assigning `d[i]` to color 1), then it's impossible.
            // Otherwise, `d[i]` is assigned color 2.
            // This logic is sound.

            for (int color : colors) {
                std::cout << color;
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

