// The logic for handling d[i] == pivot:
// If d[i] == pivot, we want to assign it to color 2 if possible, to keep color 1 sequence shorter/smaller.
// It can be assigned to color 2 if d[i] >= last2.
// If d[i] < last2, it means a previous digit colored 2 was smaller than d[i] (which is pivot).
// This is impossible if d[i] is assigned color 2.
// So if d[i] < last2, it *must* be assigned to color 1.
// Then we check if d[i] >= last1. If not, impossible.
// This is the correct greedy choice for pivot digits.
//
// Let's re-verify the logic for d[i] == pivot:
//
// Case 1: d[i] < pivot. Must be color 1. Check d[i] >= last1.
// Case 2: d[i] > pivot. Must be color 2. Check d[i] >= last2.
// Case 3: d[i] == pivot.
//   Subcase 3a: If d[i] < last2. This means `pivot < last2`.
//     Since `last2` is the last digit assigned to color 2, and `d[i]` is `pivot`,
//     if `pivot < last2`, then `d[i]` cannot be assigned to color 2 because it would violate the non-decreasing property of `S2`.
//     So, `d[i]` *must* be assigned to color 1.
//     Check if `d[i] >= last1`. If not, this pivot choice is impossible.
//     If yes, assign `colors[i] = 1`, update `last1 = d[i]`.
//   Subcase 3b: If d[i] >= last2. This means `pivot >= last2`.
//     In this case, `d[i]` *can* be assigned to color 2 without violating `S2`'s non-decreasing property.
//     We prefer assigning to color 2 to keep `S1` as small as possible.
//     Assign `colors[i] = 2`, update `last2 = d[i]`.
//
// This logic is what's implemented. It seems correct.
// The overall condition `last1 <= first2` is implicitly handled because:
// - All digits colored 1 are <= pivot (by definition of how we handle d[i] < pivot and d[i] == pivot).
// - All digits colored 2 are >= pivot (by definition of how we handle d[i] > pivot and d[i] == pivot).
// So, `max(S1) <= pivot <= min(S2)` is maintained.
// Thus, `max(S1) <= min(S2)` is always true if a solution is found for a given pivot.

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    for (char c : used_in_s) {
        if (visited_in_layout.count(c)) {
            continue;
        }

        if (adj[c].size() <= 1) { // Start of a path or isolated character
            char current = c;
            while (true) {
                if (visited_in_layout.count(current)) {
                    // This can happen if we find a cycle or a path that connects to an already processed path.
                    // For example, if s="abacaba", we process 'c', then 'a', then 'b'.
                    // When we start from 'c', we add 'c', then 'a', then 'b'.
                    // If we later iterate to 'a' or 'b', they are already visited.
                    // This is fine as long as the adjacencies are consistent.
                    // The check for adj.size() > 2 already handles inconsistencies.
                    break;
                }
                layout_str += current;
                visited_in_layout.insert(current);

                char next_char = '\0';
                for (char neighbor : adj[current]) {
                    if (!visited_in_layout.count(neighbor)) {
                        next_char = neighbor;
                        break;
                    }
                }

                if (next_char == '\0') { // End of path
                    break;
                }
                current = next_char;
            }
        }
    }

    if (layout_str.length() != used_in_s.size()) {
        // This means there's a cycle in the graph of required adjacencies.
        // For example, if s="abac", a-b, b-a, a-c, c-a.
        // This forms a cycle a-b-a-c-a.
        // The path construction logic above would start from 'b' (adj size 1), add 'b', then 'a', then 'c'.
        // Then 'c' has 'a' as only unvisited neighbor, but 'a' is visited. So it stops.
        // The length would be 3 (b,a,c). But used_in_s has 3 chars.
        // This check is actually not strictly needed if adj.size() > 2 is sufficient.
        // Let's re-evaluate. If adj.size() <= 2 for all, it means it's a collection of paths and cycles.
        // If it's a cycle, say a-b-c-a, then all a,b,c have 2 neighbors.
        // Our algorithm starts from a node with <=1 neighbor. If all nodes have 2 neighbors, it won't start.
        // So, if layout_str.length() != used_in_s.size() AND all adj.size() <= 2, it implies there's a cycle.
        // A cycle cannot be represented on a linear keyboard.
        // Example: s="abac", adj: a:{b,c}, b:{a}, c:{a}.
        // Here, 'a' has 2 neighbors, 'b' has 1, 'c' has 1.
        // Start from 'b': layout="ba". visited={b,a}.
        // Next, 'c': layout="bac". visited={b,a,c}.
        // layout_str.length() == used_in_s.size() (3 == 3). This is fine.
        // Example: s="abcda", adj: a:{b,d}, b:{a,c}, c:{b,d}, d:{a,c}. All have 2 neighbors.
        // Our loop for (char c : used_in_s) will iterate.
        // If it picks 'a', adj[a].size() is 2, so it skips.
        // It will skip all characters. layout_str will be empty.
        // used_in_s.size() will be 4. 0 != 4, so it prints NO. This is correct.
        // So, this check correctly identifies cycles.
        std::cout << "NO\n";
        return;
    }

    std::set<char> all_chars_set;
    for (char c = 'a'; c <= 'z'; ++c) {
        all_chars_set.insert(c);
    }

    for (char c : layout_str) {
        all_chars_set.erase(c);
    }

    for (char c : all_chars_set) {
        layout_str += c;
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

