        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val.
    // If b=1, then b-1=0, sum_r_val = 0.
    // If b=2, then b-1=1, sum_r_val = 1.
    long long sum_r_val = (b - 1);
    if (sum_r_val < 0) sum_r_val = 0; // Handle b=1 case where b-1 is 0
    sum_r_val = (sum_r_val % MOD * (b % MOD)) % MOD;

    // We need to divide by 2. Since MOD is prime, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9+7 is (10^9+7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Sum of (k * b + 1) from k=1 to a
    // This is sum_k_term.
    // sum_{k=1 to a} (k * b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a

    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD; // a * (a+1) / 2

    long long sum_k_term = (b % MOD * sum_k_val) % MOD;
    sum_k_term = (sum_k_term + (a % MOD)) % MOD;

    // Total sum = sum_r_val * sum_k_term
    long long total_sum = (sum_r_val * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
