#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; ++i) {
        int block_start_idx = i;
        int block_end_idx = std::min(n - 1, i + k - 1);

        int block_size = block_end_idx - block_start_idx + 1;

        for (int j = 0; j < block_size; ++j) {
            p[block_start_idx + j] = current_val - block_size + 1 + j;
        }
        current_val -= block_size;
        i = block_end_idx;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

