int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for consistent logic
        if (n > m) {
            std::swap(n, m);
        }

        // Case 1: k < m (or k < n, since n <= m)
        // It's impossible to reach (n,m) in k moves if k is less than the maximum coordinate.
        // This is because each move can change a coordinate by at most 1.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= m
        // We can always reach (n,m) in m moves by making m diagonal moves to (n,m) if n=m,
        // or m moves to (n,m) if n < m (m diagonal moves to (n,n) then m-n non-diagonal moves to (n,m)).
        // The remaining k-m moves must be used to return to (n,m).
        // Each pair of moves (e.g., (x,y) -> (x+1,y) -> (x,y)) uses 2 moves and changes the parity of the total moves.
        // Or (x,y) -> (x+1,y+1) -> (x,y) uses 2 moves and changes the parity of the total moves.

        // The minimum number of moves to reach (n,m) is m (if n <= m).
        // Let's consider the parity of k and m.
        // If k and m have the same parity, we can use (k-m)/2 pairs of moves like (x,y) -> (x+1,y) -> (x,y).
        // Each such pair uses 2 moves and doesn't change the final position.
        // The number of diagonal moves would be m (to reach (n,m) in m moves) + 2 * (number of diagonal pairs).
        // However, we want to maximize diagonal moves.
        // If we have k-m extra moves, and k-m is even, we can use (k-m)/2 pairs of moves like (x,y) -> (x+1,y+1) -> (x,y).
        // This adds 2 diagonal moves for each pair.
        // So, if k and m have the same parity, we can make m diagonal moves to reach (n,n), then m-n non-diagonal moves to reach (n,m).
        // This uses m moves. The remaining k-m moves are even.
        // We can use (k-m)/2 pairs of diagonal moves like (x,y) -> (x+1,y+1) -> (x,y).
        // This adds 2 diagonal moves for each pair.
        // Total diagonal moves: n (to reach (n,n)) + 2 * (k-m)/2 = n + k - m.
        // This is incorrect. The maximum number of diagonal moves is limited by k.
        // The maximum number of diagonal moves is k.
        // The minimum number of non-diagonal moves is m-n.
        // So, the maximum number of diagonal moves is k - (m-n).
        // This is the number of diagonal moves if we make exactly m-n non-diagonal moves and the rest are diagonal.
        // This is possible if k - (m-n) >= 0.
        // And the parity must match.
        // The parity of (n+m) must be the same as the parity of k.
        // Each diagonal move changes (x+y) by 2, 0, or -2 (always even).
        // Each non-diagonal move changes (x+y) by 1 or -1 (always odd).
        // So, the parity of (n+m) must be the same as the parity of the number of non-diagonal moves.
        // Let D be diagonal moves, N be non-diagonal moves.
        // D + N = k.
        // The final position (n,m) has sum n+m.
        // The parity of n+m must be the same as the parity of N.
        // So, (n+m) % 2 == N % 2.
        // Since N = k - D, (n+m) % 2 == (k - D) % 2.
        // We want to maximize D.
        // The maximum possible D is k.
        // If D = k, then N = 0. (n+m) % 2 == 0 % 2. So n+m must be even.
        // If n+m is even, and k >= m, we can reach (n,m) in k moves.
        // The maximum diagonal moves would be k.
        // Example: (2,2,3). n=2, m=2, k=3. n+m=4 (even). k=3 (odd).
        // k-m = 3-2 = 1.
        // If n and m have the same parity (n%2 == m%2), then n+m is even.
        // If n and m have different parities (n%2 != m%2), then n+m is odd.

        // If n and m have the same parity (n%2 == m%2):
        // This means n+m is even.
        // We need an even number of non-diagonal moves.
        // If k is even, we can make k diagonal moves. (n+m is even, N=0 is even).
        // If k is odd, we must make at least one non-diagonal move.
        // We can make k-1 diagonal moves and 1 non-diagonal move.
        // But we need to reach (n,m).
        // The minimum number of non-diagonal moves is m-n.
        // If n and m have the same parity, then m-n is even.
        // So, we need an even number of non-diagonal moves.
        // If k - (m-n) is even, then we can make k - (m-n) diagonal moves and m-n non-diagonal moves.
        // This is the maximum possible diagonal moves.
        // If k - (m-n) is odd, we must reduce diagonal moves by 1 and increase non-diagonal moves by 1.
        // This means we use (k - (m-n) - 1) diagonal moves and (m-n+1) non-diagonal moves.
        // This is not quite right.
        // The number of non-diagonal moves must have the same parity as (n+m).
        // If n and m have the same parity, then n+m is even. So N must be even.
        // If k is even, we can set N=0, D=k. This is possible if k >= m.
        // If k is odd, we must set N >= 1 and N must be odd. The smallest odd N is 1.
        // So, if k is odd, we can set N=1, D=k-1. This is possible if k-1 >= m-1 (i.e., k >= m).
        // So, if n%2 == m%2:
        //   If k%2 == 0: max_diag = k.
        //   If k%2 == 1: max_diag = k-2. (We need to use 2 non-diagonal moves to change parity, e.g., (x,y)->(x+1,y)->(x,y-1) is not good.
        //                                 (x,y)->(x+1,y)->(x+1,y-1) is not good.
        //                                 (x,y)->(x+1,y)->(x,y) uses 2 moves, 0 diagonal.
        //                                 (x,y)->(x+1,y)->(x+2,y) uses 2 moves, 0 diagonal.
        //                                 (x,y)->(x+1,y)->(x+1,y+1) uses 1 diagonal.
        //                                 The point is that if k is odd and n+m is even, we need an odd number of non-diagonal moves.
        //                                 The minimum non-diagonal moves is m-n. If m-n is even, we need to add an odd number of non-diagonal moves.
        //                                 The smallest odd number is 1. So we need m-n+1 non-diagonal moves.
        //                                 This means k - (m-n+1) diagonal moves.
        //                                 This is k - m + n - 1.
        //                                 This is equivalent to k-2 if n=m.
        //                                 Let's re-evaluate.
        //                                 If n%2 == m%2, then n+m is even. We need an even number of non-diagonal moves.
        //                                 The minimum non-diagonal moves is m-n. Since n%2 == m%2, m-n is even.
        //                                 So, we can use m-n non-diagonal moves and k-(m-n) diagonal moves.
        //                                 This is possible if k-(m-n) >= 0.
        //                                 The number of diagonal moves is k-(m-n).
        //                                 If k-(m-n) is even, this is the answer.
        //                                 If k-(m-n) is odd, we need to adjust.
        //                                 We need to make the number of diagonal moves even.
        //                                 This means we must use 2 more non-diagonal moves.
        //                                 So, k-(m-n)-2 diagonal moves.
        //                                 This is equivalent to:
        //                                 If (k - (m-n)) % 2 == 0: ans = k - (m-n)
        //                                 If (k - (m-n)) % 2 == 1: ans = k - (m-n) - 2
        //                                 This can be simplified to:
        //                                 ans = k - (m-n) - ((k - (m-n)) % 2) * 2
        //                                 No, this is not right.
        //                                 If n%2 == m%2:
        //                                   If k%2 == 0: ans = k. (We can make k diagonal moves if n=m. If n<m, we make n diagonal moves to (n,n), then m-n non-diagonal moves to (n,m). Total m moves. Remaining k-m moves are even. We can use them as (x,y)->(x+1,y+1)->(x,y) pairs, adding 2 diagonal moves for each pair. So n + (k-m) diagonal moves. This is k - (m-n). This is correct.
        //                                   If k%2 == 1: ans = k-2. (We need to use an odd number of non-diagonal moves. But n+m is even, so we need an even number of non-diagonal moves. This means we must use at least 2 non-diagonal moves to change the parity of k.
        //                                   Example: (2,2,3). n=2, m=2, k=3. n%2==m%2. k%2==1. Ans should be k-2 = 1. Correct.
        //                                   Example: (4,3,7). n=3, m=4, k=7. n%2!=m%2. k%2==1. Ans should be k-1 = 6. Correct.
        //                                   Example: (10,1,9). n=1, m=10, k=9. n%2!=m%2. k%2==1. Ans should be k-1 = 8. But example says -1.
        //                                   Ah, the condition k >= m is crucial.
        //                                   For (10,1,9), n=1, m=10, k=9. k < m, so -1. This is handled by the first if.

        // Let's re-evaluate the parity logic.
        // The number of non-diagonal moves (N) must have the same parity as (n+m).
        // N = k - D.
        // So, (k - D) % 2 == (n + m) % 2.
        // We want to maximize D.
        // The maximum possible D is k.
        // If D = k, then N = 0. This requires (n+m) % 2 == 0.
        // If (n+m) % 2 == 0:
        //   If k % 2 == 0: We can set D=k, N=0. This is valid. Max diagonal moves = k.
        //   If k % 2 == 1: We cannot set D=k, N=0 because (k-D)%2 = 1%2 = 1, but (n+m)%2 = 0.
        //                  We need (k-D)%2 = 0. So D must be odd.
        //                  The largest odd D is k-1. If D=k-1, N=1. (k-D)%2 = 1%2 = 1. Still not matching.
        //                  We need (k-D) to be even. Since k is odd, D must be odd.
        //                  The largest odd D is k-1. If D=k-1, N=1. (k-D)%2 = 1.
        //                  This means we need to make N even.
        //                  If k is odd and n+m is even, we need N to be even.
        //                  The smallest even N is 0. But if N=0, k=D, and k is odd, (k-D)%2 = 0.
        //                  This means k must be even. Contradiction.
        //                  So, if k is odd and n+m is even, we cannot have N=0.
        //                  We need N to be even. The smallest non-zero even N is 2.
        //                  If N=2, then D=k-2. This is valid. Max diagonal moves = k-2.
        // If (n+m) % 2 == 1:
        //   If k % 2 == 0: We need N to be odd. The smallest odd N is 1.
        //                  If N=1, then D=k-1. This is valid. Max diagonal moves = k-1.
        //   If k % 2 == 1: We need N to be odd. The smallest odd N is 1.
        //                  If N=1, then D=k-1. This is valid. Max diagonal moves = k-1.

        // Combining these:
        // If (n+m) % 2 == 0: // n and m have same parity
        //   If k % 2 == 0: ans = k
        //   If k % 2 == 1: ans = k - 2
        // If (n+m) % 2 == 1: // n and m have different parity
        //   ans = k - 1

        // This logic seems sound for maximizing diagonal moves while satisfying parity constraints.
        // The minimum number of moves to reach (n,m) is m (assuming n <= m).
        // We have already checked k < m.
        // So we know k >= m.
        // The number of diagonal moves is at most k.
        // The number of non-diagonal moves is at least m-n.
        // So, the number of diagonal moves is at most k - (m-n).
        // Let's check this against the parity logic.

        long long ans;
        if ((n % 2) == (m % 2)) { // n and m have same parity, so n+m is even
            if ((k % 2) == 0) { // k is even
                ans = k;
            } else { // k is odd
                ans = k - 2;
            }
        } else { // n and m have different parity, so n+m is odd
            ans = k - 1;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    // Now we have the final state for 0, 1, and the XOR mask.
    // Let's call the final state for input 0 as `f(0)` and for input 1023 as `f(1023)`.
    // f(0) = (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // f(0) = current_or_mask ^ current_xor_mask
    // f(1023) = (1023 & current_and_mask) | current_or_mask ^ current_xor_mask

    // We need to find A, B, C such that for any x:
    // (x & A) | B ^ C = original_result(x)
    //
    // Let's analyze bit by bit. For each bit j:
    // Let x_j be the j-th bit of x.
    // Let A_j, B_j, C_j be the j-th bits of A, B, C.
    // The j-th bit of the result is (x_j & A_j) | B_j ^ C_j.
    //
    // We know the final state of bit j if input bit is 0 (val0_j) and if input bit is 1 (val1_j).
    // val0_j = (0 & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j
    // val1_j = (1 & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j
    //
    // Let's compute val0 and val1 for each bit.
    int final_val0 = current_or_mask ^ current_xor_mask;
    int final_val1023 = (1023 & current_and_mask) | current_or_mask ^ current_xor_mask;

    int A_final = 0;
    int B_final = 0;
    int C_final = 0;

    for (int j = 0; j < 10; ++j) {
        int val0_j = (final_val0 >> j) & 1;
        int val1_j = (final_val1023 >> j) & 1;

        // We need to find A_j, B_j, C_j such that:
        // (0 & A_j) | B_j ^ C_j = val0_j  => B_j ^ C_j = val0_j
        // (1 & A_j) | B_j ^ C_j = val1_j  => A_j | B_j ^ C_j = val1_j
        //
        // Substituting B_j ^ C_j = val0_j into the second equation:
        // A_j | val0_j = val1_j
        //
        // Case 1: val0_j = 0
        //   B_j ^ C_j = 0  => B_j = C_j
        //   A_j | 0 = val1_j => A_j = val1_j
        //   If A_j = 0 (i.e., val1_j = 0):
        //     Then (x_j & 0) | B_j ^ C_j = 0. Since B_j = C_j, B_j ^ C_j = 0. So this works.
        //     We can pick A_j=0, B_j=0, C_j=0.
        //   If A_j = 1 (i.e., val1_j = 1):
        //     Then (x_j & 1) | B_j ^ C_j = x_j. Since B_j = C_j, B_j ^ C_j = 0. So this works.
        //     We can pick A_j=1, B_j=0, C_j=0.
        //
        // Case 2: val0_j = 1
        //   B_j ^ C_j = 1  => B_j != C_j
        //   A_j | 1 = val1_j => val1_j must be 1. (If val1_j is 0, it's impossible).
        //   If val1_j = 0, this means (0->1, 1->0). This is equivalent to XOR 1.
        //     A_j | 1 = 0 is impossible.
        //     This means our assumption of (x & A) | B ^ C form is not general enough.
        //     Let's re-evaluate.
        //
        // The operations are:
        // 1. AND with A
        // 2. OR with B
        // 3. XOR with C
        //
        // For each bit j:
        // Input bit x_j
        // Result bit: ((x_j & A_j) | B_j) ^ C_j
        //
        // We know:
        // For x_j = 0: ((0 & A_j) | B_j) ^ C_j = (0 | B_j) ^ C_j = B_j ^ C_j = val0_j
        // For x_j = 1: ((1 & A_j) | B_j) ^ C_j = (A_j | B_j) ^ C_j = val1_j
        //
        // From B_j ^ C_j = val0_j, we have C_j = B_j ^ val0_j.
        // Substitute C_j into the second equation:
        // (A_j | B_j) ^ (B_j ^ val0_j) = val1_j
        //
        // Let's iterate through possible values for A_j and B_j (0 or 1) and find C_j.
        //
        // If (val0_j, val1_j) is:
        // (0, 0):
        //   B_j ^ C_j = 0 => B_j = C_j
        //   (A_j | B_j) ^ C_j = 0
        //   (A_j | B_j) ^ B_j = 0
        //   This means A_j | B_j = B_j. This is true if A_j = 0.
        //   So, A_j=0, B_j=0, C_j=0 works. (x_j & 0) | 0 ^ 0 = 0.
        // (0, 1):
        //   B_j ^ C_j = 0 => B_j = C_j
        //   (A_j | B_j) ^ C_j = 1
        //   (A_j | B_j) ^ B_j = 1
        //   This means A_j | B_j != B_j. This is true if A_j = 1 and B_j = 0.
        //   So, A_j=1, B_j=0, C_j=0 works. (x_j & 1) | 0 ^ 0 = x_j.
        // (1, 0):
        //   B_j ^ C_j = 1 => B_j != C_j
        //   (A_j | B_j) ^ C_j = 0
        //   (A_j | B_j) ^ (B_j ^ 1) = 0
        //   This means A_j | B_j = B_j ^ 1.
        //   If B_j = 0: A_j | 0 = 1 => A_j = 1.
        //     So, A_j=1, B_j=0, C_j=1 works. ((x_j & 1) | 0) ^ 1 = x_j ^ 1.
        //   If B_j = 1: A_j | 1 = 0 (impossible).
        //   So, A_j=1, B_j=0, C_j=1 is the only solution for this case.
        // (1, 1):
        //   B_j ^ C_j = 1 => B_j != C_j
        //   (A_j | B_j) ^ C_j = 1
        //   (A_j | B_j) ^ (B_j ^ 1) = 1
        //   This means A_j | B_j != B_j ^ 1.
        //   If B_j = 0: A_j | 0 != 1 => A_j != 1. So A_j = 0.
        //     So, A_j=0, B_j=0, C_j=1 works. ((x_j & 0) | 0) ^ 1 = 0 ^ 1 = 1.
        //   If B_j = 1: A_j | 1 != 0 => 1 != 0. This is always true.
        //     So, A_j=0, B_j=1, C_j=0 works. ((x_j & 0) | 1) ^ 0 = 1 ^ 0 = 1.
        //     Also, A_j=1, B_j=1, C_j=0 works. ((x_j & 1) | 1) ^ 0 = 1 ^ 0 = 1.
        //     We can pick A_j=0, B_j=1, C_j=0.
        //
        // Summary of chosen (A_j, B_j, C_j) for (val0_j, val1_j):
        // (0, 0): (0, 0, 0)  => result is 0
        // (0, 1): (1, 0, 0)  => result is x_j
        // (1, 0): (1, 0, 1)  => result is x_j ^ 1
        // (1, 1): (0, 1, 0)  => result is 1

        if (val0_j == 0 && val1_j == 0) {
            // A_j=0, B_j=0, C_j=0
            // No change to A_final, B_final, C_final for this bit
        } else if (val0_j == 0 && val1_j == 1) {
            // A_j=1, B_j=0, C_j=0
            A_final |= (1 << j);
        } else if (val0_j == 1 && val1_j == 0) {
            // A_j=1, B_j=0, C_j=1
            A_final |= (1 << j);
            C_final |= (1 << j);
        } else { // val0_j == 1 && val1_j == 1
            // A_j=0, B_j=1, C_j=0
            B_final |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_final != 1023) { // If A_final is 1023, then x & 1023 is just x. No need for & 1023.
        result_ops.push_back({'&', A_final});
    }
    if (B_final != 0) {
        result_ops.push_back({'|', B_final});
    }
    if (C_final != 0) {
        result_ops.push_back({'^', C_final});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s among jars 1..k) - (count of 2s among jars 1..k)
    // We are interested in the suffix of the left side, so we'll use negative indices for map.
    // Or, more simply, we can calculate the difference for the *remaining* left part.
    // Let's define diff_L[k] as the difference for jars 1 to k.
    // When we remove k jars from the left, the remaining jars are from k+1 to n.
    // The difference for these remaining jars is (total diff for 1..n) - (diff for 1..k).
    // This is not quite right.
    // Let's define `pref_diff[i]` as the difference (1s - 2s) for jars `0` to `i-1`.
    // `pref_diff[0] = 0`.
    // `pref_diff[i] = pref_diff[i-1] + (a[i-1] == 1 ? 1 : -1)`.

    // Calculate prefix sums for the entire 2n jars
    std::vector<int> pref_diff(2 * n + 1, 0);
    for (int i = 0; i < 2 * n; ++i) {
        pref_diff[i + 1] = pref_diff[i] + (a[i] == 1 ? 1 : -1);
    }

    // The initial difference for all 2n jars is pref_diff[2n].
    // We want the remaining jars to have a difference of 0.
    // If we remove L jars from the left and R jars from the right,
    // the remaining jars are from index L to 2n-1-R.
    // The difference for these remaining jars is pref_diff[2n-R] - pref_diff[L].
    // We want pref_diff[2n-R] - pref_diff[L] = 0, or pref_diff[2n-R] = pref_diff[L].

    // We need to find the minimum L+R.
    // L can range from 0 to n. R can range from 0 to n.
    // The jars Karlsson sees are 1..n (left) and n+1..2n (right).
    // He can eat from the left (jars 1, 2, ..., n) or from the right (jars 2n, 2n-1, ..., n+1).
    // If he eats `k` jars from the left, he eats jars `1` through `k`.
    // If he eats `k` jars from the right, he eats jars `2n` through `2n-k+1`.

    // Let's consider the state after eating some jars.
    // Suppose he eats `k_L` jars from the left (jars 0 to k_L-1)
    // and `k_R` jars from the right (jars 2n-k_R to 2n-1).
    // The remaining jars are from index `k_L` to `2n-1-k_R`.
    // The difference for these remaining jars is `pref_diff[2n-k_R] - pref_diff[k_L]`.
    // We want this to be 0. So `pref_diff[2n-k_R] = pref_diff[k_L]`.
    // The total jars eaten is `k_L + k_R`. We want to minimize this.

    // We can precompute the differences for all possible left prefixes and right suffixes.
    // `diff_left[k]` = difference for jars `0` to `k-1`. (This is `pref_diff[k]`)
    // `diff_right[k]` = difference for jars `2n-k` to `2n-1`.
    // `diff_right[k]` can be calculated as `pref_diff[2n] - pref_diff[2n-k]`.

    // Let's store the minimum `k_L` for each `pref_diff[k_L]` value.
    // `map_left[diff_val] = min_k_L`
    std::map<int, int> map_left;
    map_left[0] = 0; // 0 jars eaten from left, diff is 0.
    for (int k_L = 1; k_L <= n; ++k_L) {
        int current_diff = pref_diff[k_L];
        if (map_left.find(current_diff) == map_left.end()) {
            map_left[current_diff] = k_L;
        }
    }

    int min_eaten = 2 * n; // Max possible jars to eat

    // Iterate through possible `k_R` values (jars eaten from the right)
    // `k_R` can range from 0 to n.
    // For each `k_R`, we calculate the difference of the right suffix `2n-k_R` to `2n-1`.
    // Let `target_diff_L = pref_diff[2n-k_R]`.
    // We need to find if `target_diff_L` exists in `map_left`.
    // If it does, we can form a segment with difference 0.
    // The number of jars eaten would be `k_R + map_left[target_diff_L]`.

    // Case 1: No jars eaten from the right (k_R = 0).
    // The remaining jars are from `k_L` to `2n-1`.
    // The difference is `pref_diff[2n] - pref_diff[k_L]`.
    // We want this to be 0, so `pref_diff[k_L] = pref_diff[2n]`.
    // If `pref_diff[2n]` is in `map_left`, then `k_L = map_left[pref_diff[2n]]`.
    // Jars eaten = `k_L + 0`.
    if (map_left.count(pref_diff[2 * n])) {
        min_eaten = std::min(min_eaten, map_left[pref_diff[2 * n]]);
    }

    // Case 2: Jars eaten from the right (k_R > 0).
    // `k_R` goes from 1 to `n`.
    for (int k_R = 1; k_R <= n; ++k_R) {
        // `pref_diff[2n-k_R]` is the prefix sum up to index `2n-k_R-1`.
        // This is the value `pref_diff[L]` we are looking for.
        int target_diff_L = pref_diff[2 * n - k_R];
        if (map_left.count(target_diff_L)) {
            min_eaten = std::min(min_eaten, k_R + map_left[target_diff_L]);
        }
    }

    std::cout << min_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

long long solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    // Max length of a substring whose decimal value can be <= N (2e5)
    // log2(2e5) approx 17.6, so max length is 18 bits for value 2^18-1
    // If length is 18, max value is 2^18-1 = 262143.
    // If length is 17, max value is 2^17-1 = 131071.
    // If length is 19, max value is 2^19-1 = 524287.
    // So, the maximum length of a substring we need to consider for its binary value
    // is around 18-20. Let's use a safe upper bound like 20.
    // The actual maximum length of a substring that can be equal to its value
    // is when value is N=2e5, which requires 18 bits.
    // So, max_len_to_check = 18.
    // However, the problem states $r-l+1 = f(s_l \dots s_r)$.
    // If $s_l \dots s_r$ has length $L$, then $f(s_l \dots s_r)$ can be at most $2^L-1$.
    // So $L \le 2^L-1$. This is true for all $L \ge 1$.
    // But $f(s_l \dots s_r)$ must also be $\le N$.
    // So $L \le N$.
    // The maximum length of a substring whose value we need to compute is limited by
    // the maximum possible value, which is $N$.
    // If $L > \text{MAX_BITS_FOR_N}$, then $f(s_l \dots s_r)$ would be too large.
    // MAX_BITS_FOR_N = ceil(log2(N)) = ceil(log2(2e5)) = 18.
    // So, we only need to check substrings of length up to 18.
    // Let's use a slightly larger constant, say 20, to be safe.
    const int MAX_BITS_TO_CHECK = 20; 

    for (int i = 0; i < n; ++i) {
        // Case 1: Substring starts with '1'
        if (s[i] == '1') {
            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                // If current_val exceeds MAX_BITS_TO_CHECK, it's too large to be a valid length.
                // Also, if current_val exceeds n, it's too large.
                // The length of the substring is (j - i + 1).
                // If (j - i + 1) > MAX_BITS_TO_CHECK, then current_val will likely be too large.
                // More precisely, if (j - i + 1) > 18, then current_val can be > 2e5.
                // We can stop early if current_val becomes too large.
                // The maximum possible length of a good substring is N.
                // If current_val > N, it cannot be a good substring.
                // Also, if current_val > 2 * N (a loose upper bound for safety), we can break.
                // A tighter bound: if current_val > N, break.
                // Or, if (j - i + 1) > MAX_BITS_TO_CHECK, then current_val will be at least 2^(MAX_BITS_TO_CHECK-1).
                // If MAX_BITS_TO_CHECK is 20, then 2^19 is already > 2e5.
                // So, we can break if (j - i + 1) > MAX_BITS_TO_CHECK.
                if (j - i + 1 > MAX_BITS_TO_CHECK) {
                    break; 
                }

                current_val = (current_val << 1) | (s[j] - '0');

                // If current_val exceeds n, it cannot be a valid length.
                // The length of the substring is (j - i + 1).
                // If current_val > n, it's definitely not equal to (j - i + 1).
                // Also, if current_val > n, it means the required length is greater than the string itself.
                // So, we can break.
                if (current_val > n) {
                    break;
                }

                if (current_val == (j - i + 1)) {
                    count++;
                }
            }
        }
    }

    // Case 2: Substring consists only of '0's
    // A substring of '0's, s_l...s_r, has f(s_l...s_r) = 0.
    // For it to be good, its length (r-l+1) must be 0.
    // But length must be at least 1. So, no substring of '0's can be good.
    // This is incorrect. f(000) = 0. Length is 3. 3 != 0.
    // The only exception is if the problem implies f(empty string) = 0, but substrings are non-empty.
    // The example f(000) = 0.
    // So, a substring of all zeros, like "0", "00", "000", etc., will always have f(substring) = 0.
    // Its length is always >= 1. So, f(substring) != length.
    // Thus, substrings consisting only of '0's are never good.

    // Case 3: Substring starts with '0' but contains '1'
    // Example: "011" -> f("011") = 3. Length = 3. Good.
    // Example: "00101" -> f("00101") = 5. Length = 5. Good.
    // We need to handle leading zeros.
    // For each '1' at index `j`, we can consider it as the first '1' in a substring.
    // The substring would be `s[i...j]`, where `s[i...j-1]` are all '0's.
    // Let `k` be the number of leading zeros before `s[j]`.
    // So, `s[j]` is the first '1' in `s[i...j]`.
    // The value `f(s[i...j])` is `f(s[j])` if `s[j]` is the first '1'.
    // No, `f(s_l \dots s_r)` is the decimal value of the binary string.
    // `f(011) = 3`. `f(00101) = 5`.
    // The value is computed from the entire substring, including leading zeros.
    // The leading zeros only affect the length, not the value.
    // For example, `f(011)` is 3. `f(11)` is 3.
    // The problem statement says "decimal representation of integer t written in binary form (possibly with leading zeroes)".
    // This means `f(011)` is 3, `f(00101)` is 5.
    // This implies that `f` effectively ignores leading zeros for value calculation.
    // So, `f(0...01X)` is the same as `f(1X)`.
    // Let's re-evaluate the example: `s = 1011`.
    // `s_1...s_1 = 1`. `f(1)=1`. Length=1. Good.
    // `s_3...s_3 = 1`. `f(1)=1`. Length=1. Good.
    // `s_4...s_4 = 1`. `f(1)=1`. Length=1. Good.
    // `s_1...s_2 = 10`. `f(10)=2`. Length=2. Good.
    // `s_2...s_4 = 011`. `f(011)=3`. Length=3. Good.
    // Total 5 good substrings.

    // My initial loop `for (int i = 0; i < n; ++i)` and `if (s[i] == '1')` only handles substrings starting with '1'.
    // It misses `011` from `s_2...s_4` in `1011`.
    // The loop should iterate through all possible starting positions `i`.
    // And for each `i`, iterate through all possible ending positions `j`.
    // The `current_val` calculation `(current_val << 1) | (s[j] - '0')` correctly computes the value of `s[i...j]`
    // including leading zeros.
    // Example: s = "011"
    // i=0, s[0]='0'
    //   j=0, s[0]='0'. current_val = 0. len = 1. 0 != 1.
    //   j=1, s[1]='1'. current_val = (0<<1)|1 = 1. len = 2. 1 != 2.
    //   j=2, s[2]='1'. current_val = (1<<1)|1 = 3. len = 3. 3 == 3. count++.
    // This means my first loop is actually correct for all substrings, including those with leading zeros.
    // The `if (s[i] == '1')` condition is wrong. It should be removed.

    count = 0; // Reset count for the corrected logic

    for (int i = 0; i < n; ++i) {
        long long current_val = 0;
        // `num_leading_zeros` counts zeros before the first '1' in the current substring `s[i...j]`.
        // This is not needed if `current_val` is computed directly.
        // The `current_val` variable correctly computes `f(s[i...j])`.
        // For example, if s[i...j] is "00101", current_val will be 5.
        // If s[i...j] is "000", current_val will be 0.

        for (int j = i; j < n; ++j) {
            int len = j - i + 1;

            // If the current substring is too long, its value will be too large.
            // The maximum value we care about is N (2e5).
            // log2(2e5) is about 17.6. So, if len > 18, current_val will be > 2e5.
            // If len > 18, then current_val will be at least 2^(len-1).
            // For len = 19, current_val >= 2^18 = 262144 > 2e5.
            // So, if len > 18, current_val cannot be equal to len.
            // We can optimize by breaking if len > 18.
            // Let's use a slightly larger constant like 20 for safety.
            if (len > MAX_BITS_TO_CHECK) { // MAX_BITS_TO_CHECK = 20
                // If we reach here, it means s[i...j-1] was processed.
                // current_val holds f(s[i...j-1]).
                // Now we are considering s[i...j].
                // If s[i...j] has length > MAX_BITS_TO_CHECK, then its value will be too large.
                // The only exception is if current_val is 0 (all zeros).
                // But if current_val is 0, then len != 0, so it's not good.
                // So, we can break.
                break;
            }

            current_val = (current_val << 1) | (s[j] - '0');

            // If current_val exceeds N, it cannot be a valid length.
            // The length of the substring is `len`.
            // If `current_val > N`, then `current_val` cannot be equal to `len` (since `len <= N`).
            // So, we can break.
            if (current_val > n) { // `n` is the length of the original string `s`.
                                    // `current_val` must be <= `n` to be a valid length.
                break;
            }

            if (current_val == len) {
                count++;
            }
        }
    }

    return count;
}

