#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The minimum possible value for the current element
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a[i] + x >= prev_val
        // This means we can potentially make a[i] become prev_val or greater.
        // If current_a >= prev_val, we can choose to increment a[i] by 0,
        // making it current_a. If current_a <= prev_val, we must increment it
        // to at least prev_val.
        // The smallest value a[i] can take is current_a.
        // The largest value a[i] can take is (current_a + x) % m.

        // If current_a is already greater than or equal to prev_val,
        // we can just keep it as current_a (by adding 0 operations to it).
        // So, the new prev_val for the next element will be current_a.
        if (current_a >= prev_val) {
            // We need to check if (current_a + x) % m < prev_val.
            // This happens if current_a + x wraps around m and becomes smaller than prev_val.
            // Example: prev_val = 5, current_a = 6, x = 1, m = 10. (6+1)%10 = 7. OK.
            // Example: prev_val = 5, current_a = 6, x = 0, m = 10. (6+0)%10 = 6. OK.
            // Example: prev_val = 5, current_a = 6, x = 10, m = 10. (6+10)%10 = 6. OK.
            // Example: prev_val = 5, current_a = 0, x = 4, m = 10. (0+4)%10 = 4. NOT OK.
            // Example: prev_val = 5, current_a = 0, x = 5, m = 10. (0+5)%10 = 5. OK.

            // If current_a + x is less than prev_val, it means even with x operations,
            // we cannot reach prev_val without wrapping around.
            // But we are in the case current_a >= prev_val.
            // So we only need to worry if current_a + x wraps around and becomes
            // smaller than prev_val.
            // This means (current_a + x) % m < prev_val, AND current_a + x >= m.
            // If current_a + x < m, then (current_a + x) % m = current_a + x >= current_a >= prev_val. This is fine.
            // So we only care if current_a + x >= m.
            // If current_a + x >= m, then the value can be (current_a + k) % m for 0 <= k <= x.
            // The smallest value it can take is current_a.
            // The largest value it can take is (current_a + x) % m.
            // If (current_a + x) % m < prev_val, it means we *must* wrap around.
            // For example, prev_val = 5, current_a = 6, x = 1, m = 10. (6+1)%10 = 7.
            // Here, current_a >= prev_val. We can choose to add 0, making it 6.
            // So prev_val for next element becomes 6.

            // If current_a + x >= m AND (current_a + x) % m < prev_val,
            // it means we cannot make a[i] >= prev_val.
            // For example, prev_val = 5, current_a = 8, x = 0, m = 10. (8+0)%10 = 8. OK.
            // For example, prev_val = 5, current_a = 8, x = 6, m = 10. (8+6)%10 = 4.
            // Here, current_a >= prev_val. But (current_a + x) % m < prev_val.
            // This means we cannot achieve a value >= prev_val.
            // The values we can achieve are [current_a, m-1] U [0, (current_a+x)%m].
            // If prev_val is in [current_a, m-1], we can achieve it.
            // If prev_val is in [0, (current_a+x)%m], we can achieve it.
            // If prev_val is in ((current_a+x)%m, current_a), we cannot achieve it.
            // This happens if (current_a + x) % m < prev_val AND current_a >= prev_val.
            // In this case, we cannot make a[i] >= prev_val.
            if ((current_a + x) % m < prev_val && current_a + x >= m) {
                return false; // Cannot satisfy non-decreasing condition
            }
            // Otherwise, we can make a[i] become current_a (by adding 0 operations to it).
            // So the next prev_val is current_a.
            prev_val = current_a;
        } else { // current_a < prev_val
            // We must increment a[i] to at least prev_val.
            // This means we need to add at least (prev_val - current_a) operations.
            // If x is less than (prev_val - current_a), we cannot reach prev_val.
            if (current_a + x < prev_val) {
                return false; // Not enough operations to reach prev_val
            }
            // If we can reach prev_val (i.e., current_a + x >= prev_val),
            // we can choose to increment a[i] by (prev_val - current_a) operations.
            // This makes a[i] become prev_val.
            // So the next prev_val is prev_val.
            // No change to prev_val.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_i = a_i + current_delta_i
    // We want to find initial a_i such that a_i + current_delta_i <= m_k for all type 2 ops
    // and a_i + current_delta_i = m_k for at least one j in [l_k, r_k]
    // This means a_i <= m_k - current_delta_i for all type 2 ops covering i.
    // So, a_i <= min(m_k - current_delta_i) over all relevant type 2 ops.
    // Let's call this upper bound for a_i as `max_initial_val[i]`.
    // Initialize `max_initial_val[i]` to a very large value.
    std::vector<long long> max_initial_val(n, std::numeric_limits<long long>::max());

    // Calculate `max_initial_val` for each `a_i`
    // Iterate through operations in reverse to find the `current_delta_i` at the time of each type 2 op.
    // This `current_delta_i` is the sum of `d` values from type 1 ops *after* the current type 2 op.
    // Let `delta_suffix[j]` be the sum of `d` values applied to `a_j` by type 1 operations
    // that occur *after* the current operation being processed.
    std::vector<long long> delta_suffix(n, 0);

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This is a type 1 operation. It contributes to `delta_suffix` for operations before it.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                delta_suffix[j] -= ops[i].val; // Subtract d because we are going backwards
            }
        } else { // ops[i].type == 2
            // This is a type 2 operation. It imposes a constraint on `a_j`.
            // At the time of this operation, the value of a_j was `initial_a_j + (total_delta_up_to_this_op_for_j)`.
            // The `total_delta_up_to_this_op_for_j` is `(total_delta_for_j_at_end) - delta_suffix[j]`.
            // So, `initial_a_j + (total_delta_for_j_at_end) - delta_suffix[j] <= ops[i].val`.
            // This implies `initial_a_j <= ops[i].val - ((total_delta_for_j_at_end) - delta_suffix[j])`.
            // For now, we just need `initial_a_j <= ops[i].val - delta_suffix[j]` (where `delta_suffix[j]` here
            // represents the sum of `d` values from type 1 ops *after* this type 2 op).
            // The `total_delta_for_j_at_end` is not needed here.
            // The `delta_suffix[j]` here is the sum of `d` values from type 1 ops that occur *after* the current op `i`.
            // So, `a_j + (sum of d's before op i) + (sum of d's from op i to end) = a_j + delta_suffix[j]` (if delta_suffix was total delta)
            // Let's rephrase:
            // `a_j_at_op_i = initial_a_j + (sum of d's from ops 0 to i-1)`
            // We need `a_j_at_op_i <= ops[i].val` for `j` in `[l, r]`.
            // This means `initial_a_j <= ops[i].val - (sum of d's from ops 0 to i-1)`.
            // Let `current_delta_at_op_i[j]` be `(sum of d's from ops 0 to i-1)` for index `j`.
            // Then `initial_a_j <= ops[i].val - current_delta_at_op_i[j]`.
            // The `delta_suffix` array, as defined, stores `sum of d's from ops i to m-1`.
            // So, `current_delta_at_op_i[j]` is `(total_delta_at_end[j]) - delta_suffix[j]`.
            // Thus, `initial_a_j <= ops[i].val - ((total_delta_at_end[j]) - delta_suffix[j])`.
            // This is `initial_a_j <= ops[i].val - total_delta_at_end[j] + delta_suffix[j]`.
            // The `total_delta_at_end[j]` is not known yet.
            // Let's define `b_j = a_j + total_delta_at_end[j]`. We want to find `a_j`.
            // The value of `a_j` at operation `i` is `a_j + (sum of d's from ops 0 to i-1)`.
            // This is `a_j + (total_delta_at_end[j] - (sum of d's from ops i to m-1))`.
            // This is `a_j + total_delta_at_end[j] - (-delta_suffix[j])` (if delta_suffix was sum of d's from i to m-1).
            // Let's redefine `delta_suffix[j]` as the sum of `d` values from type 1 operations *after* operation `i`.
            // So, when we process op `i` (type 2), `delta_suffix[j]` contains `sum_{k=i+1}^{m-1} d_k` for index `j`.
            // The value of `a_j` at op `i` is `initial_a_j + (sum_{k=0}^{i-1} d_k)`.
            // Let `total_delta_final[j]` be `sum_{k=0}^{m-1} d_k` for index `j`.
            // Then `sum_{k=0}^{i-1} d_k = total_delta_final[j] - sum_{k=i}^{m-1} d_k`.
            // The `delta_suffix` array, as currently implemented, stores `sum_{k=i}^{m-1} d_k` (with negative sign).
            // So, `sum_{k=0}^{i-1} d_k = total_delta_final[j] + delta_suffix[j]`.
            // The constraint is `initial_a_j + (total_delta_final[j] + delta_suffix[j]) <= ops[i].val`.
            // This means `initial_a_j <= ops[i].val - total_delta_final[j] - delta_suffix[j]`.
            // This is the correct interpretation.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_initial_val[j] = std::min(max_initial_val[j], ops[i].val - delta_suffix[j]);
            }
        }
    }

    // Now `max_initial_val[j]` holds `min(m_k - delta_suffix[j])` for all relevant type 2 ops.
    // This is `min(m_k - (sum of d's from ops i to m-1))` for type 2 op `i`.
    // This is `min(m_k - (sum of d's from ops i to m-1))` for type 2 op `i`.
    // Let `a_j_candidate = max_initial_val[j]`.
    // We need to verify this candidate array.
    std::vector<long long> a_candidate = max_initial_val;

    // Simulate operations with `a_candidate`
    std::vector<long long> current_a = a_candidate;
    std::vector<long long> current_delta(n, 0); // Total delta applied to a_candidate so far

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, a_candidate[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array
    for (int i = 0; i < n; ++i) {
        if (std::abs(a_candidate[i]) > 1000000000LL) {
            // This case should ideally not happen if the problem guarantees a solution within bounds
            // and our logic correctly finds one. But it's good to check.
            // The problem states `|a_i| <= 10^9`.
            // The `m_i` values are up to `5*10^7`. `d_i` up to `10^4`.
            // `m` up to `5000`.
            // `delta_suffix` can be up to `5000 * 10^4 = 5*10^7`.
            // So `a_i` can be `m_i - delta_suffix` which is `5*10^7 - (-5*10^7) = 10^8`.
            // Or `-5*10^7 - (5*10^7) = -10^8`.
            // So `|a_i|` should be within `10^8`, which is well within `10^9`.
            // This check might be redundant given the constraints.
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_candidate[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long d_chain_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply d_chain_cry from previous children who ran away
            if (d_chain_cry > 0) {
                children[j].p -= d_chain_cry;
            }

            // Apply current_v_cry from child i going to doctor
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                d_chain_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

