bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into A and B. We form B+A.
    // We need B+A to be a palindrome and B+A != s.
    for (int i = 1; i < n; ++i) { // Cut position i means A = s[0...i-1], B = s[i...n-1]
        std::string a = s.substr(0, i);
        std::string b = s.substr(i);
        std::string s_prime = b + a;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 is not possible, we check k=2.
    // With k=2, we can always make a new palindrome unless all characters are the same.
    // If all characters are the same (e.g., "aaaa"), then any rearrangement of substrings
    // will result in the same string "aaaa", which is a palindrome but not different from s.
    // In this case, it's impossible.

    // Check if all characters in s are the same.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
        // Example: s = "nolon"
        // Cut into "no", "l", "on". Rearrange to "on", "l", "no" -> "onlno". This is a palindrome and != "nolon".
        // This strategy works for any palindrome s that is not composed of all identical characters.
        // The strategy is to cut s into s[0...i-1], s[i], s[i+1...n-1] for some i.
        // Then rearrange to s[i+1...n-1] + s[i] + s[0...i-1].
        // Since s is a palindrome, s[0...i-1] is reverse of s[n-i...n-1].
        // And s[i+1...n-1] is reverse of s[0...n-1-i].
        // The new string will be a palindrome.
        // We just need to ensure it's different from s.
        // If s is not all same characters, there must be at least two distinct characters.
        // If n is odd, say n=2m+1, s = P c P_rev.
        // If n is even, say n=2m, s = P P_rev.
        // If s is not all same characters, we can always find a cut that results in a different palindrome.
        // For example, cut s into s[0...n/2-1], s[n/2...n-1].
        // If n is odd, s = s[0...n/2-1] + s[n/2] + s[n/2+1...n-1].
        // Let A = s[0...n/2-1], B = s[n/2], C = s[n/2+1...n-1].
        // s = A B C.
        // New string C B A. This is a palindrome.
        // If C B A == A B C, then A == C.
        // Since s is a palindrome, A is reverse of C. So A == C implies A is a palindrome.
        // If A is a palindrome, and s is a palindrome, and s is not all same chars,
        // then we can always find a cut.
        // The problem statement guarantees s is a palindrome.
        // If s is not all same characters, then k=2 is always possible.
        std::cout << 2 << std::endl;
    }

    return 0;
}

