    // The overall minimum `f` will be `min(a[0].value + a[1].value, a[0].value + a[1].value + h)`
    // which is `a[0].value + a[1].value`.
    // The overall maximum `f` will be `max(a[n-2].value + a[n-1].value, a[n-2].value + a[n-1].value + h)`
    // which is `a[n-2].value + a[n-1].value + h`.
    //
    // So, if both types of pairs exist (same group and different groups),
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value + h
    // goodness = (a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value)

    // This is true if there is at least one pair (x,y) in the same group AND at least one pair (u,v) in different groups.
    // This happens if both groups are non-empty and contain at least two elements each, OR
    // if one group has at least two elements and the other has at least one.
    //
    // Consider the partition where a[0] is in group 1, and all other elements a[1]...a[n-1] are in group 2.
    // S1 = {a[0]}
    // S2 = {a[1], ..., a[n-1]}
    //
    // Pairs within S1: None.
    // Pairs within S2: (a[i], a[j]) for i,j in {1, ..., n-1}.
    //    Min: a[1].value + a[2].value (if n > 2)
    //    Max: a[n-2].value + a[n-1].value
    // Pairs between S1 and S2: (a[0], a[i]) for i in {1, ..., n-1}.
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    //
    // Overall min_f for this partition:
    // If n=2, S1={a[0]}, S2={a[1]}. Only one pair: a[0].value + a[1].value + h.
    // If n>2, min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h).
    // Overall max_f for this partition:
    // If n=2, max_f = a[0].value + a[1].value + h.
    // If n>2, max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h).

    // Let's analyze the two main candidates for optimal partition:
    // 1. All elements in one group (e.g., all 1s).
    //    min_f = a[0].value + a[1].value
    //    max_f = a[n-2].value + a[n-1].value
    //    goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    //    This is `goodness1`.

    // 2. Partition where a[0] is in group 1, and a[1]...a[n-1] are in group 2.
    //    S1 = {a[0]}, S2 = {a[1], ..., a[n-1]}
    //    min_f_same_group = a[1].value + a[2].value (if n > 2, else infinity)
    //    max_f_same_group = a[n-2].value + a[n-1].value (if n > 2, else -infinity)
    //    min_f_diff_group = a[0].value + a[1].value + h
    //    max_f_diff_group = a[0].value + a[n-1].value + h
    //
    //    If n=2: S1={a[0]}, S2={a[1]}. Only diff_group pair.
    //      min_f = a[0].value + a[1].value + h
    //      max_f = a[0].value + a[1].value + h
    //      goodness = 0.
    //      This is better than goodness1 if h=0, otherwise goodness1 is 0.
    //      If n=2, goodness1 = (a[0]+a[1]) - (a[0]+a[1]) = 0. So goodness1 is always 0 for n=2.
    //      This means for n=2, any partition is optimal with goodness 0.
    //      The problem states n >= 2.
    //
    //    If n > 2:
    //      min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //      max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //      goodness = max_f - min_f
    //
    // Let's call this `goodness2`.
    long long goodness2;
    std::vector<int> partition2(n);
    if (n == 2) {
        goodness2 = 0; // (a[0]+a[1]+h) - (a[0]+a[1]+h)
    } else {
        long long min_f_val = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        long long max_f_val = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
        goodness2 = max_f_val - min_f_val;
    }
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> p_filtered;
    std::set<long long> p_set(p.begin(), p.end());

    for (long long val : h) {
        if (p_set.count(val)) {
            p_set.erase(val);
        }
    }
    for (long long val : p_set) {
        p_filtered.push_back(val);
    }

    if (p_filtered.empty()) {
        return true;
    }

    int current_p_idx = 0;
    int num_uncovered_p = p_filtered.size();

    for (int i = 0; i < n; ++i) {
        if (current_p_idx == num_uncovered_p) {
            return true;
        }

        long long head_pos = h[i];
        long long first_uncovered_p = p_filtered[current_p_idx];

        // Case 1: Head moves left to cover first_uncovered_p
        // The head moves to first_uncovered_p.
        // It can cover tracks in [first_uncovered_p, first_uncovered_p + T - (first_uncovered_p - head_pos)]
        // if first_uncovered_p <= head_pos.
        // Or it can cover tracks in [first_uncovered_p - (head_pos - first_uncovered_p), first_uncovered_p + T]
        // if first_uncovered_p > head_pos.
        // This is equivalent to saying it can cover tracks in [first_uncovered_p, head_pos + T] if it moves left.
        // The total distance moved is max(0, head_pos - first_uncovered_p).
        // The remaining time is T - max(0, head_pos - first_uncovered_p).
        // The rightmost track it can cover is first_uncovered_p + remaining_time.
        // This simplifies to: if head_pos >= first_uncovered_p, it can cover up to head_pos + T.
        // If head_pos < first_uncovered_p, it can cover up to first_uncovered_p + (T - (first_uncovered_p - head_pos)) = head_pos + T.
        // So, if it moves left to cover first_uncovered_p, it can cover up to head_pos + T.
        // This is not quite right. The head moves to some point X. It covers [X-T_rem, X+T_rem].
        // If it moves to first_uncovered_p, it uses |head_pos - first_uncovered_p| time.
        // Remaining time is T - |head_pos - first_uncovered_p|.
        // It can then cover tracks in [first_uncovered_p, first_uncovered_p + (T - |head_pos - first_uncovered_p|)].
        // This is the range [first_uncovered_p, first_uncovered_p + T - (first_uncovered_p - head_pos)] if first_uncovered_p <= head_pos
        // which is [first_uncovered_p, head_pos + T].
        // If first_uncovered_p > head_pos, it's [first_uncovered_p, first_uncovered_p + T - (first_uncovered_p - head_pos)]
        // which is [first_uncovered_p, head_pos + T].
        // So, if it moves to first_uncovered_p, it can cover up to head_pos + T.
        // This is only if first_uncovered_p is within [head_pos - T, head_pos + T].
        // The actual range covered is [first_uncovered_p, first_uncovered_p + (T - (first_uncovered_p - head_pos))]
        // if first_uncovered_p <= head_pos and first_uncovered_p >= head_pos - T.
        // This is [first_uncovered_p, head_pos + T].
        // If first_uncovered_p > head_pos and first_uncovered_p <= head_pos + T.
        // The head moves to first_uncovered_p. It uses first_uncovered_p - head_pos time.
        // Remaining time is T - (first_uncovered_p - head_pos).
        // It can cover up to first_uncovered_p + (T - (first_uncovered_p - head_pos)) = head_pos + T.
        // So, if first_uncovered_p is reachable, it can cover up to head_pos + T.
        // This is the "greedy" choice: move to first_uncovered_p and sweep right as much as possible.

        long long rightmost_covered_by_moving_to_first_p = -1;
        if (first_uncovered_p >= head_pos - T && first_uncovered_p <= head_pos + T) {
            rightmost_covered_by_moving_to_first_p = head_pos + T;
        }

        // Case 2: Head moves right to cover first_uncovered_p
        // The head moves to some point X such that first_uncovered_p is covered.
        // To maximize the rightmost point covered, the head should move to the rightmost possible point X
        // that still covers first_uncovered_p.
        // This means X + T >= first_uncovered_p.
        // And X - T <= first_uncovered_p.
        // The head can move to any X in [head_pos - T, head_pos + T].
        // We want to find max(X+T_rem) where T_rem is remaining time.
        // If we move to X, time used is |head_pos - X|. Remaining time is T - |head_pos - X|.
        // We cover [X - (T - |head_pos - X|), X + (T - |head_pos - X|)].
        // We need to cover first_uncovered_p.
        // If we move to X = head_pos + T, we cover [head_pos, head_pos + 2T].
        // If we move to X = head_pos - T, we cover [head_pos - 2T, head_pos].
        // This is not how it works. The head moves to a point X. It covers [X, X] and all points it passes.
        // The problem states: "A track is considered read if at least one head has visited this track."
        // If a head moves from A to B, all tracks in [min(A,B), max(A,B)] are visited.
        // So if a head at h_i moves to X, it covers [min(h_i, X), max(h_i, X)].
        // The time taken is |h_i - X|.
        // If we have T seconds, we can move to any X such that |h_i - X| <= T.
        // This means we can move to any X in [h_i - T, h_i + T].
        // If we move to X, we cover the interval [min(h_i, X), max(h_i, X)].
        // To cover first_uncovered_p, we must choose X such that first_uncovered_p is in [min(h_i, X), max(h_i, X)].
        // And |h_i - X| <= T.
        // To maximize the rightmost point covered, we should choose X as large as possible.
        // The largest X we can choose is h_i + T.
        // If we move to h_i + T, we cover [h_i, h_i + T].
        // If first_uncovered_p is in [h_i, h_i + T], then this move covers it.
        // The rightmost point covered is h_i + T.
        // This is the "greedy" choice: move right as much as possible.

        long long rightmost_covered_by_moving_right = -1;
        if (first_uncovered_p >= head_pos && first_uncovered_p <= head_pos + T) {
            rightmost_covered_by_moving_right = head_pos + T;
