#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long total_operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // as long as a[i] + min_val <= k.
        // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
        total_operations += (k - a[i]) / min_val;
    }

    std::cout << total_operations << std::endl;
}

