int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach for denominations 5, 2, 1
        // This works because 5 > 2*2 and 2 > 1*1.
        // For example, if we have 4, we can do 2+2 (2 presses) or 5-1 (2 presses).
        // If we have 3, we can do 2+1 (2 presses) or 5-2 (2 presses).
        // The greedy choice of taking as many 5s as possible, then 2s, then 1s
        // will always yield the minimum number of presses.

        presses += diff / 5;
        diff %= 5;

        // Now diff can be 0, 1, 2, 3, 4
        if (diff == 4) {
            // 4 can be 2+2 (2 presses) or 5-1 (2 presses). Both are 2 presses.
            // Greedy: 2+2.
            presses += 2;
        } else if (diff == 3) {
            // 3 can be 2+1 (2 presses) or 5-2 (2 presses). Both are 2 presses.
            // Greedy: 2+1.
            presses += 2;
        } else if (diff == 2) {
            // 2 is 1 press.
            presses += 1;
        } else if (diff == 1) {
            // 1 is 1 press.
            presses += 1;
        }
        // If diff is 0, no more presses needed.

        std::cout << presses << "\n";
    }
    return 0;
}

