void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always works.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // Let p' be the reversed permutation: p'_i = p_{n-i+1}.
    // p' = [p_n, p_{n-1}, ..., p_1]
    // F(p') = sort([p'_1+p'_2, p'_2+p'_3, ..., p'_{n-1}+p'_n])
    // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // The set of adjacent sums for p' is {p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1}.
    // This is the same set of sums as for p, just in reverse order.
    // Since the fingerprint involves sorting these sums, F(p) will be equal to F(p').
    // The reversed permutation p' is different from p unless p is a palindrome.
    // A permutation of distinct integers from 1 to n cannot be a palindrome for n >= 2.
    // For example, if p = [1, 2, ..., n], then p_1 = 1, p_n = n.
    // If p were a palindrome, p_1 would have to be equal to p_n, which is impossible for distinct elements.
    // Thus, p' will always be different from p.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

