    // x_i will store the necklace brightness for daughter i
    // y_i will store the bracelet brightness for daughter i
    std::vector<int> x(n);
    std::vector<int> y(n);

    // The strategy is to pair the i-th smallest necklace with the i-th smallest bracelet.
