    // The problem asks for x_i and y_i to be the brightnesses for the i-th daughter.
    // So, we assign a_indexed[i].first to x[i] and b_indexed[i].first to y[i].
    for (int i = 0; i < n; ++i) {
        x[i] = a_indexed[i].first;
        y[i] = b_indexed[i].first;
