#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
        long long pile_idx = i + 1; // 1-based index of the current pile
        long long cost_per_bale = pile_idx - 1; // Days to move one haybale from this pile to pile 1

        if (cost_per_bale == 0) { // Should not happen for i >= 1
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on remaining days
        long long max_bale_moves_from_days = remaining_days / cost_per_bale;

        // Calculate how many haybales are actually available in this pile
        long long available_bales = a[i];

        // Move the minimum of available bales and bales affordable with remaining days
        long long bales_to_move = std::min(available_bales, max_bale_moves_from_days);

        current_a1 += bales_to_move;
        remaining_days -= bales_to_move * cost_per_bale;

        if (remaining_days <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

