void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
        return;
    }

    // For n >= 2, we can construct a number.
    // A simple construction is to use '2' for the first digit
    // and '3' for all subsequent digits.
    // This number would be 233...3 (n-1 times '3').
    // Let's check its properties:
    // 1. All digits are non-zero (2 and 3).
    // 2. It's an n-digit number.
    // 3. Divisibility:
    //    - Not divisible by 2: The number ends in 3, which is odd.
    //    - Not divisible by 3: The sum of digits is 2 + (n-1)*3.
    //      If n=2, sum=2+3=5. Not div by 3.
    //      If n=3, sum=2+3+3=8. Not div by 3.
    //      If n=4, sum=2+3+3+3=11. Not div by 3.
    //      In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
    //      Since 3n is divisible by 3, 3n-1 is never divisible by 3.
    // So, this construction works for all n >= 2.

    std::cout << '2';
    for (int i = 0; i < n - 1; ++i) {
        std::cout << '3';
    }
    std::cout << "\n";
}

