int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to n+1
        // The length of the string is s.length(), so the last cell is s.length()
        // The target is cell s.length() + 1
        // If last_R_pos is -1, it means no 'R's were found.
        // In this case, the frog must jump from cell 0 to cell n+1 directly.
        // The distance is (n+1) - 0 = n+1.
        // If last_R_pos is not -1, the last 'R' is at index last_R_pos.
        // This corresponds to cell last_R_pos + 1.
        // The distance from this cell to n+1 is (s.length() + 1) - (last_R_pos + 1) = s.length() - last_R_pos.
        max_gap = std::max(max_gap, (int)s.length() - last_R_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

