    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags `has_pos_one` and `has_neg_one` reflect the state of elements a[0...i]
            // that can affect elements a[i+1...n-1].
            // For a[i], its own value is fixed, so we update flags for future iterations.
            if (a[i] == 1) has_pos_one = true;
            if (a[i] == -1) has_neg_one = true;
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i], need to decrease a[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // If we reach here, it means a[i] != b[i] and we have the necessary +1 or -1
        // available from an earlier index.
        // The value a[i] is effectively "consumed" or "fixed" to b[i] for this check.
        // We must update has_pos_one/has_neg_one based on a[i]'s original value
        // for elements a[0...i-1] that might need to use it.
        // However, the problem states that a_i can be added to a_j for j > i.
        // When we are at index i, we are determining if a[i] can become b[i].
        // The values a[0...i-1] are available to modify a[i].
        // The values a[i+1...n-1] are already fixed to b[i+1...n-1] and cannot modify a[i].
        // The flags `has_pos_one` and `has_neg_one` should track if there's a 1 or -1
        // *among a[0...i-1]* that can be used to modify a[i].
        //
        // Let's re-evaluate the flags.
        // When iterating from right to left, `has_pos_one` and `has_neg_one` should
        // represent if there is a 1 or -1 in `a[0...i-1]`.
        //
        // The initial loop for `a` correctly sets `has_pos_one` and `has_neg_one` for the *entire* array `a`.
        // As we iterate `i` from `n-1` down to `0`:
        // For `a[i]`, we check if it can become `b[i]`.
        // If `a[i] < b[i]`, we need to add positive values. This requires `a_k = 1` for some `k < i`.
        // If `a[i] > b[i]`, we need to add negative values. This requires `a_k = -1` for some `k < i`.
        //
        // The flags `has_pos_one` and `has_neg_one` should be updated *after* processing `a[i]`
        // to reflect the availability of 1s and -1s in `a[0...i-1]`.
        //
        // Let's restart the logic for flags.
        // `has_pos_one_prefix[i]` = true if there is a 1 in `a[0...i]`.
        // `has_neg_one_prefix[i]` = true if there is a -1 in `a[0...i]`.
        //
        // We need to check `a[i]` against `b[i]`.
        // If `a[i] < b[i]`, we need to add `b[i] - a[i]` (positive amount). This requires `has_pos_one_prefix[i-1]` to be true.
        // If `a[i] > b[i]`, we need to add `b[i] - a[i]` (negative amount). This requires `has_neg_one_prefix[i-1]` to be true.
        //
        // The initial `has_pos_one` and `has_neg_one` should be computed as prefix sums.
        // Let's re-read the problem: "Choose any pair of indexes (i, j) such that 1 <= i < j <= n."
        // This means a_k can be added to a_i if k < i.
        //
        // So, for a[i], we need to know if there's a 1 or -1 in a[0...i-1].
        //
        // Let's re-initialize `has_pos_one` and `has_neg_one` to track elements *before* the current index `i`.
    }

    // Corrected logic for flags:
    // Iterate from right to left.
    // `can_add_pos` indicates if there's a 1 at an index `k < current_i`.
    // `can_add_neg` indicates if there's a -1 at an index `k < current_i`.
    bool can_add_pos = false;
    bool can_add_neg = false;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // If a[i] is 1 or -1, it can be used by elements to its right (j > i).
            // But we are iterating from right to left.
            // So, for a[i], we only care about elements a[k] where k < i.
            // The flags `can_add_pos` and `can_add_neg` should reflect elements a[0...i-1].
            // After processing a[i], we update these flags to include a[i] for future (leftward) iterations.
            // This means, for the next iteration (i-1), a[i] is now part of the "prefix" that can affect a[i-1].
            // This is incorrect. a[i] cannot affect a[i-1].
            //
            // The flags `can_add_pos` and `can_add_neg` should track if there's a 1 or -1 in `a[0...i-1]`.
            // So, when we are at index `i`, we use the flags that represent `a[0...i-1]`.
            // After processing `a[i]`, we update the flags to include `a[i]` for the *next* iteration's `i-1` check.
            // This means, `can_add_pos` should be true if `a[i]` was 1 OR `can_add_pos` was true from `a[0...i-1]`.
            // This is effectively a suffix check for the ability to add.
            //
            // Let's use the original `has_pos_one` and `has_neg_one` as prefix flags.
            // `prefix_has_pos_one[k]` = true if `a[0...k]` contains a 1.
            // `prefix_has_neg_one[k]` = true if `a[0...k]` contains a -1.
            //
            // For `a[i]`, we need to check `prefix_has_pos_one[i-1]` and `prefix_has_neg_one[i-1]`.
            // This requires precomputing these prefix flags.

            // Let's try again with the original logic, but carefully.
            // `has_pos_one` and `has_neg_one` track if there's a 1 or -1 *among a[0...i]*
            // (including the current a[i]) that can be used to modify elements to its right.
            // When we iterate from right to left, for a[i], we need to know if there's a 1 or -1
            // *before* index i (i.e., in a[0...i-1]).
            // So, the flags should be updated *after* checking a[i] and *before* moving to i-1.

            // Initial state: `has_pos_one` and `has_neg_one` are true if there's a 1 or -1 in `a[0...n-1]`.
            // This is not what we need for `a[i]`.
            // We need to know if `a[0...i-1]` contains a 1 or -1.

            // Let's use two boolean variables, `found_one` and `found_neg_one`,
            // which will track if we've encountered a 1 or -1 *so far* as we iterate from left to right.
            // Then, when we iterate from right to left, we can use these precomputed values.

            // Precompute prefix flags
            std::vector<bool> prefix_has_pos_one(n, false);
            std::vector<bool> prefix_has_neg_one(n, false);
            if (a[0] == 1) prefix_has_pos_one[0] = true;
            if (a[0] == -1) prefix_has_neg_one[0] = true;
            for (int k = 1; k < n; ++k) {
                prefix_has_pos_one[k] = prefix_has_pos_one[k-1] || (a[k] == 1);
                prefix_has_neg_one[k] = prefix_has_neg_one[k-1] || (a[k] == -1);
            }

            bool current_possible = true;
            for (int i = n - 1; i >= 0; --i) {
                if (a[i] == b[i]) {
                    continue;
                }

                bool can_increase = (i > 0) ? prefix_has_pos_one[i-1] : false;
                bool can_decrease = (i > 0) ? prefix_has_neg_one[i-1] : false;

                if (a[i] < b[i]) { // Need to increase a[i]
                    if (!can_increase) {
                        current_possible = false;
                        break;
                    }
                } else { // a[i] > b[i], need to decrease a[i]
                    if (!can_decrease) {
                        current_possible = false;
                        break;
                    }
                }
            }
            possible = current_possible;
            break; // Exit the outer loop, as we've re-evaluated with correct flags.
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

