int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // Total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of (h/2) / n = h / (2n).

    // Let x_i be the distance from the apex to the i-th cut.
    // The triangle formed by the apex and the i-th cut has height x_i.
    // Due to similarity, its base b_i relates to x_i as b_i / x_i = 1 / h, so b_i = x_i / h.
    // The area of this triangle is (1/2) * b_i * x_i = (1/2) * (x_i / h) * x_i = x_i^2 / (2h).

    // For the i-th cut (from the apex), the area of the top part of the carrot
    // (from apex to x_i) must be equal to i times the area of one piece.
    // So, x_i^2 / (2h) = i * (h / (2n)).
    // x_i^2 = i * (h^2 / n).
    // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

