int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For d >= 4, d^2 - 4d >= 0, so sqrt is real.
            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            // Both a and b will be non-negative.
            // d + sqrt(d^2 - 4d) >= 0 (since d >= 4)
            // d - sqrt(d^2 - 4d) >= 0 because d^2 >= d^2 - 4d, so d >= sqrt(d^2 - 4d) for d >= 4.

            double sqrt_discriminant = std::sqrt(d * d - 4 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, min_idx and max_idx are already set to pos[1].
        // The segment is [pos[1], pos[1]], length 1.
        // min value is 1, max value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment [min_idx, max_idx]
        // to include 'm'.
        // The number 'm' is at pos[m].
        // We need to update min_idx and max_idx to cover the range
        // from 1 to m.
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // A segment [min_idx, max_idx] contains all numbers from 1 to m
        // if and only if its length is exactly m.
        // The length of the current segment is (max_idx - min_idx + 1).
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m;

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long m_last_digit = m % 10;

        // Precompute the sum of last digits for one cycle (10 multiples)
        // The sequence of last digits (i*m)%10 repeats every 10 terms for i.
        // (1*m)%10, (2*m)%10, ..., (10*m)%10
        std::vector<long long> cycle_last_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits[i - 1] = (static_cast<long long>(i) * m_last_digit) % 10;
            cycle_sum += cycle_last_digits[i - 1];
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Add the sum for the remaining multiples
        long long remaining_multiples = count % 10;
        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

