#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> left_min_val(n);
    left_min_val[0] = 0; // a[0] must be >= 0
    for (int i = 1; i < n; ++i) {
        left_min_val[i] = std::max(left_min_val[i-1] + 1, 0LL);
    }

    std::vector<long long> right_min_val(n);
    right_min_val[n-1] = 0; // a[n-1] must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        right_min_val[i] = std::max(right_min_val[i+1] + 1, 0LL);
    }

    for (int k = 0; k < n; ++k) {
        // For a[k] to be the peak, it must satisfy conditions for both increasing and decreasing parts.
        // Specifically, a[k] must be >= left_min_val[k] and a[k] must be >= right_min_val[k].
        // If a[k] (original value) is greater than or equal to both of these minimums,
        // then we can potentially form a sharpened array with k as the peak.
        if (a[k] >= left_min_val[k] && a[k] >= right_min_val[k]) {
            std::cout << "Yes\n";
            return;
        }
    }

    std::cout << "No\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Cost for elements to the left of the median
    // These elements must be <= s. If a[i] > s, we must decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Cost for elements to the right of the median
    // These elements must be >= s. If a[i] < s, we must increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

