    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (the 'p_i' values)
    int right_ptr = 0; // Pointer for original elements (the 'a_i' values)

    // We iterate through the sorted array 'a'.
    // 'a[right_ptr]' represents an original element.
    // 'a[left_ptr]' represents an element from the available pool to place.
    // To maximize matches, we try to place the smallest available element 'a[left_ptr]'
    // into a position where 'a[right_ptr]' used to be, such that 'a[left_ptr] > a[right_ptr]'.
    // Since both are sorted, this greedy approach works.
    // If a[left_ptr] can be placed at a position originally held by a[right_ptr]
    // (i.e., a[left_ptr] > a[right_ptr]), we make that match and increment both pointers.
    // Otherwise, a[left_ptr] is too small for a[right_ptr], so we must try a larger
    // element for a[right_ptr]. We increment left_ptr to consider the next available element.
    while (left_ptr < n && right_ptr < n) {
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            left_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

