#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check prefixes
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (seen_prefix[a[i]]) {
            distinct_prefix = false;
            break;
        }
        seen_prefix[a[i]] = true;
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (distinct_prefix && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Check suffixes
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (seen_suffix[a[i]]) {
            distinct_suffix = false;
            break;
        }
        seen_suffix[a[i]] = true;
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (distinct_suffix && max_val_suffix == (n - i)) {
            is_suffix_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Case 1: Final toy in Box 1 (negative, magnitude >= 1)
    // Requires an odd number of negative toys.
    // Requires at least one toy with magnitude >= 1, or two toys with magnitude > 1.
    // Or, if all initial toys have magnitude < 1, it's impossible to get magnitude >= 1.
    // If there are no toys with magnitude >= 1 (A=0, D=0), then the product of B and C toys will always have magnitude < 1.
    // So, if A=0 and D=0, Box 1 is impossible.
    if (a + d > 0) { // At least one toy with magnitude >= 1 initially
        // If total negative toys (A+B) is odd, final sign can be negative.
        // If total negative toys (A+B) is even, final sign can be positive.
        // We can always arrange multiplications to get an odd number of negative factors for the final product
        // if A+B > 0.
        // If A+B is odd, we can get a negative final product.
        // If A+B is even, we can get a positive final product.
        // If A+B is 0, final product is positive.

        // To get negative final product:
        // If A+B is odd, we can achieve negative.
        // If A+B is even and A+B > 0, we can achieve negative by pairing up negative numbers,
        // then multiplying one of them by a positive number, then multiplying by another negative number.
        // Example: -2, -0.5, -0.5. (-2 * -0.5) = 1. Then 1 * -0.5 = -0.5 (Box 2).
        // This is about the *parity* of negative numbers in the final product.
        // The final product's sign is determined by the parity of negative numbers used in the *final* multiplication.
        // We can always control the parity of negative numbers in the final product.
        // If we have at least one negative toy (A+B > 0), we can make the final product negative.
        // If we have at least one positive toy (C+D > 0), we can make the final product positive.
        // If we have both (A+B > 0 and C+D > 0), we can make it either.
        // If only negative toys (C=0, D=0), final product sign is (-1)^(A+B).
        // If only positive toys (A=0, B=0), final product sign is positive.

        // Can we make the final product negative?
        // Yes, if A+B > 0.
        // Can we make the final product magnitude >= 1?
        // Yes, if A+D > 0.
        // If A+B > 0 and A+D > 0, then Box 1 is possible.
        // Exception: If total_toys == 1, and that toy is in Box 1.
        if (total_toys == 1 && a == 1) {
            ans1 = "Ya";
        } else if (total_toys > 1) {
            // To get negative: need A+B > 0.
            // To get magnitude >= 1: need A+D > 0.
            // If A+B > 0 and A+D > 0, we can achieve Box 1.
            // We can always ensure the final product is negative if there's at least one negative toy.
            // We can always ensure the final product has magnitude >= 1 if there's at least one toy with magnitude >= 1.
            // The only tricky part is if we only have one negative toy and one positive toy with magnitude >= 1.
            // E.g., A=1, D=1. Say -2 and 3. Product is -6 (Box 1).
            // E.g., A=1, B=1, D=1. Say -2, -0.5, 3.
            //   (-2 * -0.5) = 1 (Box 4). Then 1 * 3 = 3 (Box 4).
            //   (-2 * 3) = -6 (Box 1). Then -6 * -0.5 = 3 (Box 4).
            //   (-0.5 * 3) = -1.5 (Box 1). Then -1.5 * -2 = 3 (Box 4).
            // This shows that the final box depends on the sequence.
            // The problem asks "which boxes *can* be the special box".
            // So we need to find if there exists *any* sequence.

            // Box 1: Negative, magnitude >= 1
            // To get negative: need to have an odd number of negative factors in the final product.
            // This is possible if A+B > 0.
            // To get magnitude >= 1: need to have at least one factor with magnitude >= 1,
            // or multiple factors with magnitude > 1.
            // This is possible if A+D > 0.
            // If A+B > 0 and A+D > 0, then Box 1 is possible.
            // The only edge case is if A+B=0 (all positive) or A+D=0 (all magnitude < 1).
            // If A+B=0, cannot be negative.
            // If A+D=0, cannot be magnitude >= 1.
            if (a + b > 0 && a + d > 0) {
                ans1 = "Ya";
            }
        }
    }

    // Case 2: Final toy in Box 2 (negative, magnitude < 1)
    // Requires an odd number of negative toys.
    // Requires all toys to have magnitude < 1, or a mix that results in magnitude < 1.
    // If A+D=0 (all initial toys have magnitude < 1), then the final product will always have magnitude < 1.
    // If A+D > 0, it's still possible to get magnitude < 1 (e.g., -2 * 0.1 = -0.2).
    if (total_toys == 1 && b == 1) {
        ans2 = "Ya";
    } else if (total_toys > 1) {
        // To get negative: A+B > 0.
        // To get magnitude < 1:
        // If A+D=0 (all initial toys have magnitude < 1), then magnitude will always be < 1.
        // If A+D > 0, we can still get magnitude < 1. E.g., -2 * 0.1 = -0.2.
        // The only way to *not* get magnitude < 1 is if all toys have magnitude >= 1 (B=0, C=0).
        // If B=0 and C=0, then all toys are from Box 1 or Box 4. Product will always have magnitude >= 1.
        // So, if B+C > 0, it's possible to get magnitude < 1.
        if (a + b > 0 && b + c > 0) { // Need negative and possibility of magnitude < 1
            ans2 = "Ya";
        }
    }

    // Case 3: Final toy in Box 3 (positive, magnitude < 1)
    // Requires an even number of negative toys.
    // Requires all toys to have magnitude < 1, or a mix that results in magnitude < 1.
    if (total_toys == 1 && c == 1) {
        ans3 = "Ya";
    } else if (total_toys > 1) {
        // To get positive:
        // If A+B is even, we can achieve positive.
        // If A+B is odd, we can achieve positive if C+D > 0 (multiply by a positive toy).
        // So, if A+B is even OR (A+B is odd AND C+D > 0), we can get positive.
        // This simplifies to: if (A+B)%2 == 0 OR C+D > 0.
        // This is equivalent to: if not (A+B is odd AND C+D == 0).
        // This is equivalent to: if not (all toys are negative and A+B is odd).
        // So, if (A+B)%2 == 0 || c + d > 0, we can get positive.
        // To get magnitude < 1: B+C > 0.
        if (((a + b) % 2 == 0 || c + d > 0) && b + c > 0) {
            ans3 = "Ya";
        }
    }

    // Case 4: Final toy in Box 4 (positive, magnitude >= 1)
    // Requires an even number of negative toys.
    // Requires at least one toy with magnitude >= 1, or two toys with magnitude > 1.
    if (total_toys == 1 && d == 1) {
        ans4 = "Ya";
    } else if (total_toys > 1) {
        // To get positive: (a+b)%2 == 0 || c+d > 0.
        // To get magnitude >= 1: a+d > 0.
        if (((a + b) % 2 == 0 || c + d > 0) && a + d > 0) {
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

