    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append at most 3 elements.
        // Let's try to append 2 elements.
        // We want (current_sum + b1 + b2) = 2 * (current_xor ^ b1 ^ b2)
        // Let b1 = current_xor.
        // Then current_xor ^ b1 = current_xor ^ current_xor = 0.
        // The equation becomes (current_sum + current_xor + b2) = 2 * (0 ^ b2)
        // (current_sum + current_xor + b2) = 2 * b2
        // current_sum + current_xor = b2
        // So, b2 = current_sum + current_xor.

        long long b1 = current_xor;
        long long b2 = current_sum + current_xor;

        // Check if these two elements make the array good.
        // New sum = current_sum + b1 + b2
        // New xor = current_xor ^ b1 ^ b2
        // New sum = current_sum + current_xor + (current_sum + current_xor) = 2 * (current_sum + current_xor)
        // New xor = current_xor ^ current_xor ^ (current_sum + current_xor) = current_sum + current_xor
        // Is New sum = 2 * New xor?
        // 2 * (current_sum + current_xor) = 2 * (current_sum + current_xor)
        // Yes, it is.

        std::cout << 2 << std::endl;
        std::cout << b1 << " " << b2 << std::endl;
    }
}

