int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive actions
        if (i > j) { // More items from left than right
            // The last item taken must have been from the left.
            // The difference is i - j.
            // If i - j = 1, no extra penalty.
            // If i - j > 1, then (i - j - 1) times we took left consecutively after the right items were exhausted.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The last item taken must have been from the right.
            // The difference is j - i.
            // If j - i = 1, no extra penalty.
            // If j - i > 1, then (j - i - 1) times we took right consecutively after the left items were exhausted.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak for the decreasing suffix
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // Now a[p...n-1] is non-increasing.
    // If p is 0, the whole array is non-increasing.

    // Find the rightmost peak for the increasing suffix
    int q = p; // Start from p, as we are looking for a prefix to remove.
               // The remaining array starts at index `i`.
               // We need to find the first index `i` such that `a[i...n-1]` is good.
               // `p` is the first index from the right such that `a[p...n-1]` is non-increasing.
               // Any `a[i...n-1]` where `i > p` is also non-increasing.
               // So, `a[p...n-1]` is the longest non-increasing suffix.
               // We need to find the longest suffix `a[k...n-1]` that is good.
               // The answer will be `k`.

    // The logic for finding `p` and `q` is to identify the "bad" part.
    // The array `a[i...n-1]` is good if it can be formed by picking elements from ends
    // to make a non-decreasing sequence.
    // This implies that the elements must form a "valley" shape, or a "mountain" shape
    // if we consider the elements picked from ends.
    // More precisely, if we pick elements from ends, the remaining elements must be
    // non-decreasing from left to right, or non-increasing from left to right.
    // The problem statement's example `[1, 2, 3, 4, 4, 2, 1]` is good.
    // The elements `[3, 4, 4]` are the "middle" part.
    // The elements `[1, 2]` are from the left, `[2, 1]` are from the right.
    // The elements picked are `1, 1, 2, 2, 3, 4, 4`.
    // This means the elements that are *not* picked yet must be monotonic.
    // The elements that are picked from the ends must be such that the first picked is smallest, last picked is largest.
    // This implies that the elements in the middle of the array must be larger than or equal to elements at the ends.
    // The structure of a good array `b` is that it can be split into two monotonic parts:
    // `b_1, ..., b_k` and `b_{k+1}, ..., b_m`.
    // The first part `b_1, ..., b_k` is non-decreasing.
