// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        return "0"; // Special case for 0
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern_str += '0';
        } else {
            pattern_str += '1';
        }
        n /= 10;
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Digits were processed right-to-left, reverse to get standard order
    return pattern_str;
}

