        std::cin >> type;
        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern_key = get_parity_pattern(a);
            pattern_key = normalize_pattern(pattern_key);
            counts[pattern_key]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern_key = get_parity_pattern(a);
            pattern_key = normalize_pattern(pattern_key);
            counts[pattern_key]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            std::string query_key = normalize_pattern(s);
            std::cout << counts[query_key] << "\n";
        }
    }

    return 0;
}

