#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited;
    char start_char = '\0';

    // Find a starting character for a path (degree 1)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no degree 1 node found, check for isolated nodes or cycles
    if (start_char == '\0') {
        for (char c = 'a'; c <= 'z'; ++c) {
            if (adj.count(c) && adj[c].size() == 0) { // Isolated node that appeared in password
                start_char = c;
                break;
            }
        }
    }

    // If still no start_char, it means all nodes in adj have degree 2 (a cycle)
    // or all nodes in adj have degree 0 (password was length 1, or empty, but length >= 1)
    // If password length is 1, s[0] is the start_char.
    // If password length > 1 and all nodes have degree 2, it's a cycle.
    // We can pick any character from adj as a start for a cycle.
    if (start_char == '\0' && !adj.empty()) {
        start_char = adj.begin()->first;
    } else if (start_char == '\0' && adj.empty()) { // Password length 1
        start_char = s[0];
    }


    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the previous character

        while (visited.find(current) == visited.end()) {
            layout += current;
            visited.insert(current);

            char next_char = '\0';
            if (adj.count(current)) {
                for (char neighbor : adj[current]) {
                    if (neighbor != prev) {
                        next_char = neighbor;
                        break;
                    }
                }
            }

            if (next_char == '\0') { // End of path or isolated node
                break;
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters involved in the password have been added to the layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && visited.find(c) == visited.end()) {
            // This means there's another connected component (another path or cycle)
            // that couldn't be connected to the first one.
            // This implies multiple paths/cycles, which is impossible for a single row.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

