    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val;
    if (b == 1) { // If b=1, r must be 0, but r!=0. So no nice integers.
        sum_r_val = 0;
    } else {
        sum_r_val = (b - 1);
        sum_r_val = (sum_r_val * b) / 2;
    }

    // Sum of (k * b + 1) from k=1 to a:
    // sum_{k=1 to a} (k * b + 1) = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    // This is sum_kb_plus_1_val
    long long sum_kb_plus_1_val;
    long long sum_k_val = (a * (a + 1)) / 2;

    sum_kb_plus_1_val = (b % MOD * (sum_k_val % MOD)) % MOD;
    sum_kb_plus_1_val = (sum_kb_plus_1_val + (a % MOD)) % MOD;

    // Total sum = (sum_r_val % MOD) * (sum_kb_plus_1_val % MOD) % MOD
    long long total_sum = (sum_r_val % MOD * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // Iterate through all possible pivot digits (0-9)
        std::vector<int> color1_digits;
        std::vector<int> color2_digits;
        std::string current_result(n, ' ');
        bool possible_for_p = true;

        // First pass: assign digits < p to color 1, digits > p to color 2
        // Digits == p are temporarily unassigned (marked with '0')
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                current_result[i] = '1';
                color1_digits.push_back(digit);
            } else if (digit > p) {
                current_result[i] = '2';
                color2_digits.push_back(digit);
            } else { // digit == p
                current_result[i] = '0'; // Placeholder for digits equal to p
            }
        }

        // Check if color1_digits is sorted
        for (size_t i = 0; i + 1 < color1_digits.size(); ++i) {
            if (color1_digits[i] > color1_digits[i+1]) {
                possible_for_p = false;
                break;
            }
        }
        if (!possible_for_p) continue;

        // Check if color2_digits is sorted
        for (size_t i = 0; i + 1 < color2_digits.size(); ++i) {
            if (color2_digits[i] > color2_digits[i+1]) {
                possible_for_p = false;
                break;
            }
        }
        if (!possible_for_p) continue;

        // Second pass: assign digits == p
        // All digits 'p' that appear BEFORE the first 'p' assigned to color 2, must be color 1.
        // All digits 'p' that appear AFTER the last 'p' assigned to color 1, must be color 2.
        // This means there's a split point for 'p's.
        // We can assign all 'p's up to a certain point to color 1, and the rest to color 2.
        // The simplest way to ensure this is to assign 'p's greedily.
        // All 'p's that come before any 'p' assigned to color 2, should be color 1.
        // All 'p's that come after any 'p' assigned to color 1, should be color 2.
        // This is equivalent to finding the first 'p' that we assign to color 2.
        // All 'p's before it are color 1, all 'p's after it are color 2.

        // Find the first 'p' that should be colored 2.
        // This 'p' must be greater than or equal to the last digit in color1_digits.
        // Since all digits in color1_digits are < p, this condition is always met for 'p'.
        // This 'p' must also be less than or equal to the first digit in color2_digits.
        // Since all digits in color2_digits are > p, this condition is always met for 'p'.

        // The only constraint for 'p's is that they maintain the non-decreasing order within their respective colors.
        // For digits equal to 'p', we can assign them to color 1 as long as the previous digit in color 1 was <= 'p'.
        // And assign them to color 2 as long as the previous digit in color 2 was <= 'p'.
        // The critical point is the transition from color 1 to color 2.
        // We want to find the "split point" for digits equal to 'p'.
        // All 'p's before this split point go to color 1, all 'p's after go to color 2.

        // Let's try a simpler greedy approach for 'p's:
        // Assign 'p' to color 1 if it doesn't violate the non-decreasing property of color 1.
        // Otherwise, assign it to color 2 if it doesn't violate the non-decreasing property of color 2.
        // This is tricky because we need to ensure the last_1 <= first_2 condition.

        // A more robust approach:
        // Find the rightmost 'p' that can be colored 1.
        // Find the leftmost 'p' that can be colored 2.
        // All 'p's before the leftmost 'p' colored 2 must be 1.
        // All 'p's after the rightmost 'p' colored 1 must be 2.
        // If there's an overlap, it's fine.

        // Let's try to find the first index `k` such that `s[k] == p` and we assign `s[k]` to color 2.
        // All `s[i] == p` for `i < k` are assigned to color 1.
        // All `s[i] == p` for `i >= k` are assigned to color 2.
        // If no `s[i] == p` is assigned to color 2, all `p`s are color 1.
        // If no `s[i] == p` is assigned to color 1, all `p`s are color 2.

        // This means we can iterate through all possible split points for digits equal to 'p'.
        // The split point can be before the first 'p', between any two 'p's, or after the last 'p'.
        // This is equivalent to saying: find the first 'p' that we assign to color 2.
        // All 'p's before it are color 1, all 'p's from it onwards are color 2.
        // If all 'p's are color 1, then the split point is after the last 'p'.
        // If all 'p's are color 2, then the split point is before the first 'p'.

        // Let's try to assign all 'p's to color 1 first, then check validity.
        // If valid, this is a solution.
        // If not, then some 'p's must be color 2.
        // The problem is that we need to find *any* valid coloring.

        // The simplest strategy for 'p's:
        // All 'p's that appear before the first digit > p are colored 1.
        // All 'p's that appear after the last digit < p are colored 2.
        // This is not quite right.

        // Correct strategy for 'p's:
        // Find the first occurrence of a digit `d_i` such that `d_i > p`.
        // All `d_j = p` for `j < i` must be colored 1.
        // Find the last occurrence of a digit `d_i` such that `d_i < p`.
        // All `d_j = p` for `j > i` must be colored 2.
        // This is still not quite right.

        // The condition is: last_digit_color1 <= first_digit_color2.
        // If we assign all `d_i < p` to color 1, and all `d_i > p` to color 2.
        // Then `last_digit_color1` will be at most `p-1`.
        // And `first_digit_color2` will be at least `p+1`.
        // So `p-1 <= p+1` is always true.
        // The problem is with digits equal to `p`.

        // Let's try to find the "split point" for digits equal to `p`.
        // All `d_i = p` before index `k` are colored 1.
        // All `d_i = p` at or after index `k` are colored 2.
        // We need to find such a `k` (or if all `p`s are 1, or all `p`s are 2).

        // Let `last1` be the last digit assigned to color 1 so far.
        // Let `last2` be the last digit assigned to color 2 so far.
        // Initialize `last1 = -1`, `last2 = -1`. (or 0, 0 if digits can be 0)
        // Digits are 0-9. So `last1 = -1`, `last2 = -1` is fine.

        int current_last1 = -1;
        int current_last2 = -1;
        bool possible_this_p_split = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                if (digit < current_last1) { possible_this_p_split = false; break; }
                current_result[i] = '1';
                current_last1 = digit;
            } else if (digit > p) {
                if (digit < current_last2) { possible_this_p_split = false; break; }
                if (current_last1 != -1 && digit < current_last1) { possible_this_p_split = false; break; } // This is the critical check: last_1 <= first_2
                current_result[i] = '2';
                current_last2 = digit;
            } else { // digit == p
                // Try to assign to color 1
                if (digit >= current_last1) {
                    current_result[i] = '1';
                    current_last1 = digit;
                } else { // Cannot assign to color 1, must assign to color 2
                    if (digit < current_last2) { possible_this_p_split = false; break; }
                    current_result[i] = '2';
                    current_last2 = digit;
                }
            }
        }

        if (possible_this_p_split) {
            // Final check: if color1_digits is not empty and color2_digits is not empty,
            // then max(color1_digits) <= min(color2_digits).
            // This is implicitly handled by `if (current_last1 != -1 && digit < current_last1)`
            // when `digit` is assigned to color 2.
            found_solution = true;
            result = current_result;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

