    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <iomanip>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        const std::vector<int>& possible_k_for_char = char_indices[char_code];
        if (possible_k_for_char.empty()) {
            continue;
        }

        // If only one k is possible for this char, Vasya wins for sure.
        if (possible_k_for_char.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // Otherwise, Vasya needs to choose a position p.
        // Iterate through all possible positions p (from 1 to n-1).
        // p=0 is not allowed as it's the first letter already revealed.
        double max_win_prob_for_char = 0.0;

        for (int p = 1; p < n; ++p) {
            // For a fixed p, count how many k values lead to a unique (t[0], t[p]) pair.
            // t[0] = s[k] (which is char_code)
            // t[p] = s[(k + p) % n]

            // Group k values by the character s[(k+p)%n]
            std::vector<std::vector<int>> groups_by_second_char(26);
            for (int k_val : possible_k_for_char) {
                groups_by_second_char[s[(k_val + p) % n] - 'a'].push_back(k_val);
            }

            int unique_k_count_for_p = 0;
            for (const auto& group : groups_by_second_char) {
                if (group.size() == 1) {
                    unique_k_count_for_p++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)unique_k_count_for_p / possible_k_for_char.size());
        }
        total_win_prob += max_win_prob_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

