void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance for the whole array
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Map to store the minimum number of jars eaten from the left
    // to achieve a certain balance.
    // balance -> jars_eaten_left
    std::map<int, int> left_balances;
    left_balances[0] = 0; // 0 jars eaten from left, balance is 0

    int current_balance_left = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        // We want to find the minimum jars eaten to achieve a balance.
        // Since we iterate from n-1 down to 0, the first time we see a balance,
        // it corresponds to the minimum jars eaten (n-1-i+1).
        if (left_balances.find(current_balance_left) == left_balances.end()) {
            left_balances[current_balance_left] = (n - i);
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Case 1: No jars eaten from the right.
    // We need to find if initial_balance can be achieved by eating only from left.
    // This means current_balance_left should be equal to initial_balance.
    // The number of jars eaten from left would be left_balances[initial_balance].
    // If initial_balance is 0, 0 jars are eaten.
    if (left_balances.count(initial_balance)) {
        min_jars_eaten = std::min(min_jars_eaten, left_balances[initial_balance]);
    }

    // Iterate through jars eaten from the right
    int current_balance_right = 0;
    for (int k_R = 1; k_R <= n; ++k_R) {
        int jar_idx = n + k_R - 1; // Current jar being eaten from right
        if (a[jar_idx] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }

        // The target balance for the remaining jars (after eating k_R from right)
        // is initial_balance - current_balance_right.
        // We need to find if this target balance can be achieved by eating from left.
        int target_balance_left = initial_balance - current_balance_right;

        if (left_balances.count(target_balance_left)) {
            min_jars_eaten = std::min(min_jars_eaten, k_R + left_balances[target_balance_left]);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

