    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current state for each bit
    // For each bit position (0-9):
    // bit_val[i] = 0 means if input bit is 0, output bit is 0
    // bit_val[i] = 1 means if input bit is 0, output bit is 1
    // bit_val[i] = 2 means if input bit is 1, output bit is 0
    // bit_val[i] = 3 means if input bit is 1, output bit is 1
    // This can be simplified:
    // For each bit i, we track two values:
    // val_0[i]: what the i-th bit becomes if the input i-th bit is 0
    // val_1[i]: what the i-th bit becomes if the input i-th bit is 1
    std::vector<int> val_0(10); // Initial state: if input bit is 0, output is 0
    std::vector<int> val_1(10); // Initial state: if input bit is 1, output is 1

    for (int i = 0; i < 10; ++i) {
        val_0[i] = 0;
        val_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int i = 0; i < 10; ++i) {
            int bit_x = (x >> i) & 1;
            if (op_char == '&') {
                val_0[i] &= bit_x;
                val_1[i] &= bit_x;
            } else if (op_char == '|') {
                val_0[i] |= bit_x;
                val_1[i] |= bit_x;
            } else { // '^'
                val_0[i] ^= bit_x;
                val_1[i] ^= bit_x;
            }
        }
    }

    // Now, reconstruct the operations
    // We need to find A, B, C such that:
    // ( ( (input & A) | B ) ^ C )
    // For each bit i:
    // If input_bit is 0: ( (0 & A_i) | B_i ) ^ C_i = val_0[i]
    // If input_bit is 1: ( (1 & A_i) | B_i ) ^ C_i = val_1[i]

    // Let's find A, B, C bit by bit
    int final_and_val = 1023; // All bits 1
    int final_or_val = 0;     // All bits 0
    int final_xor_val = 0;    // All bits 0

    for (int i = 0; i < 10; ++i) {
        if (val_0[i] == 0 && val_1[i] == 0) {
            // Both 0 -> 0. This means input bit must be ANDed with 0.
            // (x_i & 0) | 0 ^ 0 = 0
            // (x_i & 0) | 1 ^ 1 = 0
            // (x_i & 1) | 0 ^ 1 = 0
            // (x_i & 1) | 1 ^ 0 = 0
            // The simplest way to achieve this is to force the bit to 0.
            // This can be done by ANDing with 0.
            final_and_val &= ~(1 << i); // Set A_i to 0
            // B_i and C_i can be 0
        } else if (val_0[i] == 1 && val_1[i] == 1) {
            // Both 1 -> 1. This means input bit must be ORed with 1.
            // (x_i & 1) | 1 ^ 0 = 1
            // (x_i & 0) | 1 ^ 0 = 1
            // The simplest way to achieve this is to force the bit to 1.
            // This can be done by ORing with 1.
            final_or_val |= (1 << i); // Set B_i to 1
            // A_i can be 1, C_i can be 0
        } else if (val_0[i] == 0 && val_1[i] == 1) {
            // 0 -> 0, 1 -> 1. This means the bit is unchanged.
            // (x_i & 1) | 0 ^ 0 = x_i
            // A_i = 1, B_i = 0, C_i = 0
            // No change to final_and_val, final_or_val, final_xor_val for this bit
        } else { // val_0[i] == 1 && val_1[i] == 0
            // 0 -> 1, 1 -> 0. This means the bit is flipped.
            // (x_i & 1) | 0 ^ 1 = ~x_i
            // A_i = 1, B_i = 0, C_i = 1
            final_xor_val |= (1 << i); // Set C_i to 1
            // No change to final_and_val, final_or_val for this bit
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_val != 1023) { // If any bit of A is 0
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If any bit of B is 1
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If any bit of C is 1
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[i] to a very large value.
    // This represents the upper bound for a_0[i] based on Type 2 operations.
    // If a_0[i] is too large, it will violate some max constraint.
    // We want to find the largest possible a_0[i] that satisfies all constraints.
    // The maximum possible value for a_0[i] is 10^9.
    std::vector<long long> initial_a(n, 2000000000LL); // A value larger than 10^9, but not LLONG_MAX

    // Iterate operations in reverse to determine initial_a bounds
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If we add d to a range [l, r], then to maintain the current
            // upper bound for a_0[j], we must subtract d from it.
            // This is because a_0[j] + sum_d_up_to_this_op <= current_bound.
            // So, a_0[j] <= current_bound - sum_d_up_to_this_op.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // For a type 2 operation (max(a[l...r]) = m), it implies that
            // for all j in [l, r], a_current[j] <= m.
            // This means a_0[j] + sum_d_up_to_this_op <= m.
            // So, a_0[j] <= m - sum_d_up_to_this_op.
            // We update the upper bound for a_0[j] with this new constraint.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val);
            }
        }
    }

    // Now we have a candidate initial_a.
    // We need to verify if it satisfies all constraints.
    // Specifically, for Type 2 operations, max(a_current[l...r]) must be exactly m.
    // Our construction ensures a_current[j] <= m for all j in [l, r].
    // We need to check if there exists at least one k in [l, r] such that a_current[k] = m.

    // Simulate operations with the found initial_a to get the final array state
    std::vector<long long> current_a = initial_a;
    std::vector<long long> diff_array(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Apply type 1 operations to the diff_array
            diff_array[op.l] += op.val;
            if (op.r + 1 < n) {
                diff_array[op.r + 1] -= op.val;
            }
        } else { // op.type == 2
            // Calculate current_a values for the range [l, r] and check max
            long long current_sum_d = 0;
            long long max_val_in_range = LLONG_MIN;
            for (int j = 0; j < n; ++j) {
                current_sum_d += diff_array[j];
                if (j >= op.l && j <= op.r) {
                    max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_sum_d);
                }
            }

            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only b_1=a_1, b_n=a_n rules apply)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n), R(n);

    // Calculate L[i]: minimum distance from i to a 0 on its left (inclusive)
    // L[i] = 0 if a[i] = 0
    // L[i] = L[i-1] + 1 if a[i] = 1 and i > 0
    // L[0] = 0 if a[0] = 0, else infinity (or a large number)
    L[0] = (a[0] == 0) ? 0 : n + 1; // Use n+1 as infinity for distances up to n

    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = 0;
        } else {
            L[i] = L[i - 1] + 1;
        }
    }

    // Calculate R[i]: minimum distance from i to a 0 on its right (inclusive)
    // R[i] = 0 if a[i] = 0
    // R[i] = R[i+1] + 1 if a[i] = 1 and i < n-1
    // R[n-1] = 0 if a[n-1] = 0, else infinity
    R[n - 1] = (a[n - 1] == 0) ? 0 : n + 1;

    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = 0;
        } else {
            R[i] = R[i + 1] + 1;
        }
    }

    int max_dist_to_zero = 0;
    for (int i = 0; i < n; ++i) {
        max_dist_to_zero = std::max(max_dist_to_zero, std::min(L[i], R[i]));
    }

    // If max_dist_to_zero is n+1, it means there are no zeros in the sequence.
    // In this case, the sequence is all 1s, which is stable.
    // The max_dist_to_zero calculation would yield n+1 for all elements,
    // so max_dist_to_zero would be n+1.
    // However, the problem states n >= 3. If all are 1s, it's stable.
    // The logic below handles this correctly: if max_dist_to_zero is 0, steps = 0.
    // If all are 1s, L[i] and R[i] will be n+1 for all i.
    // min(L[i], R[i]) will be n+1. max_dist_to_zero will be n+1.
    // (n+1)/2 = (n/2) + 1/2. For integer division, it's n/2.
    // This means if all are 1s, steps = n/2. This is incorrect.
    // If all are 1s, it's stable, 0 steps.
    // Let's refine max_dist_to_zero: it should be the maximum distance for a 1 to become 0.
    // A 1 at index i becomes 0 if L[i] >= k and R[i] >= k for some k.
    // The value of a[i] becomes 0 if it's surrounded by 0s within distance k.
    // The value of a[i] becomes 1 if it's surrounded by 1s within distance k.
    // The problem is about 1s turning into 0s.
    // A 1 at index i turns into 0 if a[i-1]=0 and a[i+1]=0.
    // This means L[i-1]=0 and R[i+1]=0.
    // The value of a[i] becomes 0 if it's a 1 and its neighbors are 0.
    // The value of a[i] becomes 1 if it's a 0 and its neighbors are 1.
    // The key observation is that 0s expand, and 1s shrink.
    // A 1 at index i will eventually become 0 if it is "closer" to a 0 than to a 1.
    // Specifically, if min(L[i], R[i]) is the distance to the nearest 0.
    // If a[i] is 1, and L[i] = k, R[i] = m.
    // It means there's a 0 at i-k and a 0 at i+m.
    // The value a[i] will become 0 if k and m are large enough.
    // The number of steps is ceil(max_dist_to_zero / 2.0).
    // If max_dist_to_zero is 0, it means all elements are 0, or the sequence is stable.
    // If all elements are 1, then L[i] and R[i] are n+1 for all i.
    // min(L[i], R[i]) is n+1. max_dist_to_zero is n+1.
    // This implies (n+1)/2 steps. This is wrong for all 1s.
    // The definition of L[i] and R[i] is distance to nearest 0.
    // If there are no 0s, L[i] and R[i] should be effectively infinity.
    // Let's check if there are any 0s.
    bool has_zero = false;
    for (int x : a) {
        if (x == 0) {
            has_zero = true;
            break;
        }
    }

    if (!has_zero) { // All 1s sequence
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << 1 << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // The number of steps is max_dist_to_zero / 2 (integer division)
    // if max_dist_to_zero is the maximum of min(L[i], R[i]) for all i where a[i]=1.
    // If a[i]=0, then min(L[i], R[i]) = 0.
    // So max_dist_to_zero is effectively the maximum distance from any 1 to its nearest 0.
    int steps = max_dist_to_zero / 2;

    std::vector<int> b(n);
    for (int i = 0; i < n; ++i) {
        if (L[i] <= steps && R[i] <= steps) {
            // If a[i] is within 'steps' distance from a 0 on both sides, it becomes 0.
            // This is the condition for a 1 to become 0.
            // If a[i] is already 0, L[i]=0, R[i]=0, so it stays 0.
            b[i] = 0;
        } else if (L[i] > steps && R[i] > steps) {
            // If a[i] is further than 'steps' from any 0 on both sides, it becomes 1.
            // This is the condition for a 0 to become 1, or a 1 to stay 1.
            b[i] = 1;
        } else {
            // This is the tricky part. If L[i] <= steps and R[i] > steps, or vice versa.
            // This means it's closer to a 0 on one side, but further from a 0 on the other.
            // This implies it's on the "boundary" of a region that will turn to 0.
            // The value of b[i] will be 0 if it's closer to a 0.
            // The value of b[i] will be 1 if it's closer to a 1.
            // The rule is: b[i] = 0 if min(L[i], R[i]) <= steps.
            // Otherwise, b[i] = 1.
            // This is equivalent to: b[i] = (min(L[i], R[i]) > steps) ? 1 : 0;
            // The previous if-else if covers this:
            // if (L[i] <= steps && R[i] <= steps) -> min(L[i], R[i]) <= steps -> b[i]=0
            // if (L[i] > steps && R[i] > steps) -> min(L[i], R[i]) > steps -> b[i]=1
            // The remaining case is (L[i] <= steps && R[i] > steps) or (L[i] > steps && R[i] <= steps).
            // In both these cases, min(L[i], R[i]) <= steps. So b[i] should be 0.
            // This means the logic should be: b[i] = (min(L[i], R[i]) > steps) ? 1 : 0;
            b[i] = 0; // This covers the case where one side is <= steps and other is > steps.
                      // e.g., L[i]=1, R[i]=5, steps=2. min(1,5)=1 <= 2. So b[i]=0.
        }
    }

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * 2 * max(a_i) which is 2*10^5 * 2 * 10^9 = 4*10^14.
// x is an index, so it fits in int.

// dp[i][0] stores the final x value if starting at index i with an "add" step.
// dp[i][1] stores the final y value if starting at index i with an "add" step.
// dp[i][2] stores the final x value if starting at index i with a "subtract" step.
// dp[i][3] stores the final y value if starting at index i with a "subtract" step.
// We use -1 for x values to indicate termination or non-termination.
// For y values, -1 indicates non-termination.
std::vector<std::vector<long long>> dp;
std::vector<bool> visited; // To detect cycles (non-termination)
std::vector<bool> visiting; // To detect cycles during DFS

int N;
std::vector<long long> A_vals; // 0-indexed, A_vals[0] is a_1, A_vals[i] is a_{i+1}

// Function to solve for a given starting index and operation type
// type = 0 for "add" step, type = 1 for "subtract" step
void solve(int current_x, int type) {
    if (current_x <= 0 || current_x > N) {
        // Terminated
        dp[current_x][0] = current_x;
        dp[current_x][1] = 0;
        dp[current_x][2] = current_x;
        dp[current_x][3] = 0;
        return;
    }

    if (visited[current_x]) {
        // Already computed
        return;
    }

    if (visiting[current_x]) {
        // Cycle detected, non-terminating
        dp[current_x][0] = -1;
        dp[current_x][1] = -1;
        dp[current_x][2] = -1;
        dp[current_x][3] = -1;
        return;
    }

    visiting[current_x] = true;

    long long val_at_x = A_vals[current_x - 1]; // a_x

    // Case 1: Start with "add" step (type 0)
    long long next_x_add = current_x + val_at_x;
    long long y_increase_add = val_at_x;

    // The next step is "subtract"
    solve(next_x_add, 1); // Recursively solve for the next state

    if (dp[next_x_add][2] == -1) { // If the subsequent path is non-terminating
        dp[current_x][0] = -1;
        dp[current_x][1] = -1;
    } else {
        dp[current_x][0] = dp[next_x_add][2];
        dp[current_x][1] = y_increase_add + dp[next_x_add][3];
    }

    // Case 2: Start with "subtract" step (type 1)
    long long next_x_sub = current_x - val_at_x;
    long long y_increase_sub = val_at_x;

    // The next step is "add"
    solve(next_x_sub, 0); // Recursively solve for the next state

    if (dp[next_x_sub][0] == -1) { // If the subsequent path is non-terminating
        dp[current_x][2] = -1;
        dp[current_x][3] = -1;
    } else {
        dp[current_x][2] = dp[next_x_sub][0];
        dp[current_x][3] = y_increase_sub + dp[next_x_sub][1];
    }

    visiting[current_x] = false;
    visited[current_x] = true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A_vals.resize(N);
    // a_1 is set by the loop, a_2 to a_n are read
    for (int i = 1; i < N; ++i) {
        std::cin >> A_vals[i];
    }

    // Initialize DP table. Size N+2 to handle x=0 and x=N+1 boundary conditions.
    // dp[x][0]: final x if starting at x with add
    // dp[x][1]: final y if starting at x with add
    // dp[x][2]: final x if starting at x with subtract
    // dp[x][3]: final y if starting at x with subtract
    dp.assign(N + 2, std::vector<long long>(4, 0));
    visited.assign(N + 2, false);
    visiting.assign(N + 2, false);

    // Pre-calculate for all possible x values (1 to N)
    // We need to call solve for each x from 1 to N, for both starting types.
    // The loop below ensures all states are computed.
    for (int i = 1; i <= N; ++i) {
        if (!visited[i]) {
            solve(i, 0); // Compute starting with add
            solve(i, 1); // Compute starting with subtract
        }
    }

    for (int i = 1; i < N; ++i) {
        A_vals[0] = i; // Set a_1 = i for this run

        // Initial state: x = 1, y = 0. First step is "add".
        // We need to find the result of starting at x=1 with an "add" step.
        // This is stored in dp[1][0] (final x) and dp[1][1] (final y).

        // The total y value is A_vals[0] (from the first add step) + the y accumulated from the rest of the path.
        // The final y value from dp[1][1] already includes the A_vals[0] from the first step.
        // So, if dp[1][1] is -1, it's non-terminating. Otherwise, it's the answer.
        std::cout << dp[1][1] << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    return std::count(s.begin(), s.end(), '1');
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If ones_a is odd, we can append a '1'. This makes ones_a + 1.
    // If ones_a is even, we can append a '0'. This keeps ones_a the same.
    // In both cases, the new string will have an even number of ones.
    // So, the maximum number of ones we can achieve is ones_a + (ones_a % 2).
    // After that, any further append operation will add a '0' (since parity is 0),
    // and the number of ones will remain constant.
    int max_ones_a = ones_a + (ones_a % 2);

    if (max_ones_a >= ones_b && a.length() <= b.length()) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_idx);
