int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // dp[i] will store the maximum 'r' such that s[i..r] contains no bad triplets.
    // Or, more precisely, dp[i] stores the minimum 'r_prime' such that s[i..r_prime]
    // contains a bad triplet starting at or after index i.
    // If no such r_prime exists, dp[i] can be n+1.
    // The length of a valid substring starting at i is dp[i] - i.
    // The number of valid (l,r) pairs starting at l=i is (dp[i] - i).
    std::vector<int> dp(n + 1, n + 1); 

    // Iterate backwards to fill dp array
    for (int i = n - 1; i >= 0; --i) {
        dp[i] = dp[i+1]; // Initialize with value from i+1, meaning no new bad triplet found yet for current i

        // Check for k=1
        if (i + 2 < n && s[i] == s[i+1] && s[i+1] == s[i+2]) {
            dp[i] = std::min(dp[i], i + 2 + 1); // The first r that makes s[i..r] invalid is i+2. So r_prime is i+2+1.
        }
        // Check for k=2
        if (i + 4 < n && s[i] == s[i+2] && s[i+2] == s[i+4]) {
            dp[i] = std::min(dp[i], i + 4 + 1); // The first r that makes s[i..r] invalid is i+4. So r_prime is i+4+1.
        }
        // Check for k=3
        if (i + 6 < n && s[i] == s[i+3] && s[i+3] == s[i+6]) {
            dp[i] = std::min(dp[i], i + 6 + 1); // The first r that makes s[i..r] invalid is i+6. So r_prime is i+6+1.
        }

        // For any other k, the maximum possible value for 2k is n-1-i.
        // If i is small, 2k can be large.
        // However, the problem constraints on k are 1 <= k <= n.
        // The maximum length of a bad triplet is 2k+1.
        // If 2k+1 is large, say 2k+1 > 7, then the substring s[i..i+2k] is long.
        // Any substring s[l..r] that contains s[i..i+2k] will also contain s[i..i+6] if 2k >= 6.
        // This means if a bad triplet (i, k) exists with k >= 3, then the substring s[i..i+2k]
        // is long enough to contain a bad triplet (i', k') with k' <= 3.
        // For example, if s[i]=s[i+k]=s[i+2k] and k >= 4, then s[i..i+2k] contains s[i..i+6]
        // as a prefix. If s[i..i+6] itself contains a bad triplet, then dp[i] would be updated
        // by that smaller triplet.
        // The only case where a large k triplet (i, k) could be the *first* bad triplet
        // in s[i..r] is if all smaller k triplets starting at i, i+1, i+2, ... are not bad.
        //
        // Consider the maximum possible value for 2k.
        // If 2k >= 7, then the length of the pattern is at least 8.
        // For example, if s[i]=s[i+4]=s[i+8], then the substring s[i..i+8] is involved.
        // Any substring s[l..r] that contains s[i..i+8] will also contain s[i..i+6].
        // If s[i..i+6] does not contain a bad triplet, then s[i..i+8] might be the first.
        //
        // Let's analyze the maximum relevant k.
        // If s[x] = s[x+k] = s[x+2k], then the length of this pattern is 2k+1.
        // If 2k+1 >= 7, i.e., k >= 3, then the pattern is s[x]...s[x+2k].
        // If k=3, pattern is s[x], s[x+3], s[x+6]. Length 7.
        // If k=4, pattern is s[x], s[x+4], s[x+8]. Length 9.
        // If k=5, pattern is s[x], s[x+5], s[x+10]. Length 11.
        // If k=6, pattern is s[x], s[x+6], s[x+12]. Length 13.
        //
        // The crucial observation is that if s[x] = s[x+k] = s[x+2k] for some k >= 4,
        // then the substring s[x..x+2k] is long enough to contain a shorter bad triplet.
        // Specifically, if s[x] = s[x+k] = s[x+2k] and k >= 4, then the substring s[x..x+2k]
        // has length at least 9.
        // Any substring of length 9 or more must contain a bad triplet of type (x', k') with k' <= 3.
        // This is a known property for binary strings.
        // For example, if a binary string has length 9 and contains no 000, 111, 01010, 10101, 00100100, 11011011, etc.
        // This is related to "avoidable patterns".
        // A simpler argument: if s[i] = s[i+k] = s[i+2k] for k >= 4, then the first index that makes s[i..r] invalid is i+2k.
        // However, if there is *any* bad triplet (x', k') such that x' >= i and x'+2k' < i+2k, then dp[i] would be updated by that.
        // The maximum length of a string that does not contain any bad triplet is 6.
        // For example, 001100 or 110011.
        // If a string has length 7, it must contain a bad triplet.
        // Example: 0011001. s[0]=s[1]=0. s[4]=s[5]=0. s[0]=s[3]=s[6]=0. (k=3)
        // Example: 0101010. s[0]=s[2]=s[4]=0. (k=2) s[1]=s[3]=s[5]=1. (k=2)
        // Example: 000... (k=1)
        //
        // So, if dp[i] is updated by a triplet (i, k) where k >= 4, it means that
        // s[i..i+2k] is the *first* substring starting at i that contains a bad triplet.
        // This implies that s[i..i+2k-1] contains no bad triplets.
        // If 2k-1 >= 7, this is a contradiction.
        // So, 2k-1 < 7, which means 2k < 8, so k < 4.
        // Thus, we only need to check k=1, k=2, k=3.
        // This optimization is crucial for N=300,000.

        invalid_pairs += (n - dp[i] + 1);
    }

    long long valid_pairs = total_pairs - invalid_pairs;
    std::cout << valid_pairs << std::endl;

    return 0;
}

