        //   If `h_i` can reach `p_j` (i.e., `abs(h_i - p_j) <= T`):
        //     Then `h_i` can cover the range `[p_j, p_j + (T - abs(h_i - p_j))]`.
        //     Advance `p_idx` past all `p_k` that fall into this range.
        //   Else (`h_i` cannot reach `p_j`):
        //     This head is too far to the right to cover `p_j` (i.e., `p_j < h_i - T`).
        //     Or too far to the left (i.e., `p_j > h_i + T`).
        //     If `p_j < h_i - T`, it means `p_j` is to the left of the leftmost point `h_i` can reach.
        //     This implies that `p_j` should have been covered by a previous head.
        //     If it wasn't, then it's impossible.
        //     So, if `p_j < h_i - T`, return false.
        //     If `p_j > h_i + T`, then `h_i` cannot reach `p_j`. We need to use the next head.
        //     This means the current head `h_i` is not useful for `p_j` or any `p_k` to its right.
        //     So, we just move to the next head.

        // Let's refine the greedy strategy:
        // `p_idx` points to the first target track not yet covered.
        // For each head `h[h_idx]`:
        //   If `p_idx == m`, all tracks are covered, return true.
        //   Calculate the range this head can cover: `[h[h_idx] - T, h[h_idx] + T]`.
        //   If `p[p_idx]` is to the left of `h[h_idx] - T`:
        //     This means `p[p_idx]` cannot be covered by `h[h_idx]`.
        //     Since `p` is sorted and `h` is sorted, `p[p_idx]` is too far left for `h[h_idx]`
        //     and any subsequent head `h[h_idx+1]`, `h[h_idx+2]`, etc.
        //     Thus, `p[p_idx]` must have been covered by a previous head.
        //     If it wasn't, then it's impossible. So, return false.
        //   If `p[p_idx]` is within `[h[h_idx] - T, h[h_idx] + T]`:
        //     This head can cover `p[p_idx]`.
        //     To maximize coverage to the right, this head should move to `p[p_idx]`
        //     and then sweep right. The rightmost point it can reach is `p[p_idx] + (T - abs(h[h_idx] - p[p_idx]))`.
        //     Let `effective_max_reach = p[p_idx] + (T - std::abs(h[h_idx] - p[p_idx]))`.
        //     Advance `p_idx` past all `p_k` such that `p_k <= effective_max_reach`.
        //   Else (`p[p_idx]` is to the right of `h[h_idx] + T`):
        //     This head cannot reach `p[p_idx]`. We must use a later head.
        //     So, this head `h[h_idx]` is effectively "skipped" for covering `p[p_idx]` and beyond.
        //     We continue to the next head `h[h_idx+1]`.
        //     This is the tricky part. If `h[h_idx]` cannot reach `p[p_idx]`, it might be able to cover some `p_k`
        //     that is to its left, but still to the right of `p[p_idx-1]`.
        //     But we are trying to cover `p[p_idx]`, the leftmost *uncovered* track.
        //     If `h[h_idx]` cannot cover `p[p_idx]`, it means `p[p_idx]` is too far right for `h[h_idx]`.
        //     So `h[h_idx]` cannot help with `p[p_idx]` or any `p_k` to its right.
        //     So we must use a later head. This head `h[h_idx]` is effectively wasted for the current `p_idx`.
        //     This is the correct logic for the "skip" case.

        // Let's re-evaluate the greedy strategy for `check(T)`:
        // `p_idx` points to the first target track not yet covered.
        // For each head `h[h_idx]` from left to right:
        //   If `p_idx == m`, all tracks are covered, return true.
        //   If `p[p_idx]` is to the left of `h[h_idx] - T`:
        //     This means `p[p_idx]` cannot be covered by `h[h_idx]` or any `h_k` where `k > h_idx`
        //     (because `h_k >= h[h_idx]`, so `h_k - T >= h[h_idx] - T`).
        //     Therefore, `p[p_idx]` must have been covered by a previous head.
        //     If it wasn't, then it's impossible. Return false.
        //   If `p[p_idx]` is to the right of `h[h_idx] + T`:
        //     This head `h[h_idx]` cannot reach `p[p_idx]`.
        //     It also cannot reach any `p_k` where `k > p_idx` (since `p_k > p[p_idx]`).
        //     So, this head `h[h_idx]` cannot help cover `p[p_idx]` or any tracks to its right.
        //     We must use a later head for `p[p_idx]`.
        //     This head `h[h_idx]` is effectively "skipped" for covering `p[p_idx]` and beyond.
        //     We continue to the next head `h[h_idx+1]`.
        //   Else (`h[h_idx] - T <= p[p_idx] <= h[h_idx] + T`):
        //     This head `h[h_idx]` can cover `p[p_idx]`.
        //     To maximize coverage to the right, `h[h_idx]` should move to `p[p_idx]`
        //     and then sweep right. The rightmost point it can reach is `p[p_idx] + (T - std::abs(h[h_idx] - p[p_idx]))`.
        //     Let `effective_max_reach = p[p_idx] + (T - std::abs(h[h_idx] - p[p_idx]))`.
        //     Advance `p_idx` past all `p_k` such that `p_k <= effective_max_reach`.
        //     After this, we move to the next head `h[h_idx+1]`.

        // This logic seems sound.

        // Let's try the example: h = [2, 5, 6], p = [1, 3, 6, 8], T = 2
        // p_idx = 0 (p[0] = 1)

        // h_idx = 0 (h[0] = 2)
        //   h[0] - T = 0, h[0] + T = 4. Range [0, 4].
        //   p[0] = 1. Is 1 < 0? No.
        //   Is 1 > 4? No.
        //   Else: 0 <= 1 <= 4. Head can cover p[0].
        //     effective_max_reach = p[0] + (T - abs(h[0] - p[0]))
        //                       = 1 + (2 - abs(2 - 1)) = 1 + (2 - 1) = 1 + 1 = 2.
        //     Advance p_idx past p_k <= 2.
        //     p[0] = 1 <= 2.
        //     p[1] = 3 > 2.
        //     So p_idx becomes 1. (p[0] is covered)

        // h_idx = 1 (h[1] = 5)
        //   p_idx = 1 (p[1] = 3)
        //   h[1] - T = 3, h[1] + T = 7. Range [3, 7].
        //   p[1] = 3. Is 3 < 3? No.
        //   Is 3 > 7? No.
        //   Else: 3 <= 3 <= 7. Head can cover p[1].
        //     effective_max_reach = p[1] + (T - abs(h[1] - p[1]))
        //                       = 3 + (2 - abs(5 - 3)) = 3 + (2 - 2) = 3 + 0 = 3.
        //     Advance p_idx past p_k <= 3.
        //     p[1] = 3 <= 3.
        //     p[2] = 6 > 3.
        //     So p_idx becomes 2. (p[1] is covered)

        // h_idx = 2 (h[2] = 6)
        //   p_idx = 2 (p[2] = 6)
        //   h[2] - T = 4, h[2] + T = 8. Range [4, 8].
        //   p[2] = 6. Is 6 < 4? No.
        //   Is 6 > 8? No.
        //   Else: 4 <= 6 <= 8. Head can cover p[2].
        //     effective_max_reach = p[2] + (T - abs(h[2] - p[2]))
        //                       = 6 + (2 - abs(6 - 6)) = 6 + (2 - 0) = 6 + 2 = 8.
        //     Advance p_idx past p_k <= 8.
        //     p[2] = 6 <= 8.
        //     p[3] = 8 <= 8.
        //     p_idx becomes 4. (p[2], p[3] are covered)

        // Loop finishes. p_idx = 4 == m. Return true.
        // This matches the example output.

        // Let's consider the case where a head is skipped.
        // h = [10], p = [1, 20], T = 5
        // p_idx = 0 (p[0] = 1)

        // h_idx = 0 (h[0] = 10)
        //   h[0] - T = 5, h[0] + T = 15. Range [5, 15].
        //   p[0] = 1. Is 1 < 5? Yes.
        //     Return false. (Correct, head at 10 cannot reach 1 with T=5)

        // h = [1, 10], p = [5, 15], T = 2
        // p_idx = 0 (p[0] = 5)

        // h_idx = 0 (h[0] = 1)
        //   h[0] - T = -1, h[0] + T = 3. Range [-1, 3].
        //   p[0] = 5. Is 5 < -1? No.
        //   Is 5 > 3? Yes.
        //     Head h[0] cannot reach p[0]. Skip this head.
        //     (p_idx remains 0)

        // h_idx = 1 (h[1] = 10)
        //   p_idx = 0 (p[0] = 5)
        //   h[1] - T = 8, h[1] + T = 12. Range [8, 12].
        //   p[0] = 5. Is 5 < 8? Yes.
        //     Return false. (Correct, head at 10 cannot reach 5 with T=2)

        // This greedy strategy seems correct.

        // The range of `h_i` and `p_i` is up to 10^10. `T` can also be large.
        // `long long` is necessary.

        // The loop for `p_idx` advancement:
        // `while (p_idx < m && p[p_idx] <= effective_max_reach) { p_idx++; }`
        // This is efficient because `p_idx` only moves forward. Total `O(m)` for `p_idx` advancements.
        // Total `O(n)` for `h_idx` advancements.
        // So `check(T)` is `O(n + m)`.

        // Binary search range for T:
        // Minimum T: 0 (if all p_j are already at some h_i, or within range of some h_i with T=0)
        // Maximum T: Max possible distance. Max p_j is 10^10, min h_i is 1. Max distance is 10^10.
        // So `low = 0`, `high = 2 * 10^10` (a safe upper bound, e.g., `p_m - h_1` or `h_n - p_1` could be 10^10,
        // and a head might need to move from one end to the other, so 2 * 10^10 is a safe upper bound).
        // `high = 20000000000LL`

        long long head_left_reach = current_h - T;
        long long head_right_reach = current_h + T;

        // Case 1: The current target track p[p_idx] is too far to the left for this head.
        // Since p is sorted, and h is sorted, if p[p_idx] is too far left for h[h_idx],
        // it will also be too far left for any h[k] where k > h_idx.
        // This means p[p_idx] must have been covered by a previous head.
        // If p[p_idx] is still uncovered and it's to the left of h[h_idx] - T, then it's impossible.
        if (p[p_idx] < head_left_reach) {
            return false;
        }

        // Case 2: The current target track p[p_idx] is within reach of this head.
        // This head can cover p[p_idx]. We use it to cover p[p_idx] and extend as far right as possible.
        if (p[p_idx] <= head_right_reach) {
            // Calculate the effective rightmost point this head can cover.
            // It moves to p[p_idx], costing abs(current_h - p[p_idx]) time.
            // Remaining time is T - abs(current_h - p[p_idx]).
            // It can then sweep right by this remaining time.
            long long effective_max_reach = p[p_idx] + (T - std::abs(current_h - p[p_idx]));
            while (p_idx < m && p[p_idx] <= effective_max_reach) {
                p_idx++;
            }
        }
        // Case 3: The current target track p[p_idx] is too far to the right for this head.
        // (i.e., p[p_idx] > head_right_reach).
        // This head cannot cover p[p_idx] or any tracks to its right.
        // We must use a later head for p[p_idx].
        // So, this head h[h_idx] is effectively "skipped" for covering p[p_idx] and beyond.
        // We simply move to the next head. No change to p_idx.
    }

    return p_idx == m; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is around 10^10.
                                    // A head might need to move from 1 to 10^10, so T could be 10^10.
                                    // A safe upper bound is 2 * 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

