#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // as many times as possible without exceeding k.
        // a[i] + x * min_val <= k
        // x * min_val <= k - a[i]
        // x <= (k - a[i]) / min_val
        operations += (k - a[i]) / min_val;
    }
    std::cout << operations << std::endl;
}

