#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem guarantees that a solution exists.
    // The simplest way to get a permutation with the same fingerprint
    // is to reverse the original permutation.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // Let p' be the reverse of p: p' = [p_n, p_{n-1}, ..., p_1]
    // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // The set of adjacent sums for p' is exactly the same as for p,
    // just in reverse order. Therefore, their sorted versions (fingerprints)
    // will be identical.
    // The only case where p' might not be different from p is if p is a palindrome.
    // However, for n >= 2, a permutation cannot be a palindrome unless n=1 (which is not allowed)
    // or if it's a very specific case like [1,2,1] which is not a permutation.
    // For n >= 2, a permutation [p_1, ..., p_n] contains distinct integers from 1 to n.
    // If p is a palindrome, p_i = p_{n-i+1}.
    // For example, if n=2, p=[1,2]. Reverse is [2,1]. Different.
    // If n=3, p=[1,2,3]. Reverse is [3,2,1]. Different.
    // If n=4, p=[1,2,3,4]. Reverse is [4,3,2,1]. Different.
    // A permutation cannot be a palindrome for n > 1 because if p_i = p_{n-i+1} for all i,
    // then for n even, say n=4, p_1=p_4, p_2=p_3. This means p_1, p_2, p_3, p_4 are not distinct.
    // For n odd, say n=3, p_1=p_3, p_2=p_2. This means p_1, p_2, p_3 are not distinct.
    // The only way for p_i = p_{n-i+1} to hold for a permutation is if n=1, where p=[1].
    // But n >= 2 is given.
    // Therefore, reversing the permutation always yields a different permutation.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

