void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // A simple construction is to use '2' as the first digit,
        // and '3' for all subsequent digits.
        // This forms the number 233...3 (n-1 times '3').
        // Let's check its properties:
        // 1. All digits are non-zero (2 and 3).
        // 2. It has n digits.
        // 3. Is it divisible by 2? No, because it ends in 3 (odd).
        // 4. Is it divisible by 3? The sum of digits is 2 + (n-1)*3.
        //    If n=2, sum = 2+3 = 5, not div by 3.
        //    If n=3, sum = 2+3+3 = 8, not div by 3.
        //    If n=4, sum = 2+3+3+3 = 11, not div by 3.
        //    In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    3n - 1 is never divisible by 3, because 3n is divisible by 3,
        //    so 3n - 1 will always have a remainder of 2 when divided by 3.
        //    Thus, the number is never divisible by 3.
        // So, this construction 233...3 satisfies all conditions for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

