    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last element

        // Iterate from the second to last element backwards
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is a new minimum or equal to the current minimum
                // for the suffix starting from i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

