    bool found_n = false;

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
        if (p[i] == n - 1) {
            // If p[i] is n-1, it means p[i] could be n-1 or n.
            // If there is any p[k] = n, then a[k][j] for j!=k would contain all other values.
            // The maximum of these would be n-1.
            // So, if p[i] is n, then max_val_in_row for this i would be n-1.
            // We need to find exactly one element that is n.
            // If we find an element whose max_val_in_row is n-1, we tentatively assign it n.
            // If we find multiple, we need to be careful.
            // The problem guarantees a solution exists.
            // If all max_val_in_row are less than n-1, then n must be assigned to one of them.
            // If there's an element whose max_val_in_row is n-1, it means it's either n-1 or n.
            // If we assign n to one such element, all others must be their max_val_in_row.
            // If all max_val_in_row are less than n-1, then n must be assigned to one of them.
            // The simplest approach is to find if any p[i] is n-1. If so, one of them must be n.
            // If all p[i] are less than n-1, then all p[i] must be their max_val_in_row, and one of them must be n.
            // This implies that if all p[i] are < n-1, then the largest value in the matrix is < n-1, which is impossible
            // because the permutation contains n.
            // So there must be at least one p[i] == n-1.
            // We can just pick the first one we find and assign it n.
            // If we assign p[i] = n, then all other p[j] must be their max_val_in_row.
            // This is because if p[j] was also n, it's not a permutation.
            // If p[j] was n-1, then max_val_in_row for j would be n-1.
            // So, if we find a p[i] == n-1, we can set it to n and all others to their max_val_in_row.
            // This works because the problem guarantees a solution.
            // If there are multiple indices i where max_val_in_row is n-1, we can pick any one.
            // The problem states "reconstruct ANY permutation".
            // So, if we find an i such that p[i] == n-1, we can set p[i] = n and all other p[j] (j!=i) to their max_val_in_row.
            // This is the simplest way to handle the 'n' value.
