void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();

    int max_consecutive_L = 0;
    int current_consecutive_L = 0;

    // Add an implicit 'R' at the beginning (cell 0)
    // and an implicit 'R' at the end (cell n+1)
    // This simplifies the logic: we just need to find the maximum distance
    // between any two consecutive 'R' cells (including 0 and n+1).

    // Consider cell 0 as an 'R' cell.
    // The first segment of 'L's starts after cell 0.
    // The distance from cell 0 to the first 'R' cell (or n+1 if no 'R's)
    // is 1 + (number of 'L's before the first 'R').
    // This is equivalent to the length of the 'L' block plus 1.

    // Example: R L L R L R
    // Indices: 0 1 2 3 4 5 6 (n+1)
    // String:    s0 s1 s2 s3 s4 s5
    // Cells:   0  1  2  3  4  5  6  7 (n+1)
    // s:       R  L  L  R  L  R
    //
    // Virtual 'R' at 0.
    // s[0] is 'L'. current_consecutive_L becomes 1.
    // s[1] is 'L'. current_consecutive_L becomes 2.
    // s[2] is 'R'. This 'R' breaks the 'L' sequence.
    // The distance from the previous 'R' (cell 0) to this 'R' (cell 3)
    // is 1 (for cell 0) + current_consecutive_L (for L's) + 1 (for this R).
    // No, it's simpler: the distance from the *last R* to the *next R* is
    // (index of next R) - (index of last R).
    // If we are at cell `prev_R_idx` and the next 'R' is at cell `curr_R_idx`,
    // then the frog must be able to jump over all `L` cells between them.
    // The maximum jump needed is `curr_R_idx - prev_R_idx`.

    // Let's track the last 'R' position.
    // Initial position is 0, which acts like an 'R' cell.
    int last_r_pos = 0;
    int min_d = 0; // This will store the maximum distance between consecutive 'R's

    for (int i = 0; i < n; ++i) {
        if (s[i] == 'R') {
            // The cell is i+1.
            // The distance from last_r_pos to current 'R' cell (i+1) is (i+1) - last_r_pos.
            min_d = std::max(min_d, (i + 1) - last_r_pos);
            last_r_pos = i + 1;
        }
    }

    // After iterating through the string, we need to consider the jump to n+1.
    // The distance from the last 'R' cell found (or 0 if no 'R's) to n+1.
    min_d = std::max(min_d, (n + 1) - last_r_pos);

    std::cout << min_d << std::endl;
}

