    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams 'k' must satisfy:
        // 1. k <= c (enough coders)
        // 2. k <= m (enough mathematicians)
        // 3. k <= (c + m + x) / 3 (enough total students for 3 members per team)
        // So, k <= min(c, m, (c + m + x) / 3)
        // This is a monotonic function, so we can use binary search.
        // The maximum possible value for k is 10^8 (since c, m, x <= 10^8).
        // The minimum possible value for k is 0.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Upper bound for k
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // Check if 'mid' teams can be formed.
            // To form 'mid' teams, we need 'mid' coders and 'mid' mathematicians.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and x unspecialized.
            // The total number of remaining students is (c - mid) + (m - mid) + x.
            // Each team needs 3 members. 'mid' coders and 'mid' mathematicians are already accounted for.
            // So, we need 'mid' more members in total (3 * mid - mid - mid = mid).
            // These 'mid' additional members can come from the remaining students.
            // The total number of remaining students must be at least 'mid'.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

