int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int low = 1;
    int high = k + 1; // The largest number we'll use for the alternating part to generate k distinct differences

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << low++;
        } else {
            std::cout << high--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append them in increasing order to ensure the new differences are 1.
    // Since we already have 1 as a difference (e.g., |k - (k+1)| or |(k+1) - k|),
    // these new differences won't add new distinct elements to the set.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the potential end of the "decreasing part" of the suffix.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This is the potential end of the "increasing part" of the suffix.
    // Note: a[i-1] is the peak if it exists.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // The suffix a[j...n-1] is of the form non-increasing then non-decreasing.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

