int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m; // Number of multiples of m up to n

        // Precompute the sum of last digits for one full cycle (10 multiples)
        // The last digits of k*m repeat every 10 values of k.
        // E.g., (1*m)%10, (2*m)%10, ..., (10*m)%10
        // Then (11*m)%10 is same as (1*m)%10, etc.
        long long sum_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_cycle += (static_cast<long long>(i) * m) % 10;
        }

        // Calculate how many full cycles are there
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_cycle;

        // Calculate the sum for the remaining multiples
        long long remaining_multiples = count % 10;
        for (int i = 1; i <= remaining_multiples; ++i) {
            total_sum += (static_cast<long long>(i) * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

