#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subarray [1] is always a permutation of {1}.
    // It's found at p[pos[1]...pos[1]].
    ans[0] = '1';

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Expand the current window to include 'm'
        // The new element 'm' must be either to the left or right of the current window
        // [current_min_idx, current_max_idx]

        // Update the window boundaries to include pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current window [current_min_idx, current_max_idx]
        // forms a permutation of {1, ..., m}.
        // This requires two conditions:
        // 1. The length of the window must be exactly m.
        // 2. The minimum element in the window must be 1.
        // 3. The maximum element in the window must be m.
        //
        // Conditions 2 and 3 are implicitly handled by how we expand the window:
        // We start with 1, and for each m, we expand the window to include m.
        // So, the minimum element in the window [current_min_idx, current_max_idx]
        // will always be 1 (because 1 is always included).
        // The maximum element in this window will always be m (because we just added m,
        // and all numbers 1 to m-1 were already included, and no number > m has been added yet).
        //
        // Therefore, we only need to check condition 1: length == m.
        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, we need d - 4 >= 0, which means d >= 4.
        // If d = 0, it's a special case handled above.
        // If 0 < d < 4, then d^2 - 4d < 0, no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // Using the quadratic formula: a = (d +/- sqrt(d^2 - 4d)) / 2
            // To ensure a >= b and both are non-negative, we take the '+' for a
            // and '-' for b.
            // a = (d + sqrt_discriminant) / 2
            // b = (d - sqrt_discriminant) / 2
            // Since d >= 4, d^2 - 4d >= 0.
            // Also, d >= sqrt(d^2 - 4d) because d^2 >= d^2 - 4d (since 4d >= 0).
            // So, d - sqrt_discriminant will be non-negative.
            // Thus, both a and b will be non-negative.

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
