int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (from the sorted array)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (represented by sorted values)
        // We are trying to find an element a[j] to place at position i
        // such that a[j] > a[i].
        // Since both arrays are sorted, if a[j] > a[i], it's a valid match.
        // We want to use the smallest possible a[j] that satisfies a[j] > a[i]
        // to leave larger elements for later, potentially larger a[k].
        // So, we advance j until a[j] > a[i].
        // If we find such an a[j], we use it, increment count, and move to the next i and j.
        // If we reach the end of the array with j, we can't find any more matches.
        if (j < n && a[j] > a[i]) {
            count++;
            j++; // Move to the next element to be placed
        } else if (j < n && a[j] <= a[i]) {
            // If a[j] is not greater than a[i], we can't use a[j] for a[i].
            // We need a larger element. So, we advance j to find a suitable one.
            // We don't increment i here because we still need to find a match for a[i].
            // The outer loop will increment i, so we just need to advance j.
            j++;
            i--; // Decrement i to re-evaluate the current a[i] with the new j
                 // This effectively means we are trying to find a match for a[i]
                 // using a[j] (which is now a[j+1] from previous iteration)
                 // without advancing the 'original position' pointer i.
                 // This is equivalent to:
                 // while (j < n && a[j] <= a[i]) { j++; }
                 // if (j < n) { count++; j++; }
                 // The loop structure handles this naturally.
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::vector<std::string> result(4);

    // Box 1: (-inf, -1]
    // Final product must be negative and magnitude >= 1
    // This requires an odd number of negative factors.
    // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1 that multiply to >= 1.

    // Case 1: A single toy is the super toy.
    if (total_toys == 1) {
        result[0] = (A == 1) ? "Ya" : "Tidak";
        result[1] = (B == 1) ? "Ya" : "Tidak";
        result[2] = (C == 1) ? "Ya" : "Tidak";
        result[3] = (D == 1) ? "Ya" : "Tidak";
        std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
        return;
    }

    // Box 1: (-inf, -1]
    // Final product must be negative. This means an odd number of negative toys.
    // (A + B) % 2 == 1
    // Final product must have magnitude >= 1.
    // This requires at least one toy from Box 1 or Box 4, OR
    // multiple toys from Box 2 or Box 3 that can be chosen to make magnitude >= 1.
    // The only way to guarantee magnitude >= 1 is if there's at least one toy from Box 1 or Box 4.
    // If A+D == 0, then all toys are from Box 2 or Box 3. Their product will always have magnitude < 1.
    // So, if A+D == 0, Box 1 and Box 4 are impossible.
    // If A+D > 0, it's possible to get magnitude >= 1.
    // So, for Box 1: (A + B) % 2 == 1 AND (A + D > 0)
    if ((A + B) % 2 == 1 && (A + D > 0)) {
        result[0] = "Ya";
    } else {
        result[0] = "Tidak";
    }

    // Box 2: (-1, 0)
    // Final product must be negative. This means an odd number of negative toys.
    // (A + B) % 2 == 1
    // Final product must have magnitude < 1.
    // This requires that we can arrange multiplications such that the final product is < 1.
    // This is always possible if there's at least one toy from Box 2 or Box 3.
    // If A+D > 0, we can always multiply a large magnitude toy by a small magnitude toy to get a small magnitude.
    // For example, if we have a toy from Box 4 (e.g., 2) and a toy from Box 2 (e.g., -0.5), their product is -1.
    // If we have a toy from Box 4 (e.g., 2) and a toy from Box 3 (e.g., 0.1), their product is 0.2.
    // If we have a toy from Box 1 (e.g., -2) and a toy from Box 3 (e.g., 0.1), their product is -0.2.
    // The only way to *not* be able to get magnitude < 1 is if all toys are from Box 1 or Box 4, and there are no toys from Box 2 or Box 3.
    // If B+C == 0, then all toys are from Box 1 or Box 4. Their product will always have magnitude >= 1.
    // So, if B+C == 0, Box 2 and Box 3 are impossible.
    // If B+C > 0, it's possible to get magnitude < 1.
    // So, for Box 2: (A + B) % 2 == 1 AND (B + C > 0)
    if ((A + B) % 2 == 1 && (B + C > 0)) {
        result[1] = "Ya";
    } else {
        result[1] = "Tidak";
    }

    // Box 3: (0, 1)
    // Final product must be positive. This means an even number of negative toys.
    // (A + B) % 2 == 0
    // Final product must have magnitude < 1.
    // Similar to Box 2, this requires B+C > 0.
    // So, for Box 3: (A + B) % 2 == 0 AND (B + C > 0)
    if ((A + B) % 2 == 0 && (B + C > 0)) {
        result[2] = "Ya";
    } else {
        result[2] = "Tidak";
    }

    // Box 4: [1, inf)
    // Final product must be positive. This means an even number of negative toys.
    // (A + B) % 2 == 0
    // Final product must have magnitude >= 1.
    // Similar to Box 1, this requires A+D > 0.
    // So, for Box 4: (A + B) % 2 == 0 AND (A + D > 0)
    if ((A + B) % 2 == 0 && (A + D > 0)) {
        result[3] = "Ya";
    } else {
        result[3] = "Tidak";
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

