#include <functional>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need S' = 2 * X'
        // Let S' = current_sum + b1 + b2 + ...
        // Let X' = current_xor_sum ^ b1 ^ b2 ^ ...

        // If current_sum == 2 * current_xor_sum, array is already good.
        // But the problem statement implies we can always append elements even if it's good.
        // The example shows 0 elements appended if it's good.
        // So, let's check if it's good first.
        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
            continue;
        }

        // We need to append elements.
        // Let's try to append two elements: X_0 and S_0 + X_0.
        // This is a common trick for problems involving sum and XOR.
        // Let b1 = current_xor_sum.
        // Let b2 = current_sum + current_xor_sum.
        //
        // New sum S' = current_sum + b1 + b2
        //            = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        //            = 2 * current_sum + 2 * current_xor_sum
        //
        // New XOR sum X' = current_xor_sum ^ b1 ^ b2
        //               = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        //               = 0 ^ (current_sum + current_xor_sum)
        //               = current_sum + current_xor_sum
        //
        // We need S' = 2 * X'.
        // Substitute: (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // This equation is always true.
        // So, appending current_xor_sum and (current_sum + current_xor_sum) always works.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << "\n";
        std::cout << b1 << " " << b2 << "\n";
    }
    return 0;
}

