// Function to check if a subarray is a permutation
// `arr` is the original array
// `start_idx` is the starting index of the subarray (0-indexed)
// `len` is the length of the subarray
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len; // Max element must be equal to length
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix permutation checks
    // `is_prefix_perm[i]` is true if a[0...i] is a permutation of length i+1
    std::vector<bool> is_prefix_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false); // For checking duplicates and range
    int current_prefix_max = 0;
    bool prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val <= 0 || val > (i + 1) || seen_prefix[val]) {
            prefix_valid = false;
        }
        if (prefix_valid) {
            seen_prefix[val] = true;
            current_prefix_max = std::max(current_prefix_max, val);
            if (current_prefix_max == (i + 1)) {
                is_prefix_perm[i] = true;
            }
        }
    }

    // Precompute suffix permutation checks
    // `is_suffix_perm[i]` is true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> is_suffix_perm(n, false);
    std::vector<bool> seen_suffix(n + 1, false); // For checking duplicates and range
    int current_suffix_max = 0;
    bool suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int len = n - i;
        if (val <= 0 || val > len || seen_suffix[val]) {
            suffix_valid = false;
        }
        if (suffix_valid) {
            seen_suffix[val] = true;
            current_suffix_max = std::max(current_suffix_max, val);
            if (current_suffix_max == len) {
                is_suffix_perm[i] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> solutions;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1 (inclusive)
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if p1 (a[0...l1-1]) is a permutation of length l1
        // This is true if is_prefix_perm[l1-1] is true AND the max element in p1 is l1
        // The max element check is implicitly handled by is_prefix_perm
        bool p1_is_perm = is_prefix_perm[l1 - 1];

        // Check if p2 (a[l1...n-1]) is a permutation of length l2
        // This is true if is_suffix_perm[l1] is true AND the max element in p2 is l2
        // The max element check is implicitly handled by is_suffix_perm
        bool p2_is_perm = is_suffix_perm[l1];

        if (p1_is_perm && p2_is_perm) {
            solutions.push_back({l1, l2});
        }
    }

    std::cout << solutions.size() << "\n";
    for (const auto& sol : solutions) {
        std::cout << sol.first << " " << sol.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

