char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Prioritize R, then P, then S for tie-breaking if counts are equal
        // This is not strictly necessary for correctness, any choice works,
        // but it ensures deterministic output matching example if ties exist.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // If all counts are 0 (empty string, not possible by constraints),
        // or if all counts are equal, the order of checks above determines the tie-break.
        // For example, if R=1, P=1, S=1, it will pick 'S' because it's checked last.
        // If R=1, P=2, S=1, it will pick 'P'.
        // The problem statement implies n >= 1, so at least one char exists.
        // The specific tie-breaking rule for most_frequent_bot_move doesn't affect the maximum average,
        // only which specific character is chosen as the "most frequent".
        // The current logic correctly finds *a* most frequent character.
        // Example: R=2, P=2, S=1.
        // max_count = 2, most_frequent_bot_move = 'R'
        // max_count = 2, most_frequent_bot_move = 'P' (updated)
        // max_count = 2, most_frequent_bot_move = 'P' (not updated)
        // So 'P' would be chosen. This is fine.

        char my_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << my_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

