    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // An 'a' at this position will combine with all 'b's to its right.
            // Each such 'ab' pair will be replaced by 'bba'.
            // This operation consumes the 'a' and one 'b', and produces two 'b's.
            // So, the number of 'b's to the right effectively doubles for the next 'a'.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

