// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's to a fixed length (e.g., 18 for max 10^18-1)
    // The problem states max length 18 for pattern, and numbers up to 10^18-1 (18 digits).
    // So, a fixed length of 18 is appropriate.
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to match the fixed length
            // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // And "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we effectively extend both to a common maximum length, padding with '0's.
            // Since our stored patterns are always 18 chars long, we need to pad the query pattern to 18 chars.
            std::string padded_s = s;
            std::reverse(padded_s.begin(), padded_s.end()); // Reverse to pad from left logically (right physically)
            while (padded_s.length() < 18) {
                padded_s += '0';
            }
            // The stored patterns are also reversed (LSB first), so this matches.
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

