#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n - i' items are taken from the right side.
    // This means we are considering a split point where 'i' items are taken from left
    // and 'n-i' items are taken from right.
    // The actual number of items taken from the right is 'n - i'.
    // Let 'left_count' be the number of items taken from the left.
    // Let 'right_count' be the number of items taken from the right.
    // left_count + right_count = n.
    // We iterate 'left_count' from 0 to n.
    for (int left_count = 0; left_count <= n; ++left_count) {
        int right_count = n - left_count;

        long long current_energy = 0;

        // Cost for items taken from the left
        current_energy += (prefix_sum[left_count] - prefix_sum[0]) * l;

        // Cost for items taken from the right
        // The items taken from the right are w[n-right_count], ..., w[n-1]
        // Their sum is prefix_sum[n] - prefix_sum[n-right_count]
        current_energy += (prefix_sum[n] - prefix_sum[n - right_count]) * r;

        // Add extra costs based on the difference in counts
        if (left_count > right_count) {
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            current_energy += (right_count - left_count - 1) * Qr;
