void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last1 = '0'; // Last digit in sequence 1
        char last2 = '0'; // Last digit in sequence 2
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];

            // Option 1: Assign to color 1
            // Can assign to color 1 if current_digit >= last1 AND current_digit <= pivot_digit
            bool can_assign_1 = (current_digit >= last1) && (current_digit <= (pivot_digit + '0'));

            // Option 2: Assign to color 2
            // Can assign to color 2 if current_digit >= last2 AND current_digit >= pivot_digit
            bool can_assign_2 = (current_digit >= last2) && (current_digit >= (pivot_digit + '0'));

            if (can_assign_1 && can_assign_2) {
                // If both are possible, greedily assign to 1 if current_digit < pivot_digit
                // This helps keep S1 shorter and S2 longer, potentially making it easier for later digits.
                // Or, if current_digit == pivot_digit, assign to 1 to keep S2's first element as large as possible.
                if (current_digit < (pivot_digit + '0')) {
                    result[i] = '1';
                    last1 = current_digit;
                } else { // current_digit >= pivot_digit
                    result[i] = '2';
                    last2 = current_digit;
                }
            } else if (can_assign_1) {
                result[i] = '1';
                last1 = current_digit;
            } else if (can_assign_2) {
                result[i] = '2';
                last2 = current_digit;
            } else {
                possible_with_pivot = false;
                break;
            }
        }

        if (possible_with_pivot) {
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

