        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // To maximize x, we should remove as few factors from p as possible.
        // Specifically, we need to remove factors from p such that x no longer has all prime factors of q
        // with sufficient powers.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak.
        // If x is divisible by q, then x must have at least f_i^a_i for all i.
        // To make x not divisible by q, we need to make x lack at least one f_i^a_i.
        // This means for some prime factor f_i of q, the power of f_i in x must be less than a_i.
        // The strategy is to iterate through each distinct prime factor f of q.
        // For each f, we find the largest divisor of p that is not divisible by q.
        // This divisor is obtained by dividing p by f until it's no longer divisible by q.
        // More precisely, we find the highest power of f that divides p, say f^b.
        // We then divide p by f until the resulting number is no longer divisible by q.
        // This means we divide p by f until the power of f in p becomes less than the power of f in q.
        // The candidate x would be p / f^k where f^k is the smallest power of f such that (p / f^k) % q != 0.
        // This is equivalent to finding the smallest k such that (p / f^k) has fewer factors of f than q.
        // Or, more simply, for each prime factor f of q, we calculate p / f, p / f^2, ...
        // until p / f^k is not divisible by q. The largest such p / f^k is a candidate.
        // We want to find max(p / (f_i^k_i)) over all distinct prime factors f_i of q,
        // where k_i is the smallest positive integer such that (p / f_i^k_i) % q != 0.

        long long ans = 1;
        long long temp_q = q;
        for (long long i = 2; i * i <= temp_q; ++i) {
            if (temp_q % i == 0) {
                long long current_prime_factor = i;
                long long current_p = p;
                while (current_p % current_prime_factor == 0 && current_p % q == 0) {
                    current_p /= current_prime_factor;
                }
                ans = std::max(ans, current_p);
                while (temp_q % current_prime_factor == 0) {
                    temp_q /= current_prime_factor;
                }
            }
        }
        if (temp_q > 1) { // temp_q is now a prime factor itself
            long long current_prime_factor = temp_q;
            long long current_p = p;
            while (current_p % current_prime_factor == 0 && current_p % q == 0) {
                current_p /= current_prime_factor;
            }
            ans = std::max(ans, current_p);
        }
        std::cout << ans << "\n";
    }
    return 0;
}

