    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        long long min_coord = std::min(abs_n, abs_m);
        long long max_coord = std::max(abs_n, abs_m);

        if (k < max_coord) {
            std::cout << -1 << "\n";
            continue;
        }

        long long remaining_moves = k - max_coord;
        long long diagonal_moves = max_coord;

        if (remaining_moves % 2 == 0) {
            // If remaining_moves is even, we can use all of them to make
            // two non-diagonal moves cancel out (e.g., (x,y)->(x+1,y)->(x,y))
            // or two diagonal moves cancel out (e.g., (x,y)->(x+1,y+1)->(x,y))
            // or one diagonal and one non-diagonal (x,y)->(x+1,y+1)->(x+1,y)
            // The parity of (x+y) changes with each move.
            // (0,0) has sum 0. (n,m) has sum n+m.
            // If k and (n+m) have different parity, it's impossible.
            // (n+m) % 2 != k % 2
            if ((abs_n + abs_m) % 2 != k % 2) {
                std::cout << -1 << "\n";
            } else {
                std::cout << k << "\n";
            }
        } else { // remaining_moves is odd
            // We must end up at (max_coord, max_coord) or (max_coord, min_coord)
            // after max_coord moves.
            // If we are at (max_coord, max_coord) after max_coord moves,
            // we need to make an odd number of additional moves.
            // One move will take us to (max_coord+1, max_coord) or similar.
            // The remaining even moves can be used to return to (max_coord, max_coord).
            // This means we use one non-diagonal move, and k-1 moves are used to
            // reach (max_coord, max_coord) and then return to it.
            // So, k-1 diagonal moves are possible.
            // Example: (0,0) -> (1,1) -> (2,2) -> (2,1) -> (2,2)
            // k=4, (2,2). max_coord=2. remaining=2. k.
            // k=3, (2,2). max_coord=2. remaining=1. k-2.
            // (0,0) -> (1,1) -> (2,2) -> (2,1)
            // This means we use one non-diagonal move, and k-1 moves are used to
            // reach (max_coord, max_coord) and then return to it.
            // The parity of (x+y) changes with each move.
            // (0,0) has sum 0. (n,m) has sum n+m.
            // If k and (n+m) have different parity, it's impossible.
            // (n+m) % 2 != k % 2
            if ((abs_n + abs_m) % 2 != k % 2) {
                std::cout << -1 << "\n";
            } else {
                std::cout << k - 2 << "\n";
            }
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val;
    if (b == 1) { // If b=1, r cannot be non-zero, so sum_r_val is 0.
        sum_r_val = 0;
    } else {
        sum_r_val = (b - 1);
        sum_r_val = (sum_r_val * b) % MOD;
        sum_r_val = (sum_r_val * ((MOD + 1) / 2)) % MOD; // Multiply by modular inverse of 2
    }

    // Sum of (k * b + 1) from k=1 to a
    // This is sum_kb_plus_1_val
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_kb_plus_1_val;
    long long sum_k_val = (a % MOD);
    sum_k_val = (sum_k_val * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * ((MOD + 1) / 2)) % MOD; // Multiply by modular inverse of 2

    long long term1 = (b % MOD * sum_k_val) % MOD;
    long long term2 = (a % MOD);
    sum_kb_plus_1_val = (term1 + term2) % MOD;

    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

