#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos(26);
    for (int i = 0; i < L; ++i) {
        pos[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_val = 0; k_val < L; ++k_val) { // Iterate through all possible initial k values
        char t0_char = s[k_val];
        int char_idx = t0_char - 'a';

        // If there's only one occurrence of t0_char in s, Vasya wins immediately
        // by just knowing t0_char. He doesn't even need to pick a second position.
        // The problem states he must pick a second position, but if it's unique,
        // any choice of p will lead to a win.
        if (pos[char_idx].size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // If there are multiple occurrences of t0_char, Vasya needs to pick p.
        // He wants to pick p such that the probability of winning for this t0_char is maximized.
        // This means he wants to maximize the number of k' values that become unique.

        // For a fixed t0_char (which corresponds to s[k_val]), we need to find the best p.
        // The best p is the one that maximizes the count of unique (k', (p+k')%L) pairs
        // among all k' such that s[k'] == t0_char.

        int max_unique_count_for_t0 = 0;

        // Iterate through all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            std::map<char, int> counts; // counts of t_p characters for current p
            for (int k_prime : pos[char_idx]) { // k_prime are all indices where s[k_prime] == t0_char
                char tp_char = s[(p + k_prime) % L];
                counts[tp_char]++;
            }

            int current_unique_count = 0;
            for (auto const& [tp_char, count] : counts) {
                if (count == 1) {
                    current_unique_count++;
                }
            }
            max_unique_count_for_t0 = std::max(max_unique_count_for_t0, current_unique_count);
        }
        total_win_prob += static_cast<double>(max_unique_count_for_t0);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_in_layout;
    char current_char = '\0';

    // Find a starting point for a chain: a character with only one neighbor
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            current_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in adj have 2 neighbors (or 0, but those are not in adj)
    // This implies a cycle or multiple disjoint chains where all internal nodes have 2 neighbors.
    // For a single chain, the ends have 1 neighbor. If all have 2, it must be a cycle.
    // A cycle is not possible on a linear keyboard.
    // However, it could also be that the password itself forms a single chain, but the first/last char of the password
    // are not necessarily the ends of the full keyboard layout.
    // The problem states "adjacent characters in s, they should be adjacent on the keyboard".
    // This means the graph formed by adjacencies in s must be a collection of disjoint paths.
    // If all characters in adj have 2 neighbors, it means it's a cycle or multiple cycles, which is impossible.
    // Or, it could be a single path where the first and last characters of the path are the only ones with 1 neighbor.
    // If current_char is still '\0', it means all characters in `adj` have exactly 2 neighbors.
    // This implies that the graph formed by `adj` is a collection of disjoint cycles.
    // A cycle cannot be represented on a linear keyboard.
    // Example: "abacaba" -> a-b, a-c. 'b' has 1 neighbor ('a'), 'c' has 1 neighbor ('a'). 'a' has 2 neighbors ('b', 'c').
    // This is a valid path.
    // Example: "abcde" -> a-b, b-c, c-d, d-e. 'a' and 'e' have 1 neighbor. 'b','c','d' have 2 neighbors. Valid.
    // Example: "abac" -> a-b, a-c. 'b' has 1, 'c' has 1, 'a' has 2. Valid.
    // Example: "abcb" -> a-b, c-b. 'a' has 1, 'c' has 1, 'b' has 2. Valid.
    // Example: "abacada" -> a-b, a-c, a-d. 'a' has 3 neighbors. Invalid.
    // Example: "abacaba" -> a-b, a-c. 'a' has 2, 'b' has 1, 'c' has 1.
    // If current_char is still '\0', it means all characters that appear in `s` have exactly two neighbors.
    // This implies that the graph components formed by `s` are all cycles.
    // A cycle cannot be laid out linearly.
    // So, if current_char is '\0' AND `adj` is not empty, it's impossible.
    // If `adj` is empty (s.length() == 1), then any layout is fine.
    if (current_char == '\0' && !adj.empty()) {
        std::cout << "NO\n";
        return;
    }

    // If s has only one character, adj is empty. current_char remains '\0'.
    // In this case, any layout is fine. We'll handle this by just printing all chars.
    // If s is empty, adj is empty.
    // If s has length > 1 and current_char is found, proceed.

    if (current_char != '\0') { // Found a starting point for a chain
        char prev_char = '\0';
        while (current_char != '\0' && visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    } else { // adj is empty, meaning s has length 0 or 1.
             // In this case, any layout is valid.
             // The problem guarantees 1 <= |s|, so s has length 1.
             // We just need to print all 26 characters.
             // The loop below will handle this by adding all unvisited characters.
    }

    // Add any remaining characters not part of the password's adjacency chains
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

struct Operation {
    char type;
    int val;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Operation> ops(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> ops[i].type >> ops[i].val;
    }

    int initial_0 = 0; // What 0 becomes after all operations
    int initial_1 = 0; // What 1 becomes after all operations

    // For each bit position (0 to 9)
    // We track what 0 becomes and what 1 becomes.
    // The final result for a bit `b` will be `(x_b == 0 ? final_0_b : final_1_b)`.
    // We can represent this as two numbers:
    // `val_if_input_0`: the value if the input bit was 0
    // `val_if_input_1`: the value if the input bit was 1
    // Initially, for a single bit:
    // `val_if_input_0` is 0
    // `val_if_input_1` is 1

    int current_val_if_input_0 = 0; // Represents the state of all bits if input was 0
    int current_val_if_input_1 = 1023; // Represents the state of all bits if input was 1023

    for (const auto& op : ops) {
        if (op.type == '&') {
            current_val_if_input_0 &= op.val;
            current_val_if_input_1 &= op.val;
        } else if (op.type == '|') {
            current_val_if_input_0 |= op.val;
            current_val_if_input_1 |= op.val;
        } else if (op.type == '^') {
            current_val_if_input_0 ^= op.val;
            current_val_if_input_1 ^= op.val;
        }
    }

    // Now, current_val_if_input_0 holds the result for input 0.
    // And current_val_if_input_1 holds the result for input 1023.
    // We need to find a minimal set of operations (at most 5) that transform
    // any input `x` to `f(x)`.
    // For each bit `b`:
    // Let `x_b` be the b-th bit of `x`.
    // Let `f(x)_b` be the b-th bit of `f(x)`.
    // We know `f(0)_b` (from `current_val_if_input_0`) and `f(1023)_b` (from `current_val_if_input_1`).
    //
    // Let `bit_0_becomes_0` be the mask of bits where `0` maps to `0`.
    // Let `bit_0_becomes_1` be the mask of bits where `0` maps to `1`.
    // Let `bit_1_becomes_0` be the mask of bits where `1` maps to `0`.
    // Let `bit_1_becomes_1` be the mask of bits where `1` maps to `1`.
    //
    // `bit_0_becomes_0` = ~current_val_if_input_0 & 1023
    // `bit_0_becomes_1` = current_val_if_input_0
    // `bit_1_becomes_0` = ~current_val_if_input_1 & 1023
    // `bit_1_becomes_1` = current_val_if_input_1

    // We can simplify this.
    // For each bit `b`:
    // Case 1: `x_b` -> `0` (always 0, regardless of `x_b`)
    //   This happens if `f(0)_b = 0` AND `f(1)_b = 0`.
    //   Mask: `(~current_val_if_input_0) & (~current_val_if_input_1) & 1023`
    // Case 2: `x_b` -> `1` (always 1, regardless of `x_b`)
    //   This happens if `f(0)_b = 1` AND `f(1)_b = 1`.
    //   Mask: `current_val_if_input_0 & current_val_if_input_1`
    // Case 3: `x_b` -> `x_b` (identity)
    //   This happens if `f(0)_b = 0` AND `f(1)_b = 1`.
    //   Mask: `(~current_val_if_input_0) & current_val_if_input_1 & 1023`
    // Case 4: `x_b` -> `~x_b` (negation)
    //   This happens if `f(0)_b = 1` AND `f(1)_b = 0`.
    //   Mask: `current_val_if_input_0 & (~current_val_if_input_1) & 1023`

    int mask_always_0 = (~current_val_if_input_0) & (~current_val_if_input_1) & 1023;
    int mask_always_1 = current_val_if_input_0 & current_val_if_input_1;
    int mask_identity = (~current_val_if_input_0) & current_val_if_input_1 & 1023;
    int mask_negation = current_val_if_input_0 & (~current_val_if_input_1) & 1023;

    std::vector<Operation> result_ops;

    // Strategy:
    // 1. Apply OR with `mask_always_1` to set bits that should always be 1.
    //    This doesn't affect bits that should be 0, x, or ~x.
    if (mask_always_1 != 0) {
        result_ops.push_back({'|', mask_always_1});
    }

    // 2. Apply AND with `~mask_always_0` to clear bits that should always be 0.
    //    This doesn't affect bits that should be 1, x, or ~x.
    //    Note: `~mask_always_0` is equivalent to `mask_always_1 | mask_identity | mask_negation`.
    //    So, `x & (~mask_always_0)` will clear bits in `mask_always_0` and keep others.
    if (mask_always_0 != 0) {
        result_ops.push_back({'&', ~mask_always_0 & 1023});
    }

    // 3. Apply XOR with `mask_negation` to flip bits that should be negated.
    //    This only affects bits in `mask_negation`.
    //    Bits in `mask_always_1` are already 1.
    //    Bits in `mask_always_0` are already 0.
    //    Bits in `mask_identity` are already `x_b`.
    //    So XORing with `mask_negation` will correctly flip `x_b` to `~x_b` for those bits.
    if (mask_negation != 0) {
        result_ops.push_back({'^', mask_negation});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.type << " " << op.val << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: Substring starts with '1'
        if (s[l] == '1') {
            long long current_val = 0;
            for (int r = l; r < n; ++r) {
                current_val = (current_val << 1) | (s[r] - '0');

                // Optimization: If current_val exceeds max_len_check, break.
                // max_len_check is chosen to be slightly larger than log2(N)
                // For N = 2e5, log2(N) approx 17.6. So 20-22 bits is enough.
                // If current_val exceeds 2*N, it's definitely too large.
                // A tighter bound is 2 * (N - l), but 2*N is safe.
                if (current_val > 2LL * n) { 
                    break;
                }

                long long len = r - l + 1;
                if (len == current_val) {
                    good_substrings_count++;
                }
            }
        } else { // Case 2: Substring starts with '0'
            // Find the first '1' after or at l.
            // If no '1' exists, all substrings starting with '0' will have value 0.
            // Only s_l...s_r = "0" (len 1, val 0) is not good.
            // If s_l...s_r = "00...0" (len K, val 0), it's not good unless K=0, which is not possible.
            // So, if a substring starts with '0' and contains only '0's, it's never good.
            // We only need to consider substrings that eventually contain a '1'.

            // Find the first '1' at or after index l.
            auto it = std::lower_bound(ones_pos.begin(), ones_pos.end(), l);
            if (it == ones_pos.end()) {
                // No '1's from l to n-1. All substrings s[l...r] are all '0's.
                // Their value is 0. Their length is r-l+1 >= 1.
                // So, length != value. No good substrings here.
                continue;
            }

            int first_one_idx = *it;

            // Substrings s[l...r] where r < first_one_idx are all '0's.
            // These are not good.

            // Consider substrings s[l...r] where r >= first_one_idx.
            // The actual binary value starts from first_one_idx.
            // The length of the substring is r - l + 1.
            // The number of leading zeros is first_one_idx - l.
            // The value of the substring is f(s[first_one_idx...r]).

            long long current_val = 0;
            for (int r = first_one_idx; r < n; ++r) {
                current_val = (current_val << 1) | (s[r] - '0');

                // Optimization: If current_val exceeds max_len_check, break.
                if (current_val > 2LL * n) {
                    break;
                }

                long long len = r - l + 1;
                if (len == current_val) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s) - (count of 2s) among jars a_n, a_{n-1}, ..., a_{n-k+1}
    // This is equivalent to (count of 1s) - (count of 2s) among jars a_{n-k+1}, ..., a_n
    // We are interested in the balance of jars *removed* from the left.
    // Let's define balance_L[k] as the balance of the first k jars from the left (a_1 to a_k)
    // and balance_R[k] as the balance of the first k jars from the right (a_{2n} to a_{2n-k+1})
    // Or, more simply, let's calculate the balance of the *remaining* jars.

    // Initial balance of all 2n jars
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) initial_balance++;
        else initial_balance--;
    }

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain balance difference.
    // key: balance_diff, value: number of jars removed from left
    std::map<int, int> left_removed_balance_to_count;
    left_removed_balance_to_count[0] = 0; // 0 jars removed from left, balance diff 0

    int current_left_balance_diff = 0; // balance of jars a_1, ..., a_i
    for (int i = 0; i < n; ++i) { // Iterate from a_1 to a_n
        if (a[i] == 1) current_left_balance_diff++;
        else current_left_balance_diff--;
        // We are removing i+1 jars from the left (a_1 to a_{i+1})
        // The balance of these removed jars is current_left_balance_diff.
        // We want to store the minimum number of jars removed to get this balance.
        // Since we iterate from left to right, the first time we see a balance,
        // it corresponds to the minimum number of jars (i+1).
        if (left_removed_balance_to_count.find(current_left_balance_diff) == left_removed_balance_to_count.end()) {
            left_removed_balance_to_count[current_left_balance_diff] = i + 1;
        }
    }

    // Map to store the minimum number of jars removed from the right side
    // to achieve a certain balance difference.
    // key: balance_diff, value: number of jars removed from right
    std::map<int, int> right_removed_balance_to_count;
    right_removed_balance_to_count[0] = 0; // 0 jars removed from right, balance diff 0

    int current_right_balance_diff = 0; // balance of jars a_{2n}, ..., a_{2n-i}
    for (int i = 0; i < n; ++i) { // Iterate from a_{2n} to a_{n+1}
        if (a[2 * n - 1 - i] == 1) current_right_balance_diff++;
        else current_right_balance_diff--;
        // We are removing i+1 jars from the right (a_{2n} to a_{2n-i})
        // The balance of these removed jars is current_right_balance_diff.
        if (right_removed_balance_to_count.find(current_right_balance_diff) == right_removed_balance_to_count.end()) {
            right_removed_balance_to_count[current_right_balance_diff] = i + 1;
        }
    }

    int min_total_removed = 2 * n; // Max possible is removing all jars

    // Iterate through all possible balances achieved by removing jars from the left
    for (auto const& [left_bal_diff, left_removed_count] : left_removed_balance_to_count) {
        // If we remove 'left_removed_count' jars from the left, with balance 'left_bal_diff',
        // the remaining jars have an initial balance of (initial_balance - left_bal_diff).
        // To make the final balance 0, we need to remove jars from the right
        // such that their balance is (initial_balance - left_bal_diff).
        // So, we need to find a 'right_removed_count' such that
        // right_bal_diff = initial_balance - left_bal_diff.
        int target_right_bal_diff = initial_balance - left_bal_diff;

        if (right_removed_balance_to_count.count(target_right_bal_diff)) {
            int right_removed_count = right_removed_balance_to_count[target_right_bal_diff];
            min_total_removed = std::min(min_total_removed, left_removed_count + right_removed_count);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for sums to prevent overflow
using ll = long long;

// Max N value
const int MAXN = 200005;

// Arrays for memoization
// dp_val[i] stores the final y value if starting at x=i with parity 0 (step 2)
ll dp_val[MAXN][2];
// dp_next_x[i] stores the next x value if starting at x=i with parity 0 (step 2)
int dp_next_x[MAXN][2];
// visited[i] helps detect cycles and memoize states
bool visited[MAXN][2];
// in_stack[i] helps detect cycles during DFS
bool in_stack[MAXN][2];

// The sequence a. a[0] is unused, a[1] is the initial a_1, a[2]...a[n] are given.
std::vector<ll> a_values;
int N;

// Recursive function to calculate the final y and next x
// x_curr: current x value
// parity: 0 for step 2 (x += a_x, y += a_x), 1 for step 3 (x -= a_x, y += a_x)
void solve(int x_curr, int parity) {
    // Base cases for termination
    if (x_curr <= 0 || x_curr > N) {
        dp_val[x_curr][parity] = 0; // No further y increase
        dp_next_x[x_curr][parity] = x_curr; // Terminates here
        visited[x_curr][parity] = true;
        return;
    }

    // If already computed, return memoized value
    if (visited[x_curr][parity]) {
        return;
    }

    // Detect cycle
    if (in_stack[x_curr][parity]) {
        dp_val[x_curr][parity] = -1; // Mark as infinite loop
        dp_next_x[x_curr][parity] = -1;
        visited[x_curr][parity] = true;
        return;
    }

    // Mark current state as being processed (in recursion stack)
    in_stack[x_curr][parity] = true;

    ll current_a_val = a_values[x_curr];
    int next_x;
    ll y_increase_this_step;

    if (parity == 0) { // Step 2: x += a_x, y += a_x
        next_x = x_curr + current_a_val;
        y_increase_this_step = current_a_val;
        solve(next_x, 1); // Next state is step 3
    } else { // Parity == 1, Step 3: x -= a_x, y += a_x
        next_x = x_curr - current_a_val;
        y_increase_this_step = current_a_val;
        solve(next_x, 0); // Next state is step 2
    }

    // After recursive call returns, current state is no longer in stack
    in_stack[x_curr][parity] = false;
    visited[x_curr][parity] = true;

    // Check if the next state led to an infinite loop
    if (dp_val[next_x][(parity == 0) ? 1 : 0] == -1) {
        dp_val[x_curr][parity] = -1;
        dp_next_x[x_curr][parity] = -1;
    } else {
        dp_val[x_curr][parity] = y_increase_this_step + dp_val[next_x][(parity == 0) ? 1 : 0];
        dp_next_x[x_curr][parity] = dp_next_x[next_x][(parity == 0) ? 1 : 0];
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_values.resize(N + 1);
    // a_1 is set for each query, so we only read a_2 to a_N
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize visited and in_stack arrays to false
    // dp_val and dp_next_x are implicitly 0 or garbage, will be filled.
    // The termination states (x <= 0 or x > N) need to be handled.
    // We can use indices 0 and N+1 for these boundary conditions.
    // dp_val[0][0/1] = 0, dp_next_x[0][0/1] = 0
    // dp_val[N+1][0/1] = 0, dp_next_x[N+1][0/1] = N+1
    // These are handled by the base case in solve().

    for (int i = 1; i < N; ++i) {
        a_values[1] = i; // Set a_1 for the current query

        // Initial state: x=1, y=0. First operation is step 2.
        // So we call solve(1, 0)
        solve(1, 0);

        // The total y value is a_1 + the result from solve(1,0)
        // Note: solve(1,0) already includes a_1 in its calculation.
        // The problem states: "Initially, x = 1 and y = 0. ... The program increases both x and y by a_x simultaneously."
        // This means the first a_x (which is a_1) is added to y.
        // Our solve(x_curr, parity) function calculates the sum of a_values encountered from x_curr onwards.
        // So, dp_val[1][0] already contains the total sum of a_values added to y.
        std::cout << dp_val[1][0] << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0;
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long target_b;

        // Case 1: a[i] + x >= prev_b
        // We can potentially make b[i] = prev_b
        // This requires (a[i] + ops) % m = prev_b
        // If a[i] <= prev_b, we need ops = prev_b - a[i].
        // If a[i] > prev_b, we need ops = prev_b - a[i] + m.
        // In both cases, ops = (prev_b - a[i] + m) % m.
        // If this ops <= x, then we can achieve prev_b.
        // So, if (prev_b - current_a + m) % m <= x, we can set target_b = prev_b.

        // Case 2: a[i] + x < prev_b
        // We cannot make b[i] = prev_b.
        // We must make b[i] >= prev_b.
        // The smallest possible value for b[i] is current_a.
        // If current_a >= prev_b, we can set target_b = current_a.
        // This requires 0 operations on a[i], which is <= x.
        // If current_a < prev_b, we must increment a[i] until it's at least prev_b.
        // The smallest value we can achieve is current_a + ops.
        // If we apply x operations, the value becomes (current_a + x) % m.
        // If (current_a + x) % m < prev_b, then it's impossible to make b[i] >= prev_b.
        // This is because any value (current_a + ops) % m where ops <= x will also be < prev_b.
        // (Unless current_a + ops wraps around m, but if (current_a + x) % m < prev_b,
        // it means current_a + x is not large enough to reach prev_b or wrap around and reach prev_b.)

        // Let's simplify. We want to find a b_i such that prev_b <= b_i < m.
        // And b_i can be formed by (a_i + ops) % m where ops <= x.

        // If a[i] <= prev_b:
        // We need to increment a[i] to reach prev_b.
        // The number of operations needed is prev_b - a[i].
        // If prev_b - a[i] <= x, then we can set b_i = prev_b.
        // Otherwise, we cannot reach prev_b. The smallest value we can achieve is a[i].
        // But a[i] < prev_b, so this is not valid.
        // The largest value we can achieve is (a[i] + x) % m.
        // If (a[i] + x) % m < prev_b, then it's impossible.
        // If (a[i] + x) % m >= prev_b, then we can set b_i = prev_b.
        // This logic is tricky. Let's re-evaluate.

        // We need to find b_i such that prev_b <= b_i < m.
        // And b_i is reachable from a_i with at most x operations.
        // This means b_i = (a_i + ops) % m for some 0 <= ops <= x.

        // If a[i] >= prev_b:
        // We can potentially set b_i = a[i]. This requires 0 operations, which is <= x.
        // So, if a[i] >= prev_b, we can always set b_i = a[i].
        // The only constraint is that we must be able to make b_i >= prev_b.
        // If a[i] >= prev_b, we can just take b_i = a[i]. This is valid.
        // However, we might need to increment a[i] to satisfy the condition (a[i] + ops) % m >= prev_b.
        // The number of operations needed to make a[i] become prev_b is (prev_b - a[i] + m) % m.
        // Let `ops_needed_to_reach_prev_b = (prev_b - current_a + m) % m`.
        // If `ops_needed_to_reach_prev_b <= x`:
        //   We can make `b_i = prev_b`.
        //   So, `target_b = prev_b`.
        // Else (we cannot reach `prev_b` by incrementing `a_i` within `x` operations):
        //   This means `current_a` is "too far" from `prev_b` in the positive direction (or `x` is too small).
        //   The values we can achieve are `(current_a + 0) % m, (current_a + 1) % m, ..., (current_a + x) % m`.
        //   If `current_a >= prev_b`, then we can just take `b_i = current_a`. This requires 0 operations.
        //   So, `target_b = current_a`.
        //   If `current_a < prev_b`, and we cannot reach `prev_b` (i.e., `ops_needed_to_reach_prev_b > x`),
        //   then it means `current_a + x` is still less than `prev_b` (without wrapping around `m`).
        //   Or, `current_a + x` wraps around `m` but still doesn't reach `prev_b`.
        //   Specifically, if `current_a < prev_b` and `ops_needed_to_reach_prev_b > x`,
        //   it means `current_a + x < prev_b` (if no wrap) OR `current_a + x - m < prev_b` (if wrap).
        //   In either case, `(current_a + x) % m` will be less than `prev_b`.
        //   So, it's impossible to make `b_i >= prev_b`.
        //   Therefore, if `current_a < prev_b` and `ops_needed_to_reach_prev_b > x`, return false.

        // Combined logic:
        // We need to find a `b_i` such that `prev_b <= b_i < m` and `b_i = (current_a + ops) % m` for some `0 <= ops <= x`.
        //
        // Option 1: Set `b_i = prev_b`.
        // This is possible if `(prev_b - current_a + m) % m <= x`.
        // If this is true, we can set `target_b = prev_b`.
        //
        // Option 2: If Option 1 is not possible, we must set `b_i > prev_b`.
        // The smallest possible `b_i` we can achieve is `current_a` (with 0 ops).
        // If `current_a >= prev_b`, then we can set `target_b = current_a`.
        // This requires 0 ops, which is <= x.
        //
        // If neither Option 1 nor Option 2 is possible, it means:
        // `(prev_b - current_a + m) % m > x` (cannot reach `prev_b` with `x` ops)
        // AND `current_a < prev_b` (cannot use `current_a` as `b_i`).
        // In this situation, we need to check if any `(current_a + ops) % m` for `0 <= ops <= x` can be `>= prev_b`.
        // Since `current_a < prev_b` and we cannot reach `prev_b` by incrementing `current_a` by `x` (or less)
        // without wrapping around `m` to a value `>= prev_b`, it means `(current_a + x) % m` must be `< prev_b`.
        // So, it's impossible.

        // Let's use the simpler logic:
        // We want to find the smallest b_i >= prev_b that is reachable from a[i] with at most x operations.
        // If a[i] >= prev_b:
        //   We can choose b_i = a[i]. This requires 0 operations.
        //   We can also choose b_i = prev_b if (prev_b - a[i] + m) % m <= x.
        //   If (prev_b - a[i] + m) % m <= x, it means we can "wrap around" from a[i] to prev_b.
        //   Example: m=10, a[i]=8, prev_b=1. ops_needed = (1-8+10)%10 = 3. If x=3, we can make b_i=1.
        //   If a[i] >= prev_b, we have two choices for b_i:
        //     1. a[i] (0 ops)
        //     2. prev_b (if (prev_b - a[i] + m) % m <= x)
        //   We should pick the one that is smaller, which is prev_b if possible.
        //   So, if (prev_b - current_a + m) % m <= x, then target_b = prev_b.
        //   Else, target_b = current_a.
        // Else (a[i] < prev_b):
        //   We must increment a[i] to reach at least prev_b.
        //   The number of operations needed to reach prev_b is prev_b - a[i].
        //   If prev_b - a[i] <= x, then we can set target_b = prev_b.
        //   Else (prev_b - a[i] > x):
        //     It means even with x operations, we cannot reach prev_b.
        //     So, it's impossible to make b_i >= prev_b. Return false.

        if (current_a >= prev_b) {
            // Option 1: Keep current_a. This requires 0 operations.
            // Option 2: Try to make it prev_b by wrapping around.
            // This requires (prev_b - current_a + m) % m operations.
            // If (prev_b - current_a + m) % m <= x, we can achieve prev_b.
            // In this case, we should choose prev_b as target_b because it's smaller or equal to current_a.
            // If we choose current_a, it might be too large for the next element.
            if ((prev_b - current_a + m) % m <= x) {
                // We can make b_i = prev_b
                target_b = prev_b;
            } else {
                // We cannot make b_i = prev_b by wrapping around.
                // We must use current_a (0 ops) or increment it up to (current_a + x) % m.
                // Since current_a >= prev_b, we can just use current_a.
                // This is the smallest valid value we can achieve without wrapping around.
                target_b = current_a;
            }
        } else { // current_a < prev_b
            // We must increment current_a to reach at least prev_b.
            // The number of operations needed to reach prev_b is prev_b - current_a.
            if (prev_b - current_a <= x) {
                // We can make b_i = prev_b.
                target_b = prev_b;
            } else {
                // Even with x operations, we cannot reach prev_b.
                // So, it's impossible to make b_i >= prev_b.
                return false;
            }
        }
        prev_b = target_b;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations for any single element
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible initial_a[i]
                                            // Initialize with a very large value

    // Calculate b[i] based on type 2 operations
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_delta_sum = 0;
            for (int k = 0; k < i; ++k) { // Sum d for type 1 ops before current type 2 op
                if (ops[k].type == 1 && ops[k].l <= ops[i].r && ops[k].r >= ops[i].l) {
                    // This type 1 op affects the range [ops[i].l, ops[i].r]
                    // We need to find the maximum possible initial_a[j] for j in [ops[i].l, ops[i].r]
                    // So we need to subtract the sum of d's from m_i
                    // This is effectively calculating m_i - (sum of d's for j)
                    // The maximum initial_a[j] for j in [ops[i].l, ops[i].r] must be <= m_i - current_delta_sum
                    // This is not quite right.
                    // Let's re-evaluate.
                    // For a type 2 op (2 l r m), we know that max_{j=l..r} (initial_a[j] + current_delta[j]) = m.
                    // This implies that for all j in [l, r], initial_a[j] + current_delta[j] <= m.
                    // So, initial_a[j] <= m - current_delta[j].
                    // We want to find the largest possible initial_a[j] that satisfies all constraints.
                    // So, initial_a[j] <= min(m_k - current_delta_k[j]) over all type 2 ops k that cover j.
                    // Let's calculate current_delta_k[j] for each j and each type 2 op k.
                    // This is what the `b` array is for.
                    // For each type 2 op (2 l r m), and for each j in [l, r]:
                    // initial_a[j] <= m - (sum of d's for j from ops 0 to i-1)
                    // So, b[j] = min(b[j], m - (sum of d's for j from ops 0 to i-1))
                }
            }
            // Re-calculating current_delta_sum for each j in [ops[i].l, ops[i].r]
            // This is inefficient. We need to calculate prefix sums of d's.
            // Let's use a temporary array `temp_delta` to store the sum of d's up to this point for each index.
            // This is what `delta_at_op_start` is for.
        }
    }

    // `delta_at_op_start[k][j]` stores the sum of `d` values applied to index `j` by type 1 operations
    // from index `0` to `k-1` in the `ops` array.
    std::vector<std::vector<long long>> delta_at_op_start(m + 1, std::vector<long long>(n, 0));

    for (int k = 0; k < m; ++k) {
        for (int j = 0; j < n; ++j) {
            delta_at_op_start[k + 1][j] = delta_at_op_start[k][j];
        }
        if (ops[k].type == 1) {
            for (int j = ops[k].l; j <= ops[k].r; ++j) {
                delta_at_op_start[k + 1][j] += ops[k].val;
            }
        }
    }

    // Now, for each type 2 operation (2 l r m) at index `k` in `ops`:
    // For each `j` in `[l, r]`, we must have `initial_a[j] + delta_at_op_start[k][j] <= m`.
    // This implies `initial_a[j] <= m - delta_at_op_start[k][j]`.
    // We want to find the largest possible `initial_a[j]` that satisfies all constraints.
    // So, `b[j]` (our candidate for `initial_a[j]`) should be the minimum of `m - delta_at_op_start[k][j]`
    // over all type 2 operations `k` that cover `j`.
    for (int j = 0; j < n; ++j) {
        for (int k = 0; k < m; ++k) {
            if (ops[k].type == 2 && j >= ops[k].l && j <= ops[k].r) {
                b[j] = std::min(b[j], ops[k].val - delta_at_op_start[k][j]);
            }
        }
    }

    // If any b[j] is still LLONG_MAX, it means there were no type 2 constraints on initial_a[j].
    // We can set it to 0, as |a_i| <= 10^9 is allowed.
    // Or, more generally, any value within the range. 0 is a safe choice.
    for (int j = 0; j < n; ++j) {
        if (b[j] == LLONG_MAX) {
            b[j] = 0;
        }
    }

    // Verify the solution
    // Simulate all operations with the constructed initial array `b`
    // and check if all type 2 operations yield the correct maximum.
    std::vector<long long> current_a = b;
    for (int k = 0; k < m; ++k) {
        if (ops[k].type == 1) {
            for (int j = ops[k].l; j <= ops[k].r; ++j) {
                current_a[j] += ops[k].val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[k].l; j <= ops[k].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[k].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array
    for (int j = 0; j < n; ++j) {
        if (std::abs(b[j]) > 1000000000LL) {
            // This case should ideally not be reached if m_i and d_i are within bounds,
            // but it's good to be safe.
            // If b[j] is LLONG_MAX, it was set to 0.
            // If b[j] is derived from m_i - delta, and m_i is 5e7, delta can be up to 5000 * 10^4 = 5e7.
            // So b[j] can be around 5e7 - (-5e7) = 1e8, or -5e7 - 5e7 = -1e8.
            // These are within 10^9.
            // So this check might be redundant given the problem constraints.
            // However, if intermediate calculations overflowed, it could be an issue.
            // But long long should prevent that.
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << b[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
