    // Let `a_extended_with_zeros` be `a_final_prefix` followed by `k` zeros.
    // `len(a_extended_with_zeros) = len(a_final_prefix) + k`.
    // `ones(a_extended_with_zeros) = ones_in_a_final_prefix`.
    // We need `b` to be a suffix of `a_extended_with_zeros`.
    // This implies:
    // 1. `len(b) <= len(a_extended_with_zeros)`.
    // 2. `ones_in_b <= ones_in_a_final_prefix`. (Since appending '0's doesn't increase '1's).
    // 3. The actual characters must match.

    // Let's calculate `a_final_prefix` and its `ones_count`.
    std::string a_final_prefix = a;
    int ones_in_a_final_prefix = ones_in_a;

    if (ones_in_a % 2 != 0) { // If initial parity of a is odd
        a_final_prefix += '1';
        ones_in_a_final_prefix++;
    }
    // Now `a_final_prefix` has an even number of '1's.

    // We need to check if `b` can be a suffix of `a_final_prefix` extended with '0's.
    // This means `b` must be a suffix of `a_final_prefix` + "00...0".
    // The number of '1's in `b` must be less than or equal to `ones_in_a_final_prefix`.
    if (ones_in_b > ones_in_a_final_prefix) {
        std::cout << "NO\n";
        return 0;
    }

    // If `ones_in_b <= ones_in_a_final_prefix`, it means we have enough '1's.
    // We can always remove leading characters from `a_final_prefix` (and potentially
    // some '0's that were appended) to match `b`.
    // The length of `a_final_prefix` is `len_a_final_prefix`.
    // We need to be able to form `b` from `a_final_prefix` by removing characters from the front
    // and potentially adding '0's to the end.
    // The string `a_final_prefix` can be extended to any length `L >= len(a_final_prefix)`
    // by appending `L - len(a_final_prefix)` zeros.
    // Let this extended string be `a_prime_extended`.
    // `ones(a_prime_extended) = ones_in_a_final_prefix`.
    // We need to check if `b` can be a suffix of `a_prime_extended`.
    // This means `b` must be `a_prime_extended.substr(len(a_prime_extended) - len_b)`.
    // The number of '1's in `b` must be `ones_in_b`.
    // Since `ones_in_b <= ones_in_a_final_prefix`, we can always find a suffix of `a_prime_extended`
    // that has `ones_in_b` ones.
    // The only remaining constraint is that the actual characters must match.
    // This means `b` must be a suffix of `a_final_prefix` followed by enough '0's.
    // The length of `a_final_prefix` is `len_a_final_prefix`.
    // If `len_b <= len_a_final_prefix`:
    //   We need to check if `b` is a suffix of `a_final_prefix`.
    //   `a_final_prefix.substr(len_a_final_prefix - len_b) == b`.
    // If `len_b > len_a_final_prefix`:
    //   We need to check if `b` is `a_final_prefix` followed by `len_b - len_a_final_prefix` zeros.
    //   This means `b.substr(0, len_a_final_prefix) == a_final_prefix` AND
    //   `b.substr(len_a_final_prefix)` must consist only of '0's.

    // Let's combine these:
    // Construct the candidate string `s_candidate` by taking `a_final_prefix`
    // and appending '0's until its length is `len_b`.
    // If `len(a_final_prefix) < len_b`, append `len_b - len(a_final_prefix)` zeros.
    // If `len(a_final_prefix) >= len_b`, take the suffix of `a_final_prefix` of length `len_b`.
    // Then compare this `s_candidate` with `b`.

    std::string s_candidate;
    if (a_final_prefix.length() >= len_b) {
        s_candidate = a_final_prefix.substr(a_final_prefix.length() - len_b);
    } else { // a_final_prefix.length() < len_b
        s_candidate = a_final_prefix;
        s_candidate.append(len_b - a_final_prefix.length(), '0');
    }

    if (s_candidate == b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
