    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);

    // Calculate left_zero_run: length of consecutive zeros to the left, including current element if it's zero.
    // If a[i] is 1, left_zero_run[i] is 0.
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
        } else {
            left_zero_run[i] = 0;
        }
    }

    // Calculate right_zero_run: length of consecutive zeros to the right, including current element if it's zero.
    // If a[i] is 1, right_zero_run[i] is 0.
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
        } else {
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            // If a[i] is 0, it will eventually become 0.
            // The question is how many steps it takes for a 1 to become 0.
            // A 1 at index j becomes 0 if it's part of a 010 pattern.
            // This logic is for 1s becoming 0s.
            // For 0s, they stay 0 unless surrounded by 1s.
            // But the problem is about 010 -> 000 and 101 -> 111.
            // The key insight is that 0s expand and 1s expand.
            // A 0 at index i will remain 0 if it's part of a 000, 001, 100 pattern.
            // It will become 1 if it's part of a 101 pattern.
            // The problem states that 010 -> 000 and 101 -> 111.
            // This means 0s expand into 1s, and 1s expand into 0s.
            // This is confusing. Let's re-read the median definition.
            // median(x,y,z) is 1 if at least two are 1. Otherwise 0.
            // So 010 -> 000. A 1 becomes 0.
            // And 101 -> 111. A 0 becomes 1.
            // This means 0s "eat" isolated 1s, and 1s "eat" isolated 0s.
            // The sequence stabilizes if there are no more 010 or 101 patterns.
            // This means the stable sequence must be of the form 0...01...10...0 or 1...10...01...1.
            // Or just all 0s or all 1s.
            // The problem states 01010 -> 00100 -> 00000.
            // This implies 0s are dominant.
            // Let's re-evaluate the median:
            // 000 -> 0
            // 001 -> 0
            // 010 -> 0
            // 011 -> 1
            // 100 -> 0
            // 101 -> 1
            // 110 -> 1
            // 111 -> 1
            // So, b_i = 1 if (a_{i-1} + a_i + a_{i+1}) >= 2. Otherwise b_i = 0.
            // This means a 1 "spreads" if it has another 1 next to it.
            // A 0 "spreads" if it has another 0 next to it.
            // An isolated 1 (010) becomes 0.
